function normalizeStoredFileExplorerIndexedDir(path) {
  const normalized = normalizeDirectoryPath(expandUserPath(path));
  return normalized.startsWith('/') ? normalized : '';
}

function readStoredFileExplorerIndexedDirs() {
  const paths = readStoredJson(fileExplorerIndexedDirsStorageKey, []);
  return new Set((Array.isArray(paths) ? paths : []).map(normalizeStoredFileExplorerIndexedDir).filter(Boolean));
}

function writeStoredFileExplorerIndexedDirs() {
  const paths = Array.from(fileExplorerIndexedDirs || [])
    .map(normalizeStoredFileExplorerIndexedDir)
    .filter(Boolean)
    .sort((left, right) => left.localeCompare(right));
  storageSet(fileExplorerIndexedDirsStorageKey, JSON.stringify(Array.from(new Set(paths))));
}

function nestedSetting(source, path, fallback) {
  let current = source;
  for (const part of String(path || '').split('.')) {
    if (!part) continue;
    if (!current || typeof current !== 'object' || !(part in current)) return fallback;
    current = current[part];
  }
  return current === undefined || current === null ? fallback : current;
}

function initialSetting(path, fallback) {
  return nestedSetting(clientSettings, path, nestedSetting(clientSettingsDefaults, path, fallback));
}

function mergeSettingObjects(base, patch) {
  const result = Array.isArray(base) ? base.slice() : {...(base || {})};
  if (!patch || typeof patch !== 'object' || Array.isArray(patch)) return result;
  for (const [key, value] of Object.entries(patch)) {
    if (value && typeof value === 'object' && !Array.isArray(value) && result[key] && typeof result[key] === 'object' && !Array.isArray(result[key])) {
      result[key] = mergeSettingObjects(result[key], value);
    } else {
      result[key] = Array.isArray(value) ? value.slice() : value;
    }
  }
  return result;
}

function readStoredFileExplorerRootMode() {
  return storageGet(fileExplorerRootModeStorageKey) === 'fixed' ? 'fixed' : 'sync';
}

function writeStoredFileExplorerRootMode(mode) {
  storageSet(fileExplorerRootModeStorageKey, mode === 'sync' ? 'sync' : 'fixed');
}

function normalizeFileExplorerMode(mode) {
  return mode === 'diff' ? 'diff' : 'files';
}

function readStoredFileExplorerMode() {
  const stored = storageGet(fileExplorerModeStorageKey);
  if (stored === 'diff' || stored === 'files') return stored;
  return storageGet(legacyFileExplorerChangesHiddenStorageKey) === '0' ? 'diff' : 'files';
}

function writeStoredFileExplorerMode(mode) {
  storageSet(fileExplorerModeStorageKey, normalizeFileExplorerMode(mode));
}

function normalizeEditorSchemeId(value) {
  const normalized = String(value || '').trim().toLowerCase();
  if (normalized === 'light' || normalized === 'white') return defaultLightEditorScheme;
  const legacySchemePrefix = ['vs', 'code'].join('');
  const aliases = {
    [`${legacySchemePrefix}-dark-plus`]: 'popular-ide-dark-plus',
    [`${legacySchemePrefix}-light-plus`]: 'popular-ide-light-plus',
  };
  const id = aliases[normalized] || normalized;
  return EDITOR_SCHEMES[id] ? id : defaultEditorScheme;
}

function normalizeGlobalThemeMode(value = globalThemeMode) {
  // Default to the LIVE globalThemeMode (like resolvedGlobalThemeMode) so a no-arg call reflects the
  // current theme — calling it with no argument used to fall through to defaultGlobalTheme ('dark'),
  // which made the View -> Theme menu always mark Dark as active regardless of the real theme.
  const normalized = String(value || '').trim().toLowerCase();
  return ['system', 'dark', 'light'].includes(normalized) ? normalized : defaultGlobalTheme;
}

function globalThemeMediaQuery() {
  try { return window.matchMedia?.('(prefers-color-scheme: dark)') || null; }
  catch (_) { return null; }
}

function systemPrefersDarkTheme() {
  const query = globalThemeMediaQuery();
  return query ? query.matches === true : true;
}

function resolvedGlobalThemeMode(mode = globalThemeMode) {
  const normalized = normalizeGlobalThemeMode(mode);
  if (normalized === 'system') return systemPrefersDarkTheme() ? 'dark' : 'light';
  return normalized;
}

function globalThemeIsDark(mode = globalThemeMode) {
  return resolvedGlobalThemeMode(mode) === 'dark';
}

function globalThemeLabel(mode = globalThemeMode) {
  const normalized = normalizeGlobalThemeMode(mode);
  if (normalized === 'system') return `System (${resolvedGlobalThemeMode(mode)})`;
  return normalized === 'dark' ? 'Dark' : 'Light';
}

function nextGlobalThemeMode(mode = globalThemeMode) {
  const normalized = normalizeGlobalThemeMode(mode);
  if (normalized === 'system') return 'dark';
  if (normalized === 'dark') return 'light';
  return 'system';
}

function normalizeTerminalThemeMode(value) {
  const normalized = String(value || '').trim().toLowerCase();
  return ['dark', 'light', 'follow-app'].includes(normalized) ? normalized : defaultTerminalTheme;
}

function resolvedTerminalThemeMode(mode = terminalThemeMode, appMode = globalThemeMode) {
  const normalized = normalizeTerminalThemeMode(mode);
  return normalized === 'follow-app' ? resolvedGlobalThemeMode(appMode) : normalized;
}

function terminalThemeForGlobalTheme(mode = globalThemeMode) {
  const theme = TERMINAL_THEMES[resolvedTerminalThemeMode(terminalThemeMode, mode)] || TERMINAL_THEMES.dark;
  return {...theme};
}

// on a WHITE (light) terminal, agents emit 24-bit truecolor escapes tuned for a dark
// terminal that render faint on white. xterm's minimumContrastRatio auto-darkens ANY text color
// (including app 24-bit colors) against the bg.
// the DARK terminal used to keep 1 (no adjustment), which left low-contrast cells alone — so
// an agent composer that draws light text on an ANSI-white box (Codex's input, ~contrast 1) was
// white-on-white. Use a moderate 3 for dark: enough to force that composer to a readable foreground,
// low enough that intentionally-dim dark-palette text (already at/above 3:1) is mostly untouched. Light
// stays at the stricter WCAG-AA 4.5 (faint colors on white need more help).
function terminalMinimumContrastRatio(mode = globalThemeMode) {
  return resolvedTerminalThemeMode(terminalThemeMode, mode) === 'light' ? 4.5 : 3;
}

function normalizeEditorThemeMode(value) {
  const normalized = String(value || '').trim().toLowerCase();
  if (['inherit', 'system', 'global', 'auto', ''].includes(normalized)) return editorThemeInheritMode;
  return normalizeEditorSchemeId(normalized);
}

function normalizeEditorPreviewDisplayMode(value) {
  return String(value || '').trim().toLowerCase() === 'vanilla' ? 'vanilla' : 'theme';
}

function normalizeEditorSchemeForMode(value, dark) {
  const id = normalizeEditorSchemeId(value);
  const scheme = EDITOR_SCHEMES[id];
  if (scheme && scheme.dark === dark) return id;
  return dark ? defaultEditorScheme : defaultLightEditorScheme;
}

function activeEditorScheme() {
  if (fileEditorThemeMode === editorThemeInheritMode) {
    const inherited = configuredEditorSchemeForMode(globalThemeIsDark());
    return EDITOR_SCHEMES[inherited] || EDITOR_SCHEMES[defaultEditorScheme] || EDITOR_SCHEMES.dark;
  }
  return EDITOR_SCHEMES[normalizeEditorSchemeId(fileEditorThemeMode)] || EDITOR_SCHEMES[defaultEditorScheme] || EDITOR_SCHEMES.dark;
}

function configuredEditorSchemeForMode(dark) {
  const path = dark ? 'appearance.editor_dark_color_scheme' : 'appearance.editor_light_color_scheme';
  const fallback = dark ? defaultEditorScheme : defaultLightEditorScheme;
  return normalizeEditorSchemeForMode(initialSetting(path, fallback), dark);
}

function readStoredEditorThemeMode() {
  return normalizeEditorThemeMode(storageGet(fileEditorThemeModeStorageKey) || editorThemeInheritMode);
}

function writeStoredEditorThemeMode(mode) {
  storageSet(fileEditorThemeModeStorageKey, normalizeEditorThemeMode(mode));
}

function readStoredEditorPreviewDisplayMode() {
  return normalizeEditorPreviewDisplayMode(storageGet(fileEditorPreviewDisplayModeStorageKey) || 'theme');
}

function writeStoredEditorPreviewDisplayMode(mode) {
  storageSet(fileEditorPreviewDisplayModeStorageKey, normalizeEditorPreviewDisplayMode(mode));
}

function readConfiguredEditorScheme() {
  return normalizeEditorThemeMode(readStoredEditorThemeMode());
}

function syncPressedButton(button, active, options = {}) {
  if (!button) return;
  const activeClass = options.activeClass || 'active';
  button.classList.toggle(activeClass, active);
  button.setAttribute('aria-pressed', active ? 'true' : 'false');
  const label = active ? options.labelOn : options.labelOff;
  if (label) {
    button.title = label;
    button.setAttribute('aria-label', label);
  }
}

function syncFileExplorerHiddenButton(button) {
  syncPressedButton(button, fileExplorerShowHidden, {
    labelOn: 'Hide dotfiles (.*)',
    labelOff: 'Show hidden files (dotfiles)',
  });
}

function fileExplorerTreeDateModeLabel(mode = fileExplorerTreeDateMode) {
  const normalized = normalizeFileExplorerTreeDateMode(mode);
  return t(`finder.dateMode.${normalized}`);
}

function fileExplorerTreeDateModeButtonLabel(mode = fileExplorerTreeDateMode) {
  const normalized = normalizeFileExplorerTreeDateMode(mode);
  return normalized === 'none' ? t('finder.dateMode.date') : fileExplorerTreeDateModeLabel(normalized);
}

function fileExplorerTreeDateModeTitle(mode = fileExplorerTreeDateMode) {
  return t('finder.dateMode.title', {
    mode: fileExplorerTreeDateModeLabel(mode),
    none: fileExplorerTreeDateModeLabel('none'),
    date: fileExplorerTreeDateModeLabel('date'),
    relative: fileExplorerTreeDateModeLabel('relative'),
  });
}

function syncFileExplorerTreeDateButton(button) {
  if (!button) return;
  const mode = normalizeFileExplorerTreeDateMode(fileExplorerTreeDateMode);
  const active = mode !== 'none';
  button.classList.toggle('active', active);
  button.dataset.dateMode = mode;
  button.setAttribute('aria-pressed', active ? 'true' : 'false');
  button.textContent = fileExplorerTreeDateModeButtonLabel(mode);
  const label = fileExplorerTreeDateModeTitle(mode);
  button.title = label;
  button.setAttribute('aria-label', label);
}

function syncFileExplorerTreeDateButtons(scope = document) {
  for (const button of scope.querySelectorAll?.('[data-file-explorer-tree-dates]') || []) {
    syncFileExplorerTreeDateButton(button);
  }
}

function nextFileExplorerTreeDateMode(mode = fileExplorerTreeDateMode) {
  const normalized = normalizeFileExplorerTreeDateMode(mode);
  const index = fileExplorerTreeDateModes.indexOf(normalized);
  return fileExplorerTreeDateModes[(index + 1) % fileExplorerTreeDateModes.length];
}

function refreshFileExplorerTreeDateModeSurfaces() {
  syncFileExplorerTreeDateButtons();
  if (typeof refreshFileExplorerTrees === 'function') {
    void refreshFileExplorerTrees({preserveExpanded: true, preserveScroll: true});
  }
  if (typeof renderFileExplorerChangesPanels === 'function') renderFileExplorerChangesPanels({force: true});
}

function setFileExplorerTreeDateMode(mode) {
  const next = normalizeFileExplorerTreeDateMode(mode);
  if (next === fileExplorerTreeDateMode) return;
  fileExplorerTreeDateMode = next;
  writeStoredFileExplorerTreeDateMode(fileExplorerTreeDateMode);
  refreshFileExplorerTreeDateModeSurfaces();
}

function cycleFileExplorerTreeDateMode() {
  setFileExplorerTreeDateMode(nextFileExplorerTreeDateMode());
}

function renderTabMetaToggle() {
  document.body?.classList.toggle('tab-meta-hidden', !tabMetaVisible);
  if (!tabMetaToggle) return;
  syncPressedButton(tabMetaToggle, tabMetaVisible, {
    labelOn: 'Hide tab metadata',
    labelOff: 'Show tab metadata',
  });
}

function toggleTabMetadata() {
  tabMetaVisible = !tabMetaVisible;
  writeStoredTabMetaVisible(tabMetaVisible);
  renderTabMetaToggle();
  renderSessionButtons();
  scheduleTopbarMetricsUpdate();
}

function recordFocusNavTransition(previousItem, nextItem) {
  if (!nextItem) return;
  if (previousItem && previousItem !== nextItem) recordEditorNav(previousItem);
  recordEditorNav(nextItem);
}

function rememberActivePaneItem(item) {
  if (item && itemIsActivePaneTab(item)) lastActivePaneItem = item;
}

function visualActivePaneItem() {
  if (focusedPanelItem && itemIsActivePaneTab(focusedPanelItem)) return focusedPanelItem;
  if (lastActivePaneItem && itemIsActivePaneTab(lastActivePaneItem)) return lastActivePaneItem;
  return null;
}

function seedVisualActivePaneItem(preferredItems = []) {
  const candidates = [
    ...preferredItems,
    focusedPanelItem,
    focusedTerminal,
    lastFocusedTmuxSession,
    ...activePaneItems(),
  ];
  const item = candidates.find(candidate => candidate && itemIsActivePaneTab(candidate));
  if (item) lastActivePaneItem = item;
  return item || null;
}

function setFocusedTerminal(session, options = {}) {
  const previousItem = focusedPanelItem;
  focusedTerminal = session;
  focusedPanelItem = session;
  rememberActivePaneItem(session);
  clearPendingFileEditorFocusExcept(session);
  if (isTmuxSession(session)) lastFocusedTmuxSession = session;
  dismissAttentionAlertsForSession(session);
  updateSessionButtonStates();
  for (const activeSession of activeSessions) updateTypingIndicator(activeSession);
  updatePanelInactiveOverlays();
  if (options.userInitiated === true) {
    rememberFileExplorerExplicitSyncSession(session);
    scheduleFileExplorerActiveTabSync(session, {explicit: true});
    recordFocusNavTransition(previousItem, session);
  }
  else recordAutoFocusNav(session, previousItem);
}

function clearFocusedTerminal(session) {
  if (focusedTerminal !== session) return;
  focusedTerminal = null;
  focusedPanelItem = null;
  updateSessionButtonStates();
  for (const activeSession of activeSessions) updateTypingIndicator(activeSession);
  updatePanelInactiveOverlays();
}

function setFocusedPanelItem(item, options = {}) {
  const previousItem = focusedPanelItem;
  if (focusedTerminal !== item) focusedTerminal = null;
  focusedPanelItem = item;
  rememberActivePaneItem(item);
  clearPendingFileEditorFocusExcept(item);
  if (isTmuxSession(item)) {
    lastFocusedTmuxSession = item;
    dismissAttentionAlertsForSession(item);
  }
  updateSessionButtonStates();
  for (const activeSession of activeSessions) updateTypingIndicator(activeSession);
  updatePanelInactiveOverlays();
  if (options.userInitiated === true) {
    if (isTmuxSession(item)) rememberFileExplorerExplicitSyncSession(item);
    if (isFileEditorItem(item)) {
      activeFile = fileItemPath(item);
      scheduleFileExplorerActiveFileReveal(activeFile);
    }
    const explicitFinderSync = isTmuxSession(item) || isFileEditorItem(item);
    if (!isFileExplorerItem(item)) scheduleFileExplorerActiveTabSync(item, {explicit: explicitFinderSync});
    recordFocusNavTransition(previousItem, item);
  }
  else recordAutoFocusNav(item, previousItem);
}

let autoFocusNavTimer = null;
// an AUTO-FOCUS-driven focus change records back/forward nav "as if clicked", so Back
// returns to where you were. Debounced by a short dwell so rapid auto-focus flapping (focus chasing
// needs-attention) records only the focus that LANDS, not every transient flip. User clicks already
// record immediately (activatePaneTab userInitiated); a back/forward re-activation lands on the item
// already at the stack head, so recordEditorNav's consecutive-dedupe makes this a no-op there.
function recordAutoFocusNav(item, previousItem = null) {
  if (!autoFocusEnabled || !item) return;
  if (autoFocusNavTimer) clearTimeout(autoFocusNavTimer);
  autoFocusNavTimer = setTimeout(() => {
    autoFocusNavTimer = null;
    if (focusedPanelItem === item) recordFocusNavTransition(previousItem, item);
  }, 500);
}

function clearPendingFileEditorFocusExcept(item) {
  for (const pendingItem of Array.from(pendingFileEditorFocus)) {
    if (pendingItem !== item) pendingFileEditorFocus.delete(pendingItem);
  }
}

function focusTerminalWhenAutoFocus(session, delay = 0) {
  if (!autoFocusEnabled) return;
  setTimeout(() => terminals.get(session)?.term?.focus?.(), delay);
}

function focusTerminalFromUserAction(session, delay = 0) {
  noteFileExplorerChangesSessionInteraction(session);
  setFocusedTerminal(session, {userInitiated: true});
  const run = () => terminals.get(session)?.term?.focus?.();
  if (delay > 0) setTimeout(run, delay);
  else run();
}

function clearFocusForInactiveLayout() {
  if (focusedTerminal && !activeSessions.includes(focusedTerminal)) focusedTerminal = null;
  if (focusedPanelItem && !activeSessions.includes(focusedPanelItem)) focusedPanelItem = null;
  if (lastActivePaneItem && !itemIsActivePaneTab(lastActivePaneItem)) lastActivePaneItem = null;
  if (lastFocusedTmuxSession && !activeSessions.includes(lastFocusedTmuxSession)) lastFocusedTmuxSession = null;
}

function terminalPaneIsActive(session) {
  return document.getElementById(`terminal-pane-${session}`)?.classList.contains('active') === true;
}

function selectPanelOnHover(item) {
  if (!item) return;
  if (!autoFocusEnabled) return;
  if (isTmuxSession(item) && terminalPaneIsActive(item)) {
    setFocusedTerminal(item);
    scheduleFit(item);
    focusTerminalWhenAutoFocus(item, 0);
    return;
  }
  if (focusedPanelItem === item) return;
  setFocusedPanelItem(item);
}

function updatePanelInactiveOverlays() {
  const activeItem = visualActivePaneItem() || seedVisualActivePaneItem();
  for (const [item, panel] of panelNodes.entries()) {
    panel.classList.toggle('focused-pane', item === activeItem);
    panel.classList.toggle('active-pane', item === activeItem);
  }
  // Re-color the active terminal's cursor yellow (and revert the rest) whenever focus moves.
  if (typeof refreshActiveTerminalCursor === 'function') refreshActiveTerminalCursor();
}

function esc(value) {
  return String(value ?? '').replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
}

const searchRankWeights = Object.freeze({
  perChar: 8,
  contiguous: 10,
  wordStart: 6,
  gapPenalty: 0.2,
  haystackLengthPenalty: 0.01,
  anchorPrimary: 20000,
  anchorSecondary: 12000,
  fieldIndexPenalty: 20,
  domainPrior: {
    files: {file: 6000, pane: 3000, command: 0, setting: 0},
    command: {pane: 6000, command: 3000, setting: 3000, file: 0},
  },
  fileNamePrefix: 3500,
  fileNameContains: 1800,
  fileNameSubsequence: 600,
  finderAlias: 25000,
  finderAliasFilesMode: 2500,
  recentSelectionBase: 1000,
  recencyCap: 900,
  recencyHalfLifeSeconds: 7 * 24 * 60 * 60,
  repoAffinity: 400,
  mixWindow: 8,
  mixSecondarySlots: 2,
  mixFirstSecondaryIndex: 2,
  mixSecondaryStep: 3,
});

function fuzzySubsequenceMatch(query, text) {
  const needle = String(query || '').toLowerCase().replace(/\s+/g, '');
  const haystack = String(text || '').toLowerCase();
  if (!needle) return {score: 0, indexes: []};
  let position = 0;
  let previousIndex = -1;
  let score = 0;
  const indexes = [];
  for (const char of needle) {
    const index = haystack.indexOf(char, position);
    if (index < 0) return null;
    const previousChar = haystack[index - 1] || '';
    const contiguous = previousIndex >= 0 && index === previousIndex + 1;
    const wordStart = index === 0 || /[\s/_:.-]/.test(previousChar);
    score += searchRankWeights.perChar;
    if (contiguous) score += searchRankWeights.contiguous;
    if (wordStart) score += searchRankWeights.wordStart;
    score -= Math.max(0, index - position) * searchRankWeights.gapPenalty;
    previousIndex = index;
    position = index + 1;
    indexes.push(index);
  }
  return {score: score - Math.max(0, haystack.length - needle.length) * searchRankWeights.haystackLengthPenalty, indexes};
}

function fuzzySubsequenceScore(query, text) {
  const match = fuzzySubsequenceMatch(query, text);
  return match ? match.score : Number.NEGATIVE_INFINITY;
}

function fuzzyCanonicalPrefixText(value) {
  return String(value || '').toLowerCase().replace(/[^a-z0-9]+/g, '');
}

function fuzzyFieldStartsWithQuery(query, text) {
  const needle = fuzzyCanonicalPrefixText(query);
  return Boolean(needle) && fuzzyCanonicalPrefixText(text).startsWith(needle);
}

function fuzzySearchScore(query, fields) {
  const tokens = String(query || '').trim().split(/\s+/).filter(Boolean);
  if (!tokens.length) return 0;
  const values = (Array.isArray(fields) ? fields : [fields]).map(value => String(value || '')).filter(Boolean);
  if (!values.length) return Number.NEGATIVE_INFINITY;
  let total = 0;
  for (const token of tokens) {
    let best = Number.NEGATIVE_INFINITY;
    for (const [index, value] of values.entries()) {
      let fieldScore = fuzzySubsequenceScore(token, value);
      if (Number.isFinite(fieldScore) && fuzzyFieldStartsWithQuery(token, value)) {
        fieldScore += index === 0 ? searchRankWeights.anchorPrimary : searchRankWeights.anchorSecondary;
      }
      if (Number.isFinite(fieldScore)) best = Math.max(best, fieldScore - index * searchRankWeights.fieldIndexPenalty);
    }
    if (!Number.isFinite(best)) return Number.NEGATIVE_INFINITY;
    total += best;
  }
  return total;
}

function fuzzyHighlightHtml(query, text) {
  const value = String(text ?? '');
  // Highlight EVERY query token's subsequence match, not just the first — mirrors fuzzySearchScore, which
  // scores all tokens. So "pa exploration" highlights both "PA" and "exploration", not only "pa".
  const tokens = String(query || '').trim().split(/\s+/).filter(Boolean);
  const indexes = new Set();
  for (const token of tokens) {
    const match = fuzzySubsequenceMatch(token, value);
    if (match) for (const matchIndex of match.indexes) indexes.add(matchIndex);
  }
  if (!indexes.size) return esc(value);
  const chars = Array.from(value);
  const parts = [];
  let index = 0;
  while (index < chars.length) {
    if (!indexes.has(index)) {
      parts.push(esc(chars[index]));
      index += 1;
      continue;
    }
    const start = index;
    while (index < chars.length && indexes.has(index)) index += 1;
    parts.push(`<mark class="fuzzy-match">${esc(chars.slice(start, index).join(''))}</mark>`);
  }
  return parts.join('');
}

function restoreElementScrollPosition(element, scrollTop, scrollLeft) {
  if (!element) return;
  element.scrollTop = scrollTop;
  element.scrollLeft = scrollLeft;
  requestAnimationFrame(() => {
    element.scrollTop = scrollTop;
    element.scrollLeft = scrollLeft;
  });
}

function replaceHtmlPreservingScroll(element, html) {
  if (!element) return;
  const scrollTop = element.scrollTop || 0;
  const scrollLeft = element.scrollLeft || 0;
  element.innerHTML = html;
  restoreElementScrollPosition(element, scrollTop, scrollLeft);
}

function wsUrl(session) {
  const scheme = location.protocol === 'https:' ? 'wss:' : 'ws:';
  return `${scheme}//${location.host}/ws?session=${encodeURIComponent(session)}`;
}

function renderTransportWarning() {
  if (!httpsWarning) return;
  const secure = location.protocol === 'https:';
  httpsWarning.hidden = secure;
  if (secure) return;
  const port = location.port || '9998';
  const selfSigned = `python3 yolomux.py --port ${port} --self-signed`;
  const cert = `python3 yolomux.py --port ${port} --cert /path/fullchain.pem --key /path/privkey.pem`;
  httpsWarning.dataset.tip = `No HTTPS. Highly recommend that you restart with ${selfSigned}. Or use ${cert}.`;
  httpsWarning.setAttribute('aria-label', httpsWarning.dataset.tip);
  httpsWarning.tabIndex = 0;
}

function stripTerminalQueryResponses(data) {
  return String(data)
    .replace(/\x1b\[[?>]?[0-9;]*c/g, '')
    .replace(/\x1bP[>|!][^\x1b]*(?:\x1b\\|\x9c)/g, '');
}

const terminalLinkPattern = /(?:https?:\/\/|file:\/\/|www\.)[^\s<>"'`]+/gi;
const terminalLinkClosePairs = [
  [')', '('],
  [']', '['],
  ['}', '{'],
];

function countChar(value, char) {
  let count = 0;
  for (const item of value) {
    if (item === char) count += 1;
  }
  return count;
}

function trimTerminalLinkCandidate(value) {
  let text = String(value || '').replace(/^[<("'`]+/, '');
  let changed = true;
  while (changed && text) {
    changed = false;
    const trimmed = text.replace(/[.,;:!?"'`>]+$/, '');
    if (trimmed !== text) {
      text = trimmed;
      changed = true;
    }
    for (const [closeChar, openChar] of terminalLinkClosePairs) {
      if (text.endsWith(closeChar) && countChar(text, closeChar) > countChar(text, openChar)) {
        text = text.slice(0, -1);
        changed = true;
      }
    }
  }
  return text;
}

function normalizeTerminalLink(value) {
  const text = trimTerminalLinkCandidate(value);
  if (!text) return '';
  if (/^www\./i.test(text)) return `https://${text}`;
  return text;
}

function openTerminalLink(rawLink) {
  const link = normalizeTerminalLink(rawLink);
  if (!link) return;
  try {
    const opened = window.open(link, '_blank', 'noopener,noreferrer');
    if (!opened) statusErr(`browser blocked link: ${esc(link)}`);
  } catch (error) {
    statusErr(`could not open link: ${esc(error)}`);
  }
}

function terminalTextLinks(lineText, rangeForOffsets, y = null) {
  const links = [];
  terminalLinkPattern.lastIndex = 0;
  for (const match of lineText.matchAll(terminalLinkPattern)) {
    const raw = match[0] || '';
    const text = trimTerminalLinkCandidate(raw);
    if (!text) continue;
    const startIndex = (match.index || 0) + raw.indexOf(text);
    const endIndex = startIndex + text.length;
    const range = rangeForOffsets(startIndex, endIndex);
    if (!range) continue;
    if (Number.isFinite(y) && (range.start.y > y || range.end.y < y)) continue;
    links.push({
      text,
      range,
      activate: () => openTerminalLink(text),
    });
  }
  return links;
}

function terminalLineLinks(lineText, y) {
  return terminalTextLinks(lineText, (startIndex, endIndex) => ({
    start: {x: startIndex + 1, y},
    end: {x: endIndex, y},
  }));
}

function terminalBufferLineText(line) {
  return line?.translateToString?.(true) || '';
}

// did `line` fill the terminal to its right edge? translateToString(true) trims trailing
// blanks, so a row whose printed text reaches `cols` had a non-blank last cell — evidence the content
// was CLIPPED at the edge and wrapped, not that it merely happened to end at the row. Used to gate the
// hanging-URL stitch: a complete URL ending well short of the edge (e.g. `See https://x.com`) is NOT a
// clipped URL and must not absorb the indented next row. cols<=0 (unknown width) → treat as not clipped.
function terminalRowReachesRightEdge(line, cols) {
  if (!Number.isFinite(cols) || cols <= 0) return false;
  return terminalBufferLineText(line).length >= cols;
}

// does the joined group text end mid-URL? True when the LAST url token reaches the very end of
// the string (no trailing whitespace/terminator). Used to decide whether to stitch a hanging-indent
// continuation row onto the group — only EXTEND a url token that runs off the row's right edge.
function terminalTailIsUnterminatedUrl(text) {
  if (!text) return false;
  terminalLinkPattern.lastIndex = 0;
  let last = null;
  for (const match of text.matchAll(terminalLinkPattern)) last = match;
  if (!last) return false;
  return last.index + last[0].length === text.length;
}

// a row shaped like a hanging-indent continuation — leading whitespace, then a URL-valid char
// (not a quote/bracket). Returns {indent, text} with the indent stripped, or null. isWrapped rows are
// not hanging continuations (they are real terminal soft-wraps and are handled by the isWrapped sweep).
function terminalRowHangingShape(buffer, index) {
  const line = buffer.getLine(index);
  if (!line || line.isWrapped === true) return null;
  const raw = terminalBufferLineText(line);
  const match = /^(\s+)([^\s<>"'`])/.exec(raw);
  if (!match) return null;
  return {indent: match[1].length, text: raw.slice(match[1].length)};
}

// row `index` continues the URL printed on row `index - 1` — its own row shape is a hanging
// indent AND the previous row's tail is an unterminated url token. Gates tightly so ordinary indented
// prose under a line that merely happens to end at a URL is not merged.
// ALSO require the previous row to reach the terminal's right edge, proving the URL was
// clipped/hard-wrapped. Without this, a complete URL at end-of-line falsely swallows the next row.
function terminalRowIsHangingUrlContinuation(buffer, index, cols) {
  if (!terminalRowHangingShape(buffer, index)) return false;
  const prev = buffer.getLine(index - 1);
  if (!prev) return false;
  if (!terminalRowReachesRightEdge(prev, cols)) return false;
  return terminalTailIsUnterminatedUrl(terminalBufferLineText(prev));
}

function terminalWrappedLineGroup(term, y) {
  const buffer = term.buffer?.active;
  if (!buffer?.getLine) return null;
  // terminal width gates the hanging-URL stitch (a clipped URL fills to the right edge).
  const cols = Number(term.cols) || 0;
  const requested = Math.max(0, y - 1);
  if (!buffer.getLine(requested)) return null;
  // Walk back to the logical line's first row: over terminal soft-wraps (isWrapped) AND over
  // hanging-indent URL continuations (agent-hard-wrapped URLs whose continuation is its own
  // non-wrapped, indented row). So querying ANY row of the wrapped URL yields the same full group.
  let start = requested;
  for (;;) {
    if (start > 0 && buffer.getLine(start)?.isWrapped === true) { start -= 1; continue; }
    if (start > 0 && terminalRowIsHangingUrlContinuation(buffer, start, cols)) { start -= 1; continue; }
    break;
  }
  // Forward pass from start. Include soft-wrap rows (indent 0) and, while the joined text still ends
  // mid-URL, hanging-indent continuation rows (indent stripped for link matching, but recorded so the
  // underline maps back to the row's REAL columns). Stop at the first row that is neither.
  const rows = [];
  let offset = 0;
  let joined = '';
  let index = start;
  for (;;) {
    let text;
    let indent = 0;
    if (index === start) {
      text = terminalBufferLineText(buffer.getLine(index));
    } else if (buffer.getLine(index)?.isWrapped === true) {
      text = terminalBufferLineText(buffer.getLine(index));
    } else if (terminalTailIsUnterminatedUrl(joined) && terminalRowReachesRightEdge(buffer.getLine(index - 1), cols)) {
      const shape = terminalRowHangingShape(buffer, index);
      if (!shape) break;
      indent = shape.indent;
      text = shape.text;
    } else {
      break;
    }
    rows.push({y: index + 1, text, indent, start: offset, end: offset + text.length});
    offset += text.length;
    joined += text;
    index += 1;
    if (!buffer.getLine(index)) break;
  }
  return {text: joined, rows};
}

function terminalWrappedOffsetPosition(group, offset, endPosition = false) {
  const target = endPosition ? Math.max(0, offset - 1) : offset;
  const row = group.rows.find(candidate => target >= candidate.start && target < candidate.end) || group.rows[group.rows.length - 1];
  if (!row) return null;
  // A stitched continuation row had `indent` leading spaces stripped before joining, so its real
  // terminal column is shifted right by that indent.
  return {x: Math.max(1, target - row.start + 1 + (row.indent || 0)), y: row.y};
}

function terminalWrappedRange(group, startIndex, endIndex) {
  const start = terminalWrappedOffsetPosition(group, startIndex, false);
  const end = terminalWrappedOffsetPosition(group, endIndex, true);
  if (!start || !end) return null;
  return {start, end};
}

function terminalWrappedLineLinks(term, y) {
  const group = terminalWrappedLineGroup(term, y);
  if (!group) return [];
  if (group.rows.length === 1) return terminalLineLinks(group.text, y);
  return terminalTextLinks(group.text, (startIndex, endIndex) => terminalWrappedRange(group, startIndex, endIndex), y);
}

function installTerminalLinkProvider(term) {
  if (typeof term.registerLinkProvider !== 'function') return;
  term.registerLinkProvider({
    provideLinks: (y, callback) => {
      try {
        callback(terminalWrappedLineLinks(term, y));
      } catch (_) {
        callback([]);
      }
    },
  });
}

function dedentSelectionText(value) {
  const text = String(value ?? '').replace(/\r\n/g, '\n').replace(/\r/g, '\n');
  const lines = text.split('\n');
  const indents = lines
    .filter(line => line.trim().length > 0 && /^[ \t]+/.test(line))
    .map(line => (line.match(/^[ \t]+/) || [''])[0].length);
  const stripBullet = line => line.replace(/^[ \t]*[●•]\s*/, '');
  if (!indents.length) return lines.map(stripBullet).join('\n');
  const commonIndent = Math.min(...indents);
  return lines
    .map(line => line.trim().length > 0 && /^[ \t]+/.test(line) ? line.slice(commonIndent) : line)
    .map(stripBullet)
    .join('\n');
}

async function copyTextToClipboard(text) {
  const clipboard = globalThis.navigator?.clipboard;
  const value = String(text ?? '');
  if (clipboard?.writeText) {
    try {
      await clipboard.writeText(value);
      return;
    } catch (_) {
      // Fall through to execCommand. Some browsers expose navigator.clipboard
      // but reject writes on self-signed or permission-limited pages.
    }
  }
  const textarea = document.createElement('textarea');
  textarea.value = value;
  textarea.setAttribute('readonly', '');
  textarea.style.position = 'fixed';
  textarea.style.left = '-10000px';
  textarea.style.top = '-10000px';
  document.body.appendChild(textarea);
  textarea.select();
  const copied = document.execCommand?.('copy') === true;
  textarea.remove();
  if (!copied) throw new Error('clipboard copy is unavailable');
}

function copyTextToClipboardViaCopyEvent(text) {
  const value = String(text ?? '');
  let copied = false;
  const onCopy = event => {
    if (!event?.clipboardData) return;
    event.clipboardData.setData('text/plain', value);
    event.preventDefault();
    event.stopImmediatePropagation?.();
    event.stopPropagation?.();
    copied = true;
  };
  document.addEventListener?.('copy', onCopy, true);
  try {
    return document.execCommand?.('copy') === true && copied;
  } finally {
    document.removeEventListener?.('copy', onCopy, true);
  }
}

// ONE clipboard-write chain for terminal-initiated copies (shortcut copy AND the OSC 52
// bridge): synchronous copy-event first — it stays inside any live user activation — then the async
// navigator.clipboard path as fallback. Status text reports success/failure either way.
function writeTerminalTextToClipboard(text, label = 'copied') {
  if (copyTextToClipboardViaCopyEvent(text)) {
    copyDebug('clipboard', {via: 'copy-event', chars: String(text ?? '').length, ok: true});
    statusEl.textContent = label;
    return;
  }
  copyTextToClipboard(text)
    .then(() => {
      copyDebug('clipboard', {via: 'async', chars: String(text ?? '').length, ok: true});
      statusEl.textContent = label;
    })
    .catch(error => {
      copyDebug('clipboard', {via: 'async', chars: String(text ?? '').length, ok: false, error: String(error)});
      statusErr(`copy failed: ${esc(error)}`);
    });
}

// opt-in live instrumentation for the copy path. Set storage key 'yolomux.debugCopy' to '1'
// and every copy decision logs ONE compact console line — enough to see which link breaks without
// changing behavior.
function copyDebugEnabled() {
  return storageGet('yolomux.debugCopy') === '1';
}

function copyDebug(stage, fields = {}) {
  if (!copyDebugEnabled()) return;
  const parts = Object.entries(fields).map(([key, value]) => `${key}=${value}`).join(' ');
  console.log(`[copy-debug] ${stage} ${parts}`);
}

function createContextMenuController() {
  let menu = null;
  const close = () => {
    if (!menu) return;
    menu.remove();
    menu = null;
    document.removeEventListener('pointerdown', pointerdown, true);
    document.removeEventListener('keydown', keydown, true);
    window.removeEventListener('blur', close);
  };
  const pointerdown = event => {
    if (menu?.contains(event.target)) return;
    close();
  };
  const keydown = event => {
    if (event.key === 'Escape') close();
  };
  return {
    close,
    isOpen: () => Boolean(menu),
    open(nextMenu, x, y) {
      close();
      menu = nextMenu;
      menu.addEventListener('pointerdown', event => event.stopPropagation());
      document.body.appendChild(menu);
      positionContextMenu(menu, x, y);
      document.addEventListener('pointerdown', pointerdown, true);
      document.addEventListener('keydown', keydown, true);
      window.addEventListener('blur', close);
    },
  };
}

function makeButton(options = {}) {
  const button = document.createElement('button');
  button.type = options.type || 'button';
  if (options.id) button.id = options.id;
  if (options.className) button.className = options.className;
  if (options.role) button.setAttribute('role', options.role);
  if (options.html !== undefined) button.innerHTML = options.html;
  else if (options.label !== undefined) button.textContent = options.label;
  button.disabled = options.disabled === true;
  if (options.title) button.title = options.title;
  if (options.ariaLabel) button.setAttribute('aria-label', options.ariaLabel);
  if (options.pressed !== undefined) button.setAttribute('aria-pressed', options.pressed ? 'true' : 'false');
  if (options.checked !== undefined) {
    button.setAttribute('aria-checked', options.checked ? 'true' : 'false');
    if (options.checked === true) button.dataset.checked = 'true';
  }
  if (options.dataset) {
    for (const [key, value] of Object.entries(options.dataset)) {
      if (value !== undefined && value !== null) button.dataset[key] = String(value);
    }
  }
  if (typeof options.onClick === 'function') button.addEventListener('click', options.onClick);
  return button;
}

function delegate(parent, type, selector, handler, options = {}) {
  if (!parent || typeof handler !== 'function') return null;
  const listener = event => {
    const target = event.target?.closest?.(selector);
    if (!target || !parent.contains(target)) return;
    handler(event, target);
  };
  parent.addEventListener(type, listener, options);
  return listener;
}

// One owner for the per-session/-item DOM id scheme. Both the element that sets the id and every
// getElementById/querySelector that looks it up route through these, so the prefix lives in one place
// (the ids are produced + consumed across 7 partials). Changing a prefix is then a one-line edit.
const panelDomId = item => `panel-${item}`;
const paneTabDomId = session => `panel-tab-${session}`;
const terminalDomId = session => `term-${session}`;
const transcriptDomId = session => `transcript-${session}`;
const summaryDomId = session => `summary-${session}`;

// One inflight-dedup wrapper: run makeRequest() at most once per key while a call is outstanding, so
// concurrent callers for the same key share the single in-flight promise and clean up after it settles.
// When canReuse is false the caller wants an untracked fresh fetch, so it runs without registering. The
// TTL cache-hit check and any resource-specific guards stay at the call site; this owns only the inflight
// Map bookkeeping that was hand-rolled identically per filesystem resource (dir listing, path info, blame).
function dedupeInflight(inflight, key, canReuse, makeRequest) {
  if (canReuse) {
    const existing = inflight.get(key);
    if (existing) return existing;
  }
  const request = makeRequest();
  if (!canReuse) return request;
  inflight.set(key, request);
  return (async () => {
    try {
      return await request;
    } finally {
      if (inflight.get(key) === request) inflight.delete(key);
    }
  })();
}

function appendContextMenuButton(menu, label, handler, closeMenu, options = {}) {
  const iconHtml = options.iconHtml ? stripTitleAttrs(options.iconHtml) : '';
  const shortcutHtml = options.shortcut ? `<span class="context-menu-shortcut">${esc(options.shortcut)}</span>` : '';
  const buttonHtml = iconHtml || shortcutHtml
    ? `<span class="context-menu-line">${iconHtml ? `<span class="context-menu-icon">${iconHtml}</span>` : ''}<span class="context-menu-label">${esc(label)}</span>${shortcutHtml}</span>`
    : undefined;
  const button = makeButton({
    ...options,
    html: buttonHtml,
    label: buttonHtml ? undefined : label,
    ariaLabel: options.ariaLabel || label,
    role: options.checked !== undefined ? 'menuitemcheckbox' : 'menuitem',
  });
  button.addEventListener('click', event => {
    event.preventDefault();
    event.stopPropagation();
    if (!button.disabled) handler();
    closeMenu();
  });
  menu.appendChild(button);
  return button;
}

function appendContextMenuSeparator(menu) {
  const separator = document.createElement('div');
  separator.className = 'terminal-context-menu-separator';
  separator.role = 'separator';
  menu.appendChild(separator);
  return separator;
}

function contextMenuIsOpen() {
  return terminalContextMenu.isOpen() || fileContextMenu.isOpen() || sessionContextMenu.isOpen() || linkContextMenu.isOpen();
}

function rootCssLengthPx(name) {
  if (!document.body || typeof window.getComputedStyle !== 'function') return 0;
  const value = window.getComputedStyle(document.documentElement).getPropertyValue(name).trim();
  if (!value) return 0;
  const probe = document.createElement('div');
  probe.style.position = 'fixed';
  probe.style.visibility = 'hidden';
  probe.style.pointerEvents = 'none';
  probe.style.width = value;
  probe.style.height = '0';
  document.body.appendChild(probe);
  const width = probe.getBoundingClientRect().width || 0;
  probe.remove();
  return Math.max(0, width);
}

function popoverEdgeGapPx() {
  return rootCssLengthPx('--popover-edge-gap');
}

function positionContextMenu(menu, x, y) {
  const rect = menu.getBoundingClientRect();
  const edgeGap = popoverEdgeGapPx();
  const left = Math.min(Math.max(edgeGap, x), Math.max(edgeGap, window.innerWidth - rect.width - edgeGap));
  const top = Math.min(Math.max(edgeGap, y), Math.max(edgeGap, window.innerHeight - rect.height - edgeGap));
  menu.style.left = `${Math.round(left)}px`;
  menu.style.top = `${Math.round(top)}px`;
}

function closeTerminalContextMenu() {
  terminalContextMenu.close();
}

function closeFileContextMenu() {
  fileContextMenu.close();
}

function closeSessionContextMenu() {
  sessionContextMenu.close();
}

function closeLinkContextMenu() {
  linkContextMenu.close();
}

function closeContextMenus() {
  closeTerminalContextMenu();
  closeFileContextMenu();
  closeSessionContextMenu();
  closeLinkContextMenu();
}

// right-click menu for links in AI/markdown content — Copy URL / Open URL. Bound on the
// YO!agent body and markdown previews via installLinkContextMenu(container).
function showLinkContextMenu(anchor, x, y) {
  closeTerminalContextMenu();
  closeFileContextMenu();
  closeSessionContextMenu();
  closeOtherSessionPopovers(null);
  const href = anchor?.href || '';
  if (!href) return;
  const menu = document.createElement('div');
  menu.className = 'terminal-context-menu link-context-menu';
  menu.setAttribute('role', 'menu');
  appendContextMenuButton(menu, t('contextmenu.copyUrl'), () => copyTextToClipboard(href), closeLinkContextMenu);
  appendContextMenuButton(menu, t('contextmenu.openUrl'), () => window.open(href, '_blank', 'noopener,noreferrer'), closeLinkContextMenu);
  linkContextMenu.open(menu, x, y);
}

function installLinkContextMenu(container) {
  if (!container || container.dataset.linkContextMenuBound === '1') return;
  container.dataset.linkContextMenuBound = '1';
  container.addEventListener('contextmenu', event => {
    const anchor = event.target?.closest?.('a[href]');
    if (!anchor || !container.contains(anchor)) return;
    event.preventDefault();
    event.stopPropagation();
    showLinkContextMenu(anchor, event.clientX, event.clientY);
  });
}

function nodeInsideElement(element, node) {
  if (!element || !node) return false;
  if (element === node) return true;
  if (element.contains?.(node)) return true;
  let current = node.parentElement || node.parentNode || null;
  while (current) {
    if (current === element) return true;
    current = current.parentElement || current.parentNode || null;
  }
  return false;
}

function browserSelectionTextInside(container) {
  if (!container) return '';
  const selection = globalThis.getSelection?.() || globalThis.window?.getSelection?.();
  const text = String(selection?.toString?.() || '');
  if (!text) return '';
  const anchorNode = selection.anchorNode || null;
  const focusNode = selection.focusNode || null;
  if (!anchorNode && !focusNode) return '';
  return nodeInsideElement(container, anchorNode) || nodeInsideElement(container, focusNode) ? text : '';
}

function terminalSelectedText(term, container = null) {
  return term.getSelection?.() || browserSelectionTextInside(container);
}

async function copyTerminalSelection(session, term, options = {}, container = null) {
  // N7: the context menu passes the selection captured at right-click time, because by the time the user
  // clicks the menu the live selection may be gone (focus moved to the menu).
  const selected = options.selectionText != null ? options.selectionText : terminalSelectedText(term, container);
  if (!selected) {
    statusEl.textContent = 'nothing selected';
    return;
  }
  const text = options.dedent ? dedentSelectionText(selected) : selected;
  try {
    await copyTextToClipboard(text);
    statusEl.textContent = options.dedent ? 'copied without indent' : 'copied';
  } catch (error) {
    statusErr(`copy failed: ${esc(error)}`);
  }
}

function copyTerminalSelectionFromShortcut(session, term, options = {}, container = null) {
  const selected = terminalSelectedText(term, container);
  if (!selected) {
    statusEl.textContent = 'nothing selected';
    return false;
  }
  const text = options.dedent ? dedentSelectionText(selected) : selected;
  writeTerminalTextToClipboard(text, options.dedent ? 'copied without indent' : 'copied');
  return true;
}

function copyTerminalSelectionToClipboardEvent(session, term, event, container = null) {
  const selected = terminalSelectedText(term, container);
  if (!selected || !event?.clipboardData) return false;
  event.clipboardData.setData('text/plain', selected);
  event.preventDefault();
  event.stopPropagation();
  statusEl.textContent = 'copied';
  term.clearSelection?.();
  return true;
}

async function copyTmuxSelectionToClipboard(session) {
  const payloadPromise = fetchTmuxSelectionText(session);
  try {
    const {payload, text} = await copyDeferredTextToClipboard(payloadPromise);
    const chars = Number.isFinite(Number(payload.chars)) ? Number(payload.chars) : text.length;
    statusEl.textContent = `copied ${chars} chars from tmux`;
    return true;
  } catch (error) {
    if (error?.noClipboardText) {
      statusEl.textContent = error.message || 'nothing selected';
      return false;
    }
    statusErr(`copy failed: ${esc(error)}`);
    return false;
  }
}

async function fetchTmuxSelectionText(session) {
  const payload = await apiFetchJson(`/api/tmux-copy-selection?session=${encodeURIComponent(session)}`, {method: 'POST'});
  const text = payload?.copied ? String(payload.text || '') : '';
  if (!text) {
    const error = new Error(payload?.error === 'tmux copy mode is not active' ? 'nothing selected' : (payload?.error || 'nothing selected'));
    error.noClipboardText = true;
    throw error;
  }
  return {payload, text};
}

async function copyDeferredTextToClipboard(payloadPromise) {
  const clipboard = globalThis.navigator?.clipboard;
  if (clipboard?.write && typeof globalThis.ClipboardItem === 'function' && typeof globalThis.Blob === 'function') {
    const textBlob = payloadPromise.then(({text}) => new Blob([text], {type: 'text/plain'}));
    try {
      await clipboard.write([new ClipboardItem({'text/plain': textBlob})]);
      return await payloadPromise;
    } catch (error) {
      if (error?.noClipboardText) throw error;
      const result = await payloadPromise;
      await copyTextToClipboard(result.text);
      return result;
    }
  }
  const result = await payloadPromise;
  await copyTextToClipboard(result.text);
  return result;
}

// ROOT CAUSE: while Claude (or any TUI) owns the mouse inside tmux, the visible selection is the
// APP's — a plain drag never creates an xterm selection, and the copied text instead arrives as an
// OSC 52 clipboard escape (app -> tmux `set-clipboard` passthrough -> our PTY -> xterm.js). xterm.js
// DROPS OSC 52 unless a handler is registered, so those copies silently vanished. This bridge decodes
// the escape and writes the browser clipboard. It also catches tmux copy-mode `copy-pipe` buffers.
// Payload format: "Pc;Pd" — Pc selects clipboard(s) (c/p/s/q...), Pd is base64 text or '?' (a READ
// request, which we never answer so apps cannot exfiltrate the browser clipboard).
function osc52ClipboardText(data) {
  const raw = String(data ?? '');
  const semi = raw.indexOf(';');
  if (semi < 0) return null;
  const payload = raw.slice(semi + 1);
  if (!payload || payload === '?') return null;
  try {
    const binary = atob(payload);
    const bytes = new Uint8Array(binary.length);
    for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
    const decoded = new TextDecoder('utf-8', {fatal: false}).decode(bytes);
    return decoded || null;
  } catch (_error) {
    return null; // not valid base64: ignore rather than copy garbage
  }
}

function installTerminalOsc52Bridge(session, term) {
  if (!term?.parser?.registerOscHandler) return false;
  term.parser.registerOscHandler(52, data => {
    const text = osc52ClipboardText(data);
    copyDebug('osc52', {session, payloadChars: String(data ?? '').length, textChars: text ? text.length : 0});
    if (text) writeTerminalTextToClipboard(text, `copied ${text.length} chars`);
    return true; // consumed either way; '?' queries get no reply
  });
  return true;
}

function handleTerminalCopyShortcutKeydown(session, term, container, event) {
  if (event.type !== 'keydown') return false;
  if (event.code !== 'KeyC' && event.key?.toLowerCase() !== 'c') return false;
  const isTmuxCopyShortcut = event.altKey
    && !event.shiftKey
    && ((isMacPlatform() && event.metaKey && !event.ctrlKey)
      || (!isMacPlatform() && event.ctrlKey && !event.metaKey));
  if (isTmuxCopyShortcut) {
    event.preventDefault();
    copyTmuxSelectionToClipboard(session);
    return true;
  }
  const isCmdC = event.metaKey && !event.ctrlKey && !event.altKey;
  const isCtrlC = event.ctrlKey && !event.metaKey && !event.altKey;
  if (!isCmdC && !isCtrlC) return false;
  const xtermSelected = term.getSelection?.() || '';
  const browserSelected = browserSelectionTextInside(container);
  const selected = xtermSelected || browserSelected;
  copyDebug('shortcut', {
    session,
    combo: isCmdC ? 'cmd-c' : 'ctrl-c',
    xtermSel: xtermSelected.length,
    browserSel: browserSelected.length,
    branch: selected ? 'copy' : (isCmdC ? 'no-selection' : 'sigint'),
  });
  if (!selected) {
    if (isCmdC) {
      event.preventDefault();
      // in a Claude/tmux pane the APP owns the mouse, so a plain drag never creates an xterm
      // selection — tell the user the working gestures instead of dead-ending.
      statusEl.textContent = isMacPlatform()
        ? 'nothing selected — Option-drag selects while Claude/tmux owns the mouse; Cmd-Option-C copies the tmux selection'
        : 'nothing selected — Shift-drag selects while the app owns the mouse; Ctrl-Alt-C copies the tmux selection';
      return true;
    }
    return false; // no selection: let Ctrl-C through as SIGINT
  }
  event.preventDefault();
  copyTerminalSelectionFromShortcut(session, term, {}, container);
  term.clearSelection?.(); // so a second Ctrl-C falls through to SIGINT
  return true;
}

function installTerminalCopyShortcut(session, term, container = null) {
  // Ctrl-C / Cmd-C copy the xterm selection. Plain Ctrl-C with NO selection
  // must still send SIGINT to the PTY, and Cmd-C must stay browser/xterm copy
  // only. Tmux copy-mode text has a separate explicit shortcut/menu action.
  container?.addEventListener?.('keydown', event => {
    if (!handleTerminalCopyShortcutKeydown(session, term, container, event)) return;
    event.stopImmediatePropagation?.();
    event.stopPropagation?.();
  }, {capture: true});
  term.attachCustomKeyEventHandler?.(event => {
    return handleTerminalCopyShortcutKeydown(session, term, container, event) ? false : true;
  });
}

function showTerminalContextMenu(session, term, x, y, container = null, presetSelection = '') {
  closeFileContextMenu();
  closeSessionContextMenu();
  closeFileImagePreview();
  closeOtherSessionPopovers(null);
  const menu = document.createElement('div');
  menu.className = 'terminal-context-menu';
  menu.setAttribute('role', 'menu');
  // N7: prefer the selection captured at right-click time over a live re-read (which can be empty by now).
  const selected = presetSelection || terminalSelectedText(term, container);
  const items = [
    ['Copy', false],
    ['Copy without indent', true],
  ];
  for (const [label, dedent] of items) {
    appendContextMenuButton(menu, label, () => copyTerminalSelection(session, term, {dedent, selectionText: selected}, container), closeTerminalContextMenu, {disabled: !selected});
  }
  appendContextMenuSeparator(menu);
  appendContextMenuButton(menu, t('terminal.copyTmuxSelection'), () => copyTmuxSelectionToClipboard(session), closeTerminalContextMenu);
  terminalContextMenu.open(menu, x, y);
}

function installTerminalContextMenu(session, term, container) {
  // N7: right-click must NOT clear the highlight. xterm clears its selection on mousedown, so capture the
  // selected text on the right-mousedown (capture phase, before xterm's handler) and stopPropagation so
  // xterm never processes that mousedown — the highlight stays visible AND the menu has the text even if
  // focus moves to the menu. No preventDefault, so the contextmenu event still fires normally.
  let rightClickSelection = '';
  container.addEventListener('mousedown', event => {
    if (event.button !== 2) return;
    rightClickSelection = terminalSelectedText(term, container);
    event.stopPropagation();
  }, {capture: true});
  container.addEventListener('contextmenu', event => {
    event.preventDefault();
    event.stopPropagation();
    showTerminalContextMenu(session, term, event.clientX, event.clientY, container, rightClickSelection);
    rightClickSelection = '';
  });
}

function showTabContextMenu(item, x, y, options = {}) {
  if (!isPinnableTab(item) && !isTmuxSession(item)) return;
  closeAppMenus();
  closeTerminalContextMenu();
  closeFileContextMenu();
  closeOtherSessionPopovers(null);
  const menu = document.createElement('div');
  menu.className = 'terminal-context-menu session-context-menu';
  menu.setAttribute('role', 'menu');
  if (isPinnableTab(item)) {
    const pinned = tabIsPinned(item);
    appendContextMenuButton(
      menu,
      pinned ? t('tab.unpin') : t('tab.pin'),
      () => setTabPinned(item, !pinned),
      closeSessionContextMenu,
      {
        checked: pinned,
        iconHtml: appMenuUiIcon('pin', pinned),
        shortcut: `${appShortcutText('K')} Enter`,
      },
    );
  }
  if (isTmuxSession(item)) {
    if (isPinnableTab(item)) appendContextMenuSeparator(menu);
    const renameAction = options.tab ? () => beginPaneTabRename(options.tab, item) : () => renameTmuxSession(item);
    for (const command of tmuxSessionActionCommands(item, {renameAction, includeKill: false})) {
      appendContextMenuButton(menu, command.label, command.action, closeSessionContextMenu, {disabled: command.disabled, checked: command.checked});
    }
    const viewItems = tmuxSessionViewCommands(item).filter(command => command.label !== 'Pane details');
    for (const command of viewItems) {
      appendContextMenuButton(menu, command.label, command.action, closeSessionContextMenu, {
        disabled: command.disabled,
        checked: command.checked,
        title: command.detail || '',
      });
    }
    appendContextMenuSeparator(menu);
    const killItem = tmuxSessionKillCommand(item);
    appendContextMenuButton(menu, killItem.label, killItem.action, closeSessionContextMenu, {disabled: killItem.disabled, className: 'danger'});
  }
  sessionContextMenu.open(menu, x, y);
}

function showSessionContextMenu(session, x, y, options = {}) {
  showTabContextMenu(session, x, y, options);
}
function emptyLayoutSlots() {
  return {[layoutTreeKey]: null};
}

function emptyPaneState() {
  return {active: null, tabs: []};
}

function emptyPlaceholderPaneState() {
  return {active: null, tabs: [], placeholder: true};
}

function emptyPlaceholderLayoutSlots(slot = 'left') {
  const next = emptyLayoutSlots();
  next[slot] = emptyPlaceholderPaneState();
  next[layoutTreeKey] = leafNode(slot);
  return next;
}

function leafNode(slot) {
  return {slot};
}

function splitNode(direction, first, second, pct = defaultSplitPercent) {
  return {split: direction, pct: splitPercent(pct), children: [first, second]};
}

function splitPercent(value) {
  if (value === null || value === undefined || value === '') return defaultSplitPercent;
  const number = Number(value);
  if (!Number.isFinite(number)) return defaultSplitPercent;
  return Math.min(maxSplitPercent, Math.max(minSplitPercent, number));
}

function splitPercentForDisplay(value) {
  const rounded = Math.round(splitPercent(value) * 10) / 10;
  return Number.isInteger(rounded) ? String(rounded) : String(rounded);
}

function layoutLeafSlots(node) {
  if (!node) return [];
  if (node.slot) return [node.slot];
  return (node.children || []).flatMap(layoutLeafSlots);
}

// a signature of the layout TREE SHAPE — topology + slot ids + split dirs/pcts — that
// EXCLUDES each pane's tabs order and active item (those live in the per-slot pane state, not the
// tree). Equal signatures mean a same-shape change (reorder / activate / move-within-or-between
// existing panes / replace-in-place / close-a-non-last tab) that needs no grid/topbar teardown.
function layoutShapeSignature(slots = layoutSlots) {
  const sig = node => {
    if (!node) return '';
    if (node.slot) return `S:${node.slot}`;
    return `${node.split}:${splitPercent(node.pct)}:[${(node.children || []).map(sig).join(',')}]`;
  };
  return sig(slots?.[layoutTreeKey]);
}

function layoutSlotKeys(slots = layoutSlots) {
  const treeSlots = layoutLeafSlots(slots?.[layoutTreeKey]);
  if (treeSlots.length) return treeSlots;
  return Object.keys(slots || {}).filter(key => key !== layoutTreeKey && paneHasLayoutContent(key, slots));
}

function cloneLayoutSlots(slots = layoutSlots) {
  return JSON.parse(JSON.stringify(slots || emptyLayoutSlots()));
}

function layoutSlotsSignature(slots = layoutSlots) {
  return JSON.stringify(normalizeLayoutSlots(cloneLayoutSlots(slots)));
}

function compactCurrentLayoutSlots(options = {}) {
  const normalized = normalizeLayoutSlots(layoutSlots);
  if (layoutSlotsSignature(normalized) === layoutSlotsSignature(layoutSlots)) return false;
  applyLayoutSlots(normalized, {
    focusSession: options.focusSession || focusedPanelItem || undefined,
    prune: false,
  });
  return true;
}

function nextLayoutSlot(slots = layoutSlots) {
  const used = new Set(Object.keys(slots || {}));
  let index = 1;
  while (used.has(`slot${index}`)) index += 1;
  return `slot${index}`;
}

function normalizeLayoutMode(value) {
  const text = String(value || '').trim();
  return layoutModeValues.includes(text) ? text : defaultLayoutMode;
}

function configuredDefaultLayoutMode() {
  return normalizeLayoutMode(initialSetting('general.default_layout', defaultLayoutMode));
}

function layoutModePaneCount(mode, items) {
  const count = Array.isArray(items) ? items.length : 0;
  if (!count) return 0;
  const normalized = normalizeLayoutMode(mode);
  if (normalized === 'single') return 1;
  if (normalized === 'split') return Math.min(2, count);
  if (normalized === 'grid') return Math.min(4, count);
  return count;
}

function layoutModeBaseSlots(mode) {
  if (mode === 'grid') return ['leftTop', 'rightTop', 'leftBottom', 'rightBottom'];
  if (mode === 'split') return ['left', 'right'];
  if (mode === 'wall') return ['left', 'right'];
  return ['left'];
}

function layoutModeSlotNames(mode, count, options = {}) {
  const finderSlot = options.finderSlot || null;
  const used = {[layoutTreeKey]: null};
  if (finderSlot) used[finderSlot] = emptyPaneState();
  const slots = [];
  for (const slot of options.preferredSlots || []) {
    if (slots.length >= count) break;
    if (!slot || slot === finderSlot || used[slot]) continue;
    slots.push(slot);
    used[slot] = emptyPaneState();
  }
  for (const slot of layoutModeBaseSlots(normalizeLayoutMode(mode))) {
    if (slots.length >= count) break;
    if (slot === finderSlot || used[slot]) continue;
    slots.push(slot);
    used[slot] = emptyPaneState();
  }
  while (slots.length < count) {
    const slot = nextLayoutSlot(used);
    slots.push(slot);
    used[slot] = emptyPaneState();
  }
  return slots;
}

function partitionLayoutItems(items, count) {
  const groups = [];
  let start = 0;
  for (let index = 0; index < count; index += 1) {
    const remainingItems = items.length - start;
    const remainingGroups = count - index;
    const size = Math.ceil(remainingItems / remainingGroups);
    groups.push(items.slice(start, start + size));
    start += size;
  }
  return groups;
}

function rowTreeForSlots(slots) {
  return slots.map(leafNode).reduce((tree, leaf) => (tree ? splitNode('row', tree, leaf) : leaf), null);
}

function columnTreeForSlots(slots) {
  return slots.map(leafNode).reduce((tree, leaf) => (tree ? splitNode('column', tree, leaf) : leaf), null);
}

function gridTreeForSlots(slots) {
  if (slots.length <= 2) return rowTreeForSlots(slots);
  const left = columnTreeForSlots([slots[0], slots[2]].filter(Boolean));
  const right = columnTreeForSlots([slots[1], slots[3]].filter(Boolean));
  return right ? splitNode('row', left, right) : left;
}

function layoutModeTreeForSlots(mode, slots) {
  return normalizeLayoutMode(mode) === 'grid' ? gridTreeForSlots(slots) : rowTreeForSlots(slots);
}

function layoutSlotsForItems(items, mode, options = {}) {
  const selected = (Array.isArray(items) ? items : []).filter(item => isLayoutItem(item));
  if (!selected.length) return emptyPlaceholderLayoutSlots(options.emptySlot || 'left');
  const normalizedMode = normalizeLayoutMode(mode);
  const paneCount = layoutModePaneCount(normalizedMode, selected);
  const slots = layoutModeSlotNames(normalizedMode, paneCount, options);
  const groups = partitionLayoutItems(selected, slots.length);
  const active = selected.includes(options.active) ? options.active : selected[0];
  const next = emptyLayoutSlots();
  for (let index = 0; index < slots.length; index += 1) {
    const group = groups[index] || [];
    next[slots[index]] = paneStateWithTabs(group, group.includes(active) ? active : group[0]);
  }
  next[layoutTreeKey] = layoutModeTreeForSlots(normalizedMode, slots);
  return compactLayoutSlots(next);
}

function normalizePaneState(raw, seen, options = {}) {
  const state = emptyPaneState();
  const items = Array.isArray(raw) ? raw : Array.isArray(raw?.tabs) ? raw.tabs : [];
  const preserveRemovedItems = new Set(options.preserveRemovedItems || []);
  let hadPreservedRemovedItem = false;
  for (const value of items) {
    if (preserveRemovedItems.has(String(value))) hadPreservedRemovedItem = true;
    const item = resolveLayoutItem(value);
    if (preserveRemovedItems.has(item)) hadPreservedRemovedItem = true;
    if (isLayoutItem(item) && !seen.has(item)) {
      state.tabs.push(item);
      seen.add(item);
    }
  }
  state.tabs = orderPaneTabs(state.tabs);
  const active = resolveLayoutItem(raw?.active);
  state.active = state.tabs.includes(active) ? active : state.tabs[0] || null;
  if (!state.tabs.length && !Array.isArray(raw) && raw?.placeholder === true) state.placeholder = true;
  if (!state.tabs.length && options.preserveRemovedSlots === true && hadPreservedRemovedItem) state.placeholder = true;
  return state;
}

function normalizeLayoutSlots(value, options = {}) {
  let normalized;
  if (!value || typeof value !== 'object') normalized = emptyPlaceholderLayoutSlots();
  else if (value[layoutTreeKey]) normalized = normalizeTreeLayout(value, options);
  else normalized = normalizeLegacyLayoutSlots(value, options);
  return normalizeFileExplorerDock(normalized);
}

function normalizeTreeLayout(value, options = {}) {
  const next = emptyLayoutSlots();
  const seen = new Set();
  next[layoutTreeKey] = normalizeLayoutNode(value[layoutTreeKey], value, next, seen, options);
  return compactLayoutSlots(next);
}

function normalizeLayoutNode(node, value, next, seen, options = {}) {
  if (!node || typeof node !== 'object') return null;
  if (typeof node.slot === 'string') {
    next[node.slot] = normalizePaneState(value[node.slot], seen, options);
    return leafNode(node.slot);
  }
  const direction = node.split === 'column' ? 'column' : 'row';
  const children = (node.children || []).map(child => normalizeLayoutNode(child, value, next, seen, options)).filter(Boolean);
  if (children.length >= 2) return splitNode(direction, children[0], children[1], node.pct);
  return children[0] || null;
}

function normalizeLegacyLayoutSlots(value, options = {}) {
  const next = emptyLayoutSlots();
  const seen = new Set();
  for (const side of paneKeys) {
    next[side] = normalizePaneState(value[side], seen, options);
  }
  next[layoutTreeKey] = legacyLayoutTree(next);
  return compactLayoutSlots(next);
}

function legacyLayoutTree(slots) {
  const columns = basePaneKeys.map(column => legacyColumnTree(column, slots)).filter(Boolean);
  if (columns.length >= 2) return splitNode('row', columns[0], columns[1]);
  return columns[0] || null;
}

function legacyColumnTree(column, slots) {
  if (paneHasLayoutContent(column, slots)) return leafNode(column);
  const top = verticalSplitSlot(column, 'top');
  const bottom = verticalSplitSlot(column, 'bottom');
  const topNode = paneHasLayoutContent(top, slots) ? leafNode(top) : null;
  const bottomNode = paneHasLayoutContent(bottom, slots) ? leafNode(bottom) : null;
  if (topNode && bottomNode) return splitNode('column', topNode, bottomNode);
  return topNode || bottomNode;
}

function compactLayoutSlots(slots) {
  const next = emptyLayoutSlots();
  for (const key of layoutSlotKeys(slots)) next[key] = paneStateForLayoutSlot(key, slots);
  next[layoutTreeKey] = compactLayoutNode(slots[layoutTreeKey], next);
  const keys = layoutSlotKeys(next);
  if (keys.length && keys.every(key => paneIsPlaceholder(key, next))) return emptyPlaceholderLayoutSlots(keys[0] || 'left');
  return next[layoutTreeKey] ? next : emptyPlaceholderLayoutSlots();
}

function compactLayoutNode(node, slots) {
  return compactLayoutNodeInfo(node, slots)?.node || null;
}

function compactLayoutNodeInfo(node, slots) {
  if (!node) return null;
  if (node.slot) {
    if (!paneHasLayoutContent(node.slot, slots)) return null;
    const placeholderOnly = paneIsPlaceholder(node.slot, slots);
    const containsFileExplorer = paneTabs(node.slot, slots).includes(fileExplorerItemId);
    return {
      node: leafNode(node.slot),
      containsFileExplorer,
      directFileExplorerLeaf: containsFileExplorer,
      placeholderOnly,
    };
  }
  const direction = node.split === 'column' ? 'column' : 'row';
  const children = (node.children || []).map(child => compactLayoutNodeInfo(child, slots)).filter(Boolean);
  if (!children.length) return null;
  if (children.length === 1) return children[0];
  const hasFileExplorer = children.some(child => child.containsFileExplorer);
  const hasDirectFileExplorerLeaf = children.some(child => child.directFileExplorerLeaf);
  const kept = direction === 'row' && hasDirectFileExplorerLeaf
    ? children
    : children.filter(child => !child.placeholderOnly);
  const compacted = kept.length ? kept : [children[0]];
  if (compacted.length < 2) return compacted[0];
  const nextNode = splitNode(direction, compacted[0].node, compacted[1].node, node.pct);
  return {
    node: nextNode,
    containsFileExplorer: compacted.some(child => child.containsFileExplorer),
    directFileExplorerLeaf: false,
    placeholderOnly: compacted.every(child => child.placeholderOnly),
  };
}

function layoutNodeHasContent(node, slots = layoutSlots) {
  if (!node) return false;
  if (node.slot) return paneHasLayoutContent(node.slot, slots);
  return (node.children || []).some(child => layoutNodeHasContent(child, slots));
}

function layoutNodeContainsItem(node, item, slots = layoutSlots) {
  if (!node) return false;
  if (node.slot) return paneTabs(node.slot, slots).includes(item);
  return (node.children || []).some(child => layoutNodeContainsItem(child, item, slots));
}

function layoutHasHorizontalContentBeforeItem(node, item, slots = layoutSlots) {
  if (!node || node.slot) return false;
  const children = node.children || [];
  if (node.split === 'row') {
    let hasContentBefore = false;
    for (const child of children) {
      if (layoutNodeContainsItem(child, item, slots)) {
        return hasContentBefore || layoutHasHorizontalContentBeforeItem(child, item, slots);
      }
      if (layoutNodeHasContent(child, slots)) hasContentBefore = true;
    }
    return false;
  }
  return children.some(child => (
    layoutNodeContainsItem(child, item, slots)
    && layoutHasHorizontalContentBeforeItem(child, item, slots)
  ));
}

function fileExplorerNeedsLeftDock(slots = layoutSlots) {
  return layoutHasHorizontalContentBeforeItem(slots?.[layoutTreeKey], fileExplorerItemId, slots);
}

function normalizeFileExplorerDock(slots) {
  return fileExplorerNeedsLeftDock(slots) ? layoutWithFileExplorerDockedLeft(slots) : slots;
}

function layoutFromSessionList(values) {
  const seen = new Set();
  const items = [];
  for (const raw of values) {
    const item = resolveLayoutItem(raw);
    if (!isLayoutItem(item) || seen.has(item)) continue;
    items.push(item);
    seen.add(item);
  }
  return layoutSlotsForItems(items, configuredDefaultLayoutMode());
}

function layoutFromParam(raw, tabsRaw = '') {
  const text = String(raw || '').trim();
  if (!text) return null;
  if (text.toLowerCase() === 'empty') return emptyPlaceholderLayoutSlots();
  if (text.startsWith(layoutTreeParamPrefix)) return treeLayoutFromParam(text.slice(layoutTreeParamPrefix.length));
  if (compactLayoutParamLooksLikeTree(text)) return compactTreeLayoutFromParam(text, tabsRaw);
  const namedSlotLayout = namedSlotLayoutFromParam(text, tabsRaw);
  if (namedSlotLayout) return namedSlotLayout;
  const sides = text.split(',');
  if (!sides.some(value => value.trim())) return null;
  const next = emptyLayoutSlots();
  const seen = new Set();
  for (let index = 0; index < basePaneKeys.length; index += 1) {
    const side = basePaneKeys[index];
    for (const value of (sides[index] || '').split('+')) {
      if (!value.trim()) continue;
      const item = resolveLayoutItem(value.trim());
      if (isLayoutItem(item) && !seen.has(item)) {
        if (!next[side]) next[side] = emptyPaneState();
        next[side].tabs.push(item);
        if (!next[side].active) next[side].active = item;
        seen.add(item);
      }
    }
  }
  next[layoutTreeKey] = legacyLayoutTree(next);
  return layoutHasRestorableContent(next) ? next : null;
}

function namedSlotLayoutFromParam(raw, tabsRaw) {
  const tabStates = layoutTabStatesFromParam(tabsRaw);
  if (!tabStates.size) return null;
  const slotNames = String(raw || '')
    .split(',')
    .map(value => layoutSlotName(readableParamComponentDecode(value.trim())))
    .filter(Boolean);
  if (!slotNames.length) return null;
  const next = emptyLayoutSlots();
  const leaves = [];
  const seen = new Set();
  for (const slot of slotNames) {
    if (seen.has(slot)) continue;
    seen.add(slot);
    const state = tabStates.get(slot);
    if (!state || !paneHasLayoutContent(slot, {[slot]: state})) continue;
    next[slot] = state;
    leaves.push(leafNode(slot));
  }
  if (!leaves.length) return null;
  next[layoutTreeKey] = leaves.reduce((tree, leaf) => (tree ? splitNode('row', tree, leaf) : leaf), null);
  const normalized = normalizeLayoutSlots(next);
  return layoutHasRestorableContent(normalized) ? normalized : null;
}

function treeLayoutFromParam(raw) {
  try {
    const payload = JSON.parse(raw);
    if (!payload || typeof payload !== 'object') return null;
    const tree = layoutTreeFromParamNode(payload.tree);
    const slots = payload.slots && typeof payload.slots === 'object' ? payload.slots : {};
    const next = emptyLayoutSlots();
    next[layoutTreeKey] = tree;
    for (const slot of layoutLeafSlots(tree)) {
      const rawState = slots[slot];
      const tabs = Array.isArray(rawState?.tabs) ? rawState.tabs : Array.isArray(rawState) ? rawState : [];
      const active = resolveLayoutItem(rawState?.active);
      next[slot] = rawState?.placeholder === true && !tabs.length
        ? emptyPlaceholderPaneState()
        : paneStateWithTabs(tabs.map(resolveLayoutItem), active);
    }
    const normalized = normalizeLayoutSlots(next);
    return layoutHasRestorableContent(normalized) ? normalized : null;
  } catch (_) {
    return null;
  }
}

function compactLayoutParamLooksLikeTree(text) {
  return /^(row|col|column)(?:@\d+(?:\.\d+)?)?\(/.test(text);
}

function compactTreeLayoutFromParam(raw, tabsRaw) {
  const parser = {text: String(raw || ''), index: 0};
  const tree = parseCompactLayoutNode(parser);
  skipCompactLayoutWhitespace(parser);
  if (!tree || parser.index !== parser.text.length) return null;
  const tabStates = layoutTabStatesFromParam(tabsRaw);
  const next = emptyLayoutSlots();
  next[layoutTreeKey] = tree;
  for (const slot of layoutLeafSlots(tree)) {
    next[slot] = tabStates.get(slot) || emptyPlaceholderPaneState();
  }
  const normalized = normalizeLayoutSlots(next);
  return layoutHasRestorableContent(normalized) ? normalized : null;
}

function parseCompactLayoutNode(parser) {
  skipCompactLayoutWhitespace(parser);
  const name = readCompactLayoutToken(parser);
  if (!name) return null;
  const splitMatch = name.toLowerCase().match(/^(row|col|column)(?:@(\d+(?:\.\d+)?))?$/);
  skipCompactLayoutWhitespace(parser);
  if (splitMatch && parser.text[parser.index] === '(') {
    parser.index += 1;
    const children = [];
    while (parser.index < parser.text.length) {
      const child = parseCompactLayoutNode(parser);
      if (!child) return null;
      children.push(child);
      skipCompactLayoutWhitespace(parser);
      if (parser.text[parser.index] === ',') {
        parser.index += 1;
        continue;
      }
      if (parser.text[parser.index] === ')') {
        parser.index += 1;
        break;
      }
      return null;
    }
    if (children.length < 2) return children[0] || null;
    return splitNode(splitMatch[1] === 'row' ? 'row' : 'column', children[0], children[1], splitMatch[2]);
  }
  const slot = layoutSlotName(readableParamComponentDecode(name));
  return slot ? leafNode(slot) : null;
}

function readCompactLayoutToken(parser) {
  const start = parser.index;
  while (parser.index < parser.text.length && !/[(),\s]/.test(parser.text[parser.index])) parser.index += 1;
  return parser.text.slice(start, parser.index);
}

function skipCompactLayoutWhitespace(parser) {
  while (/\s/.test(parser.text[parser.index] || '')) parser.index += 1;
}

function layoutTreeFromParamNode(node) {
  if (!node || typeof node !== 'object') return null;
  const slot = layoutSlotName(node.slot);
  if (slot) return leafNode(slot);
  const children = (node.children || []).map(layoutTreeFromParamNode).filter(Boolean);
  if (children.length >= 2) return splitNode(node.split === 'column' ? 'column' : 'row', children[0], children[1], node.pct);
  return children[0] || null;
}

function layoutSlotName(value) {
  const slot = String(value || '').trim();
  return slot && slot !== layoutTreeKey ? slot : null;
}

function layoutParamValue(slots) {
  const tree = slots?.[layoutTreeKey];
  if (tree) return compactLayoutTreeParam(tree);
  const keys = layoutSlotKeys(slots);
  if (!keys.length) return 'empty';
  return keys.map(side => paneTabs(side, slots).map(readableItemParam).join('+')).join(',');
}

function compactLayoutTreeParam(node) {
  if (!node) return '';
  if (node.slot) return readableParamComponent(node.slot);
  const name = node.split === 'column' ? 'col' : 'row';
  return `${name}@${splitPercentForDisplay(node.pct)}(${(node.children || []).map(compactLayoutTreeParam).filter(Boolean).join(',')})`;
}

function layoutTabsParamValue(slots) {
  const slotValues = [];
  for (const slot of layoutSlotKeys(slots)) {
    if (paneIsPlaceholder(slot, slots)) {
      slotValues.push(`${readableParamComponent(slot)}:${emptyPaneParam}`);
      continue;
    }
    const active = activeItemForSide(slot, slots);
    const tabs = paneTabs(slot, slots).map((item, index) => {
      const marker = item === active && index > 0 ? '*' : '';
      return `${readableItemParam(item)}${marker}`;
    });
    if (tabs.length) slotValues.push(`${readableParamComponent(slot)}:${tabs.join(',')}`);
  }
  return slotValues.join(';');
}

function layoutTabStatesFromParam(raw) {
  const result = new Map();
  for (const part of String(raw || '').split(';')) {
    if (!part.trim()) continue;
    const separator = part.indexOf(':');
    if (separator <= 0) continue;
    const slot = layoutSlotName(readableParamComponentDecode(part.slice(0, separator)));
    if (!slot) continue;
    const tabs = [];
    let active = null;
    let placeholder = false;
    for (const rawItem of part.slice(separator + 1).split(',')) {
      let token = rawItem.trim();
      if (!token) continue;
      const activeToken = token.endsWith('*');
      if (activeToken) token = token.slice(0, -1);
      const decoded = readableParamComponentDecode(token);
      if (decoded === emptyPaneParam) {
        placeholder = true;
        continue;
      }
      const item = resolveLayoutItem(decoded);
      if (isLayoutItem(item) && !tabs.includes(item)) {
        tabs.push(item);
        if (activeToken) active = item;
      }
    }
    result.set(slot, placeholder && !tabs.length ? emptyPlaceholderPaneState() : paneStateWithTabs(tabs, active));
  }
  return result;
}

function readableItemParam(item) {
  return readableParamComponent(itemParam(item));
}

function readableParamComponent(value) {
  return encodeURIComponent(String(value)).replace(/[!'()*]/g, char => `%${char.charCodeAt(0).toString(16).toUpperCase()}`);
}

function readableParamComponentDecode(value) {
  try {
    return decodeURIComponent(String(value || ''));
  } catch (_) {
    return String(value || '');
  }
}

// a bookmarked ?…=yoagent / __yoagent__ (or legacy __yosup__) URL opens the merged pane on
// the YO!agent sub-tab. The aliases resolve to __info__ during normalization (losing the yoagent intent),
// so detect them in the raw params here and pre-select the sub-tab before the layout is built.
function maybeAdoptYoagentDeepLink(params) {
  const raw = [params.get('tabs') || '', params.get('sessions') || '', params.get('active') || ''].join(',');
  const referencesYoagent = raw
    .split(/[,:|]/)
    .map(value => value.trim())
    .some(value => tabTypeForParam(value)?.key === 'info' && value !== 'info' && value !== infoItemId);
  if (referencesYoagent) {
    infoPanelSubTab = 'yoagent';
    writeStoredInfoSubTab('yoagent');
  }
}

function initialLayoutSlots() {
  const params = new URLSearchParams(location.search);
  maybeAdoptYoagentDeepLink(params);
  const layoutFromUrl = layoutFromParam(params.get('layout') || '', params.get('tabs') || '');
  if (layoutFromUrl) return layoutWithDebugPaneActive(layoutFromUrl);
  const raw = params.get('sessions') || params.get('active') || '';
  const selected = [];
  for (const part of raw.split(',')) {
    const value = part.trim();
    if (!value) continue;
    const item = resolveLayoutItem(value);
    if (isLayoutItem(item) && !selected.includes(item)) selected.push(item);
  }
  if (selected.length) return layoutWithDebugPaneActive(layoutFromSessionList(selected));
  return layoutWithDebugPaneActive(defaultLayoutSlots());
}

function debugPanePreferredSlot(slots) {
  const keys = layoutSlotKeys(slots);
  return keys.find(slot => paneTabs(slot, slots).includes(infoItemId) || paneTabs(slot, slots).includes(prefsItemId))
    || keys.find(slot => {
      const active = activeItemForSide(slot, slots);
      return active && !isFileExplorerItem(active);
    })
    || keys[0]
    || 'left';
}

function layoutWithDebugPaneActive(slots) {
  if (!debugModeEnabled || !isLayoutItem(debugPaneItemId)) return slots;
  const next = cloneLayoutSlots(slots);
  const existingSlot = layoutSlotKeys(next).find(slot => paneTabs(slot, next).includes(debugPaneItemId));
  const slot = existingSlot || debugPanePreferredSlot(next);
  const tabs = paneTabs(slot, next).filter(item => item !== debugPaneItemId);
  next[slot] = paneStateWithTabs([...tabs, debugPaneItemId], debugPaneItemId);
  if (!next[layoutTreeKey]) next[layoutTreeKey] = leafNode(slot);
  return compactLayoutSlots(next);
}

function defaultLayoutSlots() {
  const sorted = visibleSessions.slice().sort((left, right) => String(left).localeCompare(String(right)));
  return layoutSlotsForItems(sorted, configuredDefaultLayoutMode());
}

function layoutWithItems(value, items, preferredSlot = null) {
  const next = normalizeLayoutSlots(value);
  const present = new Set(paneItems(next));
  const missing = items.filter(item => isLayoutItem(item) && !present.has(item));
  if (!missing.length) return next;
  let slot = preferredSlot && layoutSlotKeys(next).includes(preferredSlot) ? preferredSlot : firstEmptyPane(next) || layoutSlotKeys(next)[0];
  if (!slot) {
    slot = 'left';
    next[layoutTreeKey] = leafNode(slot);
    next[slot] = emptyPlaceholderPaneState();
  }
  if (!preferredSlot
    && activeItemForSide(slot, next) === fileExplorerItemId
    && paneTabs(slot, next).length === 1
    && missing.some(isTmuxSession)) {
    const sessionTabs = missing.filter(isTmuxSession);
    const otherTabs = missing.filter(item => !isTmuxSession(item));
    const newSlot = nextLayoutSlot(next);
    next[newSlot] = paneStateWithTabs(sessionTabs, sessionTabs[0] || null);
    next[slot] = paneStateWithTabs([...paneTabs(slot, next), ...otherTabs], activeItemForSide(slot, next));
    next[layoutTreeKey] = splitNode('row', leafNode(slot), leafNode(newSlot), fileExplorerSplitPercent);
    return compactLayoutSlots(next);
  }
  const tabs = [...paneTabs(slot, next), ...missing];
  const active = activeItemForSide(slot, next) || tabs.find(isTmuxSession) || tabs[0] || null;
  next[slot] = paneStateWithTabs(tabs, active);
  return compactLayoutSlots(next);
}

function paneTabs(side, slots = layoutSlots) {
  const state = slots?.[side];
  if (Array.isArray(state)) return state;
  return Array.isArray(state?.tabs) ? state.tabs : [];
}

function paneIsPlaceholder(side, slots = layoutSlots) {
  const state = slots?.[side];
  return Boolean(!Array.isArray(state) && state?.placeholder === true && !paneTabs(side, slots).length);
}

function paneHasLayoutContent(side, slots = layoutSlots) {
  return paneTabs(side, slots).length > 0 || paneIsPlaceholder(side, slots);
}

function layoutHasRestorableContent(slots = layoutSlots) {
  return paneItems(slots).length > 0 || layoutSlotKeys(slots).some(slot => paneIsPlaceholder(slot, slots));
}

function paneStateForLayoutSlot(side, slots = layoutSlots) {
  return paneIsPlaceholder(side, slots)
    ? emptyPlaceholderPaneState()
    : paneStateWithTabs(paneTabs(side, slots), activeItemForSide(side, slots));
}

function slotColumn(slot) {
  if (String(slot).startsWith('right')) return 'right';
  return 'left';
}

function verticalSplitSlot(column, position) {
  return `${column}${position === 'top' ? 'Top' : 'Bottom'}`;
}

function activeItemForSide(side, slots = layoutSlots) {
  if (paneIsPlaceholder(side, slots)) return null;
  const stack = paneTabs(side, slots);
  const state = slots?.[side];
  const active = !Array.isArray(state) ? state?.active : null;
  return stack.includes(active) ? active : stack[0] || null;
}

function normalizePinnedTabItems(items = pinnedTabItems) {
  const result = [];
  for (const raw of items || []) {
    const item = String(raw || '').trim();
    if (item && isPinnableTab(item) && !result.includes(item)) result.push(item);
  }
  return result;
}

function isPinnableTab(item) {
  return isLayoutItem(item) && !isFileExplorerItem(item);
}

function tabIsPinned(item) {
  return pinnedTabItems.includes(item) && isPinnableTab(item);
}

function orderPaneTabs(tabs) {
  const unique = [];
  for (const item of tabs) {
    if (isLayoutItem(item) && !unique.includes(item)) unique.push(item);
  }
  return [
    ...unique.filter(tabIsPinned),
    ...unique.filter(item => !tabIsPinned(item)),
  ];
}

function paneStateWithTabs(tabs, active = null) {
  const ordered = orderPaneTabs(tabs);
  return {tabs: ordered, active: ordered.includes(active) ? active : ordered[0] || null};
}

function pinnedTabIconHtml(item) {
  if (!tabIsPinned(item)) return '';
  const label = t('tab.pinned');
  return `<span class="pane-tab-pin-icon" title="${esc(label)}" aria-label="${esc(label)}"></span>`;
}

function setTabPinned(item, pinned) {
  const resolved = resolveLayoutItem(item);
  if (!isPinnableTab(resolved)) {
    statusEl.textContent = t('tab.pinUnavailable');
    return false;
  }
  const nextPinned = pinnedTabItems.filter(tab => tab !== resolved);
  if (pinned) nextPinned.push(resolved);
  pinnedTabItems = normalizePinnedTabItems(nextPinned);
  writeStoredPinnedTabs();
  const next = cloneLayoutSlots(layoutSlots);
  for (const slot of layoutSlotKeys(next)) {
    next[slot] = paneStateWithTabs(paneTabs(slot, next), activeItemForSide(slot, next));
  }
  applyLayoutSlots(next, {focusSession: resolved, prune: false, forceFull: dockviewLayoutActive()});
  statusEl.textContent = pinned ? t('tab.pinnedStatus', {name: itemLabel(resolved)}) : t('tab.unpinnedStatus', {name: itemLabel(resolved)});
  return true;
}

function toggleTabPinned(item) {
  const resolved = resolveLayoutItem(item);
  return setTabPinned(resolved, !tabIsPinned(resolved));
}

function toggleActiveTabPinned() {
  const item = currentActiveMenuItem();
  if (!item) return false;
  return toggleTabPinned(item);
}

function paneItems(slots = layoutSlots) {
  const result = [];
  for (const side of layoutSlotKeys(slots)) {
    for (const item of paneTabs(side, slots)) {
      if (!result.includes(item)) result.push(item);
    }
  }
  return result;
}

function activePaneItems(slots = layoutSlots) {
  const result = [];
  for (const side of layoutSlotKeys(slots)) {
    const item = activeItemForSide(side, slots);
    if (item && !result.includes(item)) result.push(item);
  }
  return result;
}

function itemInLayout(item, slots = layoutSlots) {
  return paneItems(slots).includes(item);
}

function itemIsActivePaneTab(item, slots = layoutSlots) {
  return activePaneItems(slots).includes(item);
}

function itemIsBackgroundPaneTab(item, slots = layoutSlots) {
  return itemInLayout(item, slots) && !itemIsActivePaneTab(item, slots);
}

function allTabItems() {
  return [...virtualTabItems(), ...openFileEditorItems(), ...visibleSessions];
}

function sortTabItems(items) {
  return items
    .slice()
    .sort((left, right) => itemSortNumber(left) - itemSortNumber(right) || itemLabel(left).localeCompare(itemLabel(right)));
}

function backgroundTabItems(slots = layoutSlots) {
  const activeItems = new Set(activePaneItems(slots));
  return sortTabItems(paneItems(slots).filter(item => !activeItems.has(item)));
}

function sessionsFromSlots(slots) {
  const result = [];
  for (const side of layoutSlotKeys(slots)) {
    const session = activeItemForSide(side, slots);
    if (session && !result.includes(session)) result.push(session);
  }
  return result;
}

function sessionsFromLayout() {
  return sessionsFromSlots(layoutSlots);
}

function isInfoItem(item) {
  return tabTypeForItem(item)?.key === 'info';
}

function isVirtualItem(item) {
  return Boolean(tabTypeForItem(item));
}

function openFileEditorItems() {
  const items = [];
  if (sharedImageViewerPath && openFiles.has(sharedImageViewerPath)) {
    items.push(imageViewerItemFor(sharedImageViewerPath));
  }
  for (const [path, state] of openFiles.entries()) {
    normalizeFileStateRecord(state);
    for (const item of state.editorTabItems) items.push(item);
  }
  return items;
}

function computeLayoutItems() {
  return [...virtualTabItems(), ...openFileEditorItems(), ...visibleSessions];
}

function isTmuxSession(item) {
  return sessions.includes(item);
}

function isLayoutItem(item) {
  return layoutItems.includes(item);
}

function registerFileEditorLayoutItem(path) {
  if (!path || !path.startsWith('/')) return null;
  const item = fileEditorItemFor(path);
  addFileEditorTabItem(path, item);
  if (openFiles.get(path)?.loading !== true && openFiles.get(path)?.kind) {
    syncFileLayoutItems();
    return item;
  }
  ensureFileState(path, {
      mtime: 0,
      kind: 'file',
      original: '',
      content: '',
      dirty: false,
      loading: true,
  });
  syncFileLayoutItems();
  return item;
}

function registerImageViewerLayoutItem(path) {
  if (!path || !path.startsWith('/')) return null;
  sharedImageViewerPath = path;
  if (!openFiles.get(path)?.kind) {
    ensureFileState(path, {
      mtime: 0,
      kind: 'image',
      original: '',
      content: '',
      dirty: false,
      loading: true,
    });
  }
  syncFileLayoutItems();
  return imageViewerItemFor(path);
}

function resolveLayoutItem(value) {
  const text = String(value || '');
  if (text === 'changes' || text === '__changes__') {
    fileExplorerMode = 'diff';
    writeStoredFileExplorerMode(fileExplorerMode);
    return fileExplorerItemId;
  }
  const type = tabTypeForParam(text);
  if (type?.prefix === imageViewerItemPrefix) return registerImageViewerLayoutItem(text.slice(imageViewerItemPrefix.length)) || text;
  if (type?.prefix === fileEditorItemPrefix) return registerFileEditorLayoutItem(text.slice(fileEditorItemPrefix.length)) || text;
  if (type?.id) return type.id;
  if (sessions.includes(text)) return text;
  const ordinal = Number(text);
  if (Number.isInteger(ordinal) && ordinal > 0) return sessionForLabel(String(ordinal));
  return text;
}

function itemLabel(item) {
  const type = tabTypeForItem(item);
  if (type?.label) return type.label(item);
  return sessionLabel(item);
}

function itemSortNumber(item) {
  const type = tabTypeForItem(item);
  if (type) return type.sortRank;
  const label = Number(sessionLabel(item));
  return Number.isFinite(label) ? label : Number.MAX_SAFE_INTEGER;
}

function itemParam(item) {
  const type = tabTypeForItem(item);
  if (type) return tabTypeParam(type, item);
  return String(item);
}

const stateDefs = {
  'needs-approval': {label: 'Needs approval', short: 'EXEC?', priority: 0, attention: true},
  'yolo-approval': {label: 'YOLO pending approval', short: 'YOLO?', priority: 0, attention: false},
  'needs-input': {label: 'Needs input', short: 'QUES?', priority: 1, attention: true},
  blocked: {label: 'Blocked', short: 'BLK', priority: 2, attention: true},
  disconnected: {label: 'Disconnected', short: 'OFF', priority: 3, attention: true},
  'tests-running': {label: 'Tests running', short: 'TEST', priority: 4, attention: false},
  'ready-review': {label: 'Ready for review', short: 'PR', priority: 5, attention: false},
  working: {label: 'Working', short: 'RUN', priority: 6, attention: false},
  idle: {label: 'Idle', short: 'IDLE', priority: 7, attention: false},
  done: {label: 'Done', short: 'DONE', priority: 8, attention: false},
};

function stateReason(key, params = {}) {
  return t(`state.reason.${key}`, params);
}

function stateDef(key) {
  // #121: resolve the human label through t() on each access so a runtime language switch
  // re-localizes it (stateDefs is frozen at load). Compact badge text is localized too.
  const resolvedKey = stateDefs[key] ? key : 'idle';
  return {...stateDefs[resolvedKey], label: t(`state.${resolvedKey}`), short: t(`state.short.${resolvedKey}`)};
}

function terminalDisconnected(session) {
  if (!activeSessions.includes(session)) return false;
  const item = terminals.get(session);
  if (!item) return false;
  return item.socket?.readyState === WebSocket.CLOSED || item.socket?.readyState === WebSocket.CLOSING;
}

function sessionState(session, info = transcriptMeta.sessions?.[session]) {
  if (!isTmuxSession(session)) return {key: 'idle', ...stateDef('idle'), reason: t('state.notTmux')};
  const auto = autoApproveStates.get(session) || {};
  const autoEnabled = autoApproveEnabledForSession(auto);
  const approvalPrompt = auto.prompt || {};
  const screen = auto.screen || {};
  const lastAction = String(auto.last_action || '').toLowerCase();
  const approvalPromptVisible = approvalPrompt.visible === true;
  const approvalYesSelected = approvalPrompt.yes_selected === true;
  const approvalPromptText = String(approvalPrompt.text || stateReason('approvalPromptVisible'));
  const screenKey = String(screen.key || '');
  const screenText = String(screen.text || '');
  const agents = Array.isArray(info?.agents) ? info.agents : [];
  const panes = Array.isArray(info?.panes) ? info.panes : [];
  const agentText = agents
    .map(agent => `${agent.kind || ''} ${agent.status || ''} ${agent.error || ''}`)
    .join(' ')
    .toLowerCase();
  const paneText = panes
    .map(pane => `${pane.command || ''} ${pane.title || ''}`)
    .join(' ')
    .toLowerCase();
  const pr = info?.project?.pull_request;
  const prStatus = pullRequestStatusLabel(pr).toLowerCase();
  const checksState = String(pr?.checks?.state || '').toLowerCase();

  if (terminalDisconnected(session) || (!info && terminals.has(session))) {
    return stateValue('disconnected', stateReason('terminalConnectionClosed'));
  }
  if (screenKey === 'disconnected') {
    const disconnectedReason = screenText && screenText !== 'failed to capture pane'
      ? screenText
      : stateReason('terminalScreenUnavailable');
    return stateValue('disconnected', disconnectedReason);
  }
  if (/blocked|denied|rejected/.test(lastAction)) {
    return stateValue('blocked', stateReason('yoloBlockedApproval'));
  }
  if (approvalPromptVisible && approvalYesSelected && autoEnabled) {
    return stateValue('yolo-approval', stateReason('yoloWillPressEnter'));
  }
  if (approvalPromptVisible && approvalYesSelected) {
    return stateValue('needs-approval', approvalPromptText || stateReason('approvalPromptVisible'));
  }
  if (approvalPromptVisible) {
    return stateValue('needs-input', stateReason('approvalYesNotSelected'));
  }
  if (!autoEnabled && /permission|approval|approve|confirm/.test(agentText)) {
    return stateValue('needs-approval', approvalPromptText || stateReason('approvalPromptVisible'));
  }
  if (screenKey === 'approval') {
    return stateValue('needs-approval', screenText || approvalPromptText || stateReason('approvalPromptVisible'));
  }
  if (screenKey === 'working') {
    return stateValue('working', screenText || stateReason('agentWorking'));
  }
  if (screenKey === 'needs-input') {
    return stateValue('needs-input', screenText || stateReason('agentWaitingInput'));
  }
  if (screenKey === 'error') {
    return stateValue('blocked', screenText || stateReason('agentScreenFailed'));
  }
  if (/needs input|waiting for input|awaiting input|user input|input required|waiting for user|paused/.test(agentText)) {
    return stateValue('needs-input', stateReason('agentWaitingInput'));
  }
  if (agents.some(agent => agentErrorIsBlocking(agent.error)) || /blocked|error|failed|failure|stuck/.test(agentText)) {
    return stateValue('blocked', stateReason('agentErrorBlocker'));
  }
  if (/pytest|cargo test|npm test|pnpm test|yarn test|vitest|jest|ctest|go test|python3 -m pytest|python -m pytest|ruff|mypy|pre-commit/.test(paneText)) {
    return stateValue('tests-running', stateReason('testsActive'));
  }
  if (pr?.number && !pr.draft && prStatus !== 'closed' && prStatus !== 'merged' && (prStatus.includes('passing') || checksState === 'success')) {
    return stateValue('ready-review', stateReason('prChecksPassing'));
  }
  if (/done|completed|complete|finished|success/.test(agentText)) {
    return stateValue('done', stateReason('agentComplete'));
  }
  if (agents.length || panes.some(pane => pane.active) || terminals.get(session)?.socket?.readyState === WebSocket.OPEN) {
    return stateValue('working', stateReason('agentActivePaneDetected'));
  }
  return stateValue('idle', stateReason('noActiveAgent'));
}

function agentErrorIsBlocking(error) {
  const text = String(error || '').toLowerCase();
  if (!text) return false;
  return !(/transcript not found/.test(text) || /^missing /.test(text));
}

function stateValue(key, reason, extra = {}) {
  const def = stateDef(key);
  return {key, ...def, reason, ...extra};
}

function autoApproveEnabledHere(payload) {
  return payload?.enabled === true;
}

function autoApproveEnabledElsewhere(payload) {
  return payload?.enabled_elsewhere === true || (payload?.locked === true && payload?.enabled !== true);
}

function autoApproveEnabledForSession(payload) {
  return autoApproveEnabledHere(payload) || autoApproveEnabledElsewhere(payload);
}

function yoloEnabledSessions() {
  return sessions.filter(session => autoApproveEnabledHere(autoApproveStates.get(session)));
}

function autoApproveScreenIsWorking(payload) {
  return String(payload?.screen?.key || '') === 'working';
}

function sessionYoloIsWorking(session, payload = autoApproveStates.get(session)) {
  // Spin the YO ball whenever the agent is working, regardless of auto-approve state.
  return autoApproveScreenIsWorking(payload);
}

function runningAgentCount() {
  return sessions.filter(session => autoApproveScreenIsWorking(autoApproveStates.get(session))).length;
}

function documentTitleNowMs() {
  const testNow = Number(window.__yolomuxDocumentTitleNowMs);
  return Number.isFinite(testNow) ? testNow : Date.now();
}

function documentTitleIdleMinutes(now) {
  if (documentTitleIdleSinceMs === null) return 0;
  const elapsedMs = Math.max(0, now - documentTitleIdleSinceMs);
  return elapsedMs >= documentTitleIdleThresholdMs ? Math.max(2, Math.floor(elapsedMs / 60000)) : 0;
}

function updateDocumentTitle() {
  const count = runningAgentCount();
  if (count > 0) {
    documentTitleIdleSinceMs = null;
    document.title = `YOLOmux [${count} running]`;
    return;
  }
  const now = documentTitleNowMs();
  if (documentTitleIdleSinceMs === null) documentTitleIdleSinceMs = now;
  const idleMinutes = documentTitleIdleMinutes(now);
  document.title = idleMinutes ? `YOLOmux (idle for ${idleMinutes} min)` : 'YOLOmux [idle]';
}

// Cross-session "what's going on" rollup for the always-visible top-bar status line: how many tmux
// agents are running, how many need the user, how many are idle. Reads the same live per-session
// state the tabs use (stateful, no recompute).
function globalActivityCounts() {
  let running = 0;
  let attention = 0;
  let total = 0;
  for (const session of sessions) {
    if (!isTmuxSession(session)) continue;
    total += 1;
    const key = sessionState(session).key;
    if (['working', 'tests-running', 'yolo-approval'].includes(key)) running += 1;
    else if (['needs-input', 'needs-approval', 'blocked', 'disconnected'].includes(key)) attention += 1;
  }
  return {running, attention, idle: Math.max(0, total - running - attention), total};
}

function globalActivityStatusLineHtml() {
  const counts = globalActivityCounts();
  if (!counts.total) return '';
  const parts = [];
  if (counts.running) parts.push(`<span class="topbar-activity-run">${counts.running} running</span>`);
  if (counts.attention) parts.push(`<span class="topbar-activity-attn">${counts.attention} need you</span>`);
  parts.push(`<span class="topbar-activity-idle">${counts.idle} idle</span>`);
  return parts.join('<span class="topbar-activity-sep" aria-hidden="true">·</span>');
}

function createTopbarActivityStatus() {
  const button = document.createElement('button');
  button.type = 'button';
  button.id = 'topbarActivity';
  button.className = 'topbar-activity';
  button.title = 'Open the cross-session AI activity summary';
  button.setAttribute('aria-label', 'AI activity summary across all sessions');
  button.onclick = () => openInfoSubTab('yoagent');
  return button;
}

function updateTopbarActivityStatus() {
  const node = document.getElementById('topbarActivity');
  if (!node) return;
  const counts = globalActivityCounts();
  const html = globalActivityStatusLineHtml();
  node.innerHTML = html;
  node.hidden = !html;
  node.classList.toggle('has-attention', counts.attention > 0);
}

function yoloRotationDelay(now = Date.now()) {
  const duration = Math.max(0, Number(yoloRotateMs) || 0);
  if (duration <= 0) return '0s';
  return `${-((now % duration) / 1000).toFixed(3)}s`;
}

function attentionAnimationDelay(now = Date.now()) {
  return `${-((now % redReminderMs) / 1000).toFixed(3)}s`;
}

function attentionAnimationStyle() {
  return `--attention-animation-delay: ${attentionAnimationDelay()}`;
}

function syncAttentionAnimation(node, active) {
  if (!node?.style) return;
  if (active) {
    if (!node.style.getPropertyValue('--attention-animation-delay')) {
      node.style.setProperty('--attention-animation-delay', attentionAnimationDelay());
    }
  } else {
    node.style.removeProperty('--attention-animation-delay');
  }
}

function stateBadgeHtml(key, short, title) {
  const classes = ['session-state-badge', 'tab-symbol', `session-state-${key}`];
  const attention = stateDef(key).attention;
  if (attention) classes.push('session-state-reminder');
  const style = attention ? ` style="${attentionAnimationStyle()}"` : '';
  return `<span class="${esc(classes.join(' '))}"${style} title="${esc(title)}">${esc(short)}</span>`;
}

function sessionStateHtml(state) {
  // 'ready-review' is dropped — the dedicated #NNNN / CI / Approved PR chips already convey
  // "PR ready", so the standalone "PR" state pill is redundant on the tab.
  if (!state || ['working', 'tests-running', 'done', 'disconnected', 'yolo-approval', 'ready-review'].includes(state.key)) return '';
  return stateBadgeHtml(state.key, state.short || stateDef(state.key).short, `${state.label}: ${state.reason}`);
}

function inactiveTabItems() {
  const inPane = new Set(paneItems());
  return sortTabItems(allTabItems().filter(item => !inPane.has(item)));
}

function renderNotifyToggle() {
  if (!notifyToggle) return;
  const supported = 'Notification' in window;
  notifyToggle.disabled = readOnlyMode;
  syncPressedButton(notifyToggle, notificationsEnabled, {
    labelOn: 'Notify',
    labelOff: 'Notify',
  });
  const browserState = supported ? Notification.permission : 'unsupported';
  notifyToggle.title = readOnlyMode
    ? 'Notify is admin-only'
    : `notify when a session needs attention; browser notifications: ${browserState}`;
}

async function toggleNotifications() {
  if (readOnlyMode) {
    statusErr('readonly access cannot change Notify');
    return;
  }
  const nextEnabled = !notificationsEnabled;
  let browserPermission = 'unsupported';
  if (nextEnabled && 'Notification' in window && Notification.permission === 'default') {
    const permission = await Notification.requestPermission();
    browserPermission = permission;
  } else if ('Notification' in window) {
    browserPermission = Notification.permission;
  }
  try {
    const response = await apiFetch(`/api/notify?enabled=${nextEnabled ? '1' : '0'}`, {method: 'POST'});
    const payload = await response.json();
    if (!response.ok) throw new Error(payload.error || response.statusText || `HTTP ${response.status}`);
    notificationsEnabled = payload.enabled === true;
  } catch (error) {
    statusErr(`Notify request failed: ${esc(error)}`);
    return;
  }
  renderNotifyToggle();
  renderSessionButtons();
  if (notificationsEnabled) {
    if (browserPermission !== 'granted') {
      statusOk(`in-page alerts on; browser notifications ${esc(browserPermission)}`);
    }
    sendTestNotification();
    notifyCurrentAttentionStates();
  } else {
    statusOk(`${esc(t('status.notifyOff'))}`);
  }
}

async function loadNotifyStatus() {
  try {
    const response = await apiFetch('/api/notify', {cache: 'no-store'});
    const payload = await response.json();
    notificationsEnabled = response.ok && payload.enabled === true;
  } catch (_) {
    notificationsEnabled = false;
  }
  renderNotifyToggle();
}

function logOut() {
  window.location.href = '/logout';
}

function appMenuUiIcon(kind, active = false) {
  return `<span class="app-menu-ui-icon app-menu-ui-icon-${esc(kind)} ${active ? 'active' : ''}" aria-hidden="true"></span>`;
}

function tabTypeIconHtml(item, options = {}) {
  if (options.menu !== true) return '';
  const type = tabTypeForItem(item);
  const icon = typeof type?.icon === 'function' ? type.icon(item) : type?.icon;
  return icon ? appMenuUiIcon(icon) : '';
}

function projectReadmePath() {
  const root = String(repoRoot || '').replace(/\/+$/, '');
  return root ? `${root}/README.md` : '';
}

async function openProjectReadme() {
  const path = projectReadmePath();
  if (!path) {
    statusErr('README path is unavailable');
    return;
  }
  // open the README as rendered markdown by default (the user can switch to edit via the
  // mode control); README.md is markdown so editorPreviewModeAvailable is true.
  await openFileInEditor(path, 'README.md', {viewMode: 'preview'});
}

function keyboardShortcutCatalog() {
  return [
    {section: t('shortcuts.section.app'), items: [
      {label: t('shortcuts.commandPalette'), keys: appShortcutText('P', {shift: true})},
      {label: t('shortcuts.fileQuickOpen'), keys: appShortcutText('P')},
      {label: t('shortcuts.toggleFinder', {name: fileExplorerLabel()}), keys: appShortcutText('B')},
      {label: t('shortcuts.openPreferences'), keys: appShortcutText(',')},
      {label: t('shortcuts.keyboardShortcuts'), keys: '?'},
    ]},
    {section: t('shortcuts.section.terminal'), items: [
      {label: t('shortcuts.copyTmuxSelection'), keys: appShortcutText('C', {alt: true})},
    ]},
    {section: t('shortcuts.section.editor'), items: [
      {label: t('shortcuts.saveEditor'), keys: appShortcutText('S')},
      {label: t('shortcuts.find'), keys: appShortcutText('F')},
      {label: t('shortcuts.replace'), keys: appShortcutText('H')},
      {label: t('shortcuts.goToLine'), keys: appShortcutText('G')},
      {label: t('shortcuts.toggleComment'), keys: appShortcutText('/')},
      {label: t('shortcuts.indentOutdent'), keys: 'Tab / Shift+Tab'},
      {label: t('shortcuts.undoRedo'), keys: `${appShortcutText('Z')} / ${appShortcutText('Z', {shift: true})}`},
      {label: t('shortcuts.editorNav'), keys: `${appShortcutText('[', {alt: true})} / ${appShortcutText(']', {alt: true})}`},
    ]},
    {section: t('shortcuts.section.diff'), items: [
      {label: t('shortcuts.undoChunk'), keys: appShortcutText('Z')},
      {label: t('shortcuts.redoChunk'), keys: appShortcutText('Z', {shift: true})},
    ]},
    {section: t('shortcuts.section.tabsPanes'), items: [
      {label: t('shortcuts.pinTab'), keys: t('shortcuts.keys.pinTab', {k: appShortcutText('K')})},
      {label: t('shortcuts.closeTab'), keys: t('shortcuts.keys.closeTab', {w: appShortcutText('W'), bs: appShortcutText('Backspace')})},
      {label: t('shortcuts.moveTab'), keys: t('shortcuts.keys.dragTab')},
      {label: t('shortcuts.sessionActions'), keys: t('shortcuts.keys.rightClick')},
      {label: t('shortcuts.closeMenu'), keys: 'Esc'},
    ]},
  ];
}

function keyboardShortcutsHtml() {
  return keyboardShortcutCatalog().map(section => `
    <section class="keyboard-shortcuts-section">
      <h3>${esc(section.section)}</h3>
      <div class="keyboard-shortcuts-list">
        ${section.items.map(item => `
          <div class="keyboard-shortcut-row">
            <span>${esc(item.label)}</span>
            <kbd>${esc(item.keys)}</kbd>
          </div>`).join('')}
      </div>
    </section>`).join('');
}

function ensureKeyboardShortcutsOverlay() {
  if (keyboardShortcutsNode) return keyboardShortcutsNode;
  const node = document.createElement('div');
  node.className = 'keyboard-shortcuts-overlay';
  node.hidden = true;
  node.innerHTML = `
    <div class="keyboard-shortcuts-dialog" role="dialog" aria-modal="true" aria-label="${esc(t('shortcuts.title'))}">
      <div class="keyboard-shortcuts-head">
        <h2>${esc(t('shortcuts.title'))}</h2>
        <button type="button" class="keyboard-shortcuts-close" aria-label="${esc(t('shortcuts.close'))}">×</button>
      </div>
      <div class="keyboard-shortcuts-body"></div>
    </div>`;
  node.addEventListener('mousedown', event => {
    if (event.target === node) closeKeyboardShortcutsOverlay();
  });
  node.querySelector('.keyboard-shortcuts-close')?.addEventListener('click', closeKeyboardShortcutsOverlay);
  document.body.appendChild(node);
  keyboardShortcutsNode = node;
  return node;
}

function openKeyboardShortcutsOverlay() {
  const node = ensureKeyboardShortcutsOverlay();
  closeAppMenus();
  closeCommandPalette();
  const body = node.querySelector('.keyboard-shortcuts-body');
  if (body) body.innerHTML = keyboardShortcutsHtml();
  node.hidden = false;
  node.classList.add('open');
  node.querySelector('.keyboard-shortcuts-close')?.focus?.({preventScroll: true});
}

function closeKeyboardShortcutsOverlay() {
  if (!keyboardShortcutsNode) return;
  keyboardShortcutsNode.hidden = true;
  keyboardShortcutsNode.classList.remove('open');
}

function commandPaletteAllTabItems() {
  return Array.from(new Set([...activePaneItems(), ...backgroundTabItems(), ...inactiveTabItems()]));
}

function flattenMenuCommands(items, prefix = []) {
  const result = [];
  for (const item of items || []) {
    if (item.type === 'submenu') {
      result.push(...flattenMenuCommands(item.items, [...prefix, item.label]));
    } else if (item.type === 'command' && item.action && !item.disabled) {
      result.push({
        group: t('palette.group.menu'),
        label: [...prefix, item.label].join(' / '),
        detail: item.detail || '',
        key: `menu:${[...prefix, item.label].join('/')}`,
        targetItem: item.targetItem || '',
        keybinding: commandPaletteKeybinding([...prefix, item.label].join(' / '), item.detail || ''),
        run: item.action,
      });
    }
  }
  return result;
}

function commandPaletteKeybinding(label, detail = '') {
  const text = `${label} ${detail}`;
  if (/command palette/i.test(text)) return appShortcutText('P', {shift: true});
  if (/open file/i.test(text)) return appShortcutText('P');
  if (/toggle .*file explorer|toggle .*finder/i.test(text)) return appShortcutText('B');
  if (/preferences/i.test(text)) return appShortcutText(',');
  if (/keyboard shortcuts/i.test(text)) return '?';
  if (/close menu|dialog/i.test(text)) return 'Esc';
  return /\b(?:Ctrl|Cmd|Shift|Esc|Alt)[^,;]*/.exec(detail)?.[0] || '';
}

// a short localized label for an editor/preview view mode, shown as a chip on a deduped row.
function commandPaletteViewModeLabel(mode) {
  if (mode === 'preview') return t('editor.mode.preview');
  if (mode === 'split') return t('editor.mode.split');
  if (mode === 'diff') return t('editor.diff');
  return t('editor.mode.edit');
}

function commandPaletteNumericTime(value) {
  const number = Number(value || 0);
  if (!Number.isFinite(number) || number <= 0) return 0;
  if (number > 1e15) return number / 1e9;
  if (number > 1e11) return number / 1000;
  return number;
}

function commandPalettePaneMtime(item) {
  if (!isTmuxSession(item)) return 0;
  const info = sessionTranscriptInfo(item).info || {};
  return commandPaletteNumericTime(
    info.last_activity_ts || info.transcript_mtime || info.updated_ts || info.rolling_updated_ts || info.mtime || 0
  );
}

function commandPaletteCommandItems() {
  // Group FILE items by path and emit ONE row per file; non-file tabs (sessions, Finder/Info/Prefs)
  // stay one row each.
  const tabRow = (item, extra = {}) => ({
    group: t('palette.group.tabs'),
    category: 'pane',
    label: itemLabel(item),
    detail: menuTabDetail(item),
    key: `tab:${item}`,
    targetItem: item,
    mtime: commandPalettePaneMtime(item),
    searchFields: tabSearchFields(item),
    keybinding: 'Enter',
    run: () => selectSession(item, {userInitiated: true}),
    ...extra,
  });
  const fileGroups = new Map();   // path -> [items], in discovery order
  const tabItems = [];
  for (const item of commandPaletteAllTabItems()) {
    const path = fileItemPath(item);
    if (!path) { tabItems.push(tabRow(item)); continue; }
    if (!fileGroups.has(path)) fileGroups.set(path, []);
    fileGroups.get(path).push(item);
  }
  for (const [path, items] of fileGroups) {
    if (items.length === 1) { tabItems.push(tabRow(items[0])); continue; }
    const editorItem = items[0];
    // Each chip is clickable to jump to that exact view — carry the mode + the layout item.
    const viewModes = [];
    const seenModes = new Set();
    for (const it of items) {
      const mode = editorViewModeFor(path, it);
      if (seenModes.has(mode)) continue;
      seenModes.add(mode);
      viewModes.push({mode, label: commandPaletteViewModeLabel(mode), item: String(it)});
    }
    tabItems.push(tabRow(editorItem, {key: `file:${path}`, viewModes}));
  }
  const tabItemIds = new Set(commandPaletteAllTabItems());
  const menuItems = appMenuTree()
    .flatMap(menu => flattenMenuCommands(menu.items, [menu.label]))
    .filter(item => !(item.targetItem && isVirtualItem(item.targetItem) && tabItemIds.has(item.targetItem)))
    .map(item => ({...item, category: 'command'}));
  const settingItems = preferenceSections().flatMap(section => section.items.map(item => ({
    group: t('palette.group.settings'),
    category: 'setting',
    label: `${section.title} / ${item.label}`,
    detail: item.help || item.path,
    key: `setting:${item.path}`,
    keybinding: 'Enter',
    run: () => {
      preferencesSearchText = item.label;
      collapsedPreferenceSections.delete(section.title);
      writeStoredCollapsedPreferenceSections();
      selectSession(prefsItemId);
      requestAnimationFrame(() => {
        renderPreferencesPanels({force: true});
        const control = document.querySelector(`[data-setting-path="${cssEscape(item.path)}"]`);
        control?.focus?.({preventScroll: false});
        control?.scrollIntoView?.({block: 'center', inline: 'nearest'});
      });
    },
  })));
  return [...tabItems, ...menuItems, ...settingItems];
}

function fileQuickOpenRootForFile(path) {
  const normalized = normalizeDirectoryPath(path || '');
  if (!normalized || normalized === '/') return '';
  const rawGitRoot = openFiles.get(normalized)?.gitRoot || '';
  const gitRoot = rawGitRoot ? normalizeDirectoryPath(rawGitRoot) : '';
  if (gitRoot && pathIsInsideDirectory(normalized, gitRoot)) return gitRoot;
  return dirnameOf(normalized);
}

function fileQuickOpenPathAliasSegment(query) {
  const text = String(query || '').trim();
  if (!text || text.startsWith('/') || text.startsWith('~')) return '';
  const slash = text.indexOf('/');
  return slash > 0 ? text.slice(0, slash) : '';
}

function fileQuickOpenRootMatchesPathAlias(root, query) {
  const alias = fuzzyCanonicalPrefixText(fileQuickOpenPathAliasSegment(query));
  if (alias.length < 2) return false;
  return fuzzyCanonicalPrefixText(basenameOf(root)).startsWith(alias);
}

function fileQuickOpenExtraRootsForSearchQuery(query) {
  return compactNestedPaths([repoRoot, fileQuickOpenRootForFile(activeFile)]
    .map(normalizeDirectoryPath)
    .filter(root => root && root !== '/' && fileQuickOpenRootMatchesPathAlias(root, query)));
}

function fileQuickOpenRootForSearch() {
  const activeItem = currentActiveMenuItem();
  const activePath = isFileEditorItem(activeItem) ? fileItemPath(activeItem) : '';
  const activeFileRoot = fileQuickOpenRootForFile(activePath);
  if (activeFileRoot) return activeFileRoot;
  const target = currentSessionActionTarget();
  const gitRoot = isTmuxSession(target) ? sessionTranscriptInfo(target).gitRoot : '';
  if (gitRoot) return normalizeDirectoryPath(gitRoot);
  const activeTmux = activeTmuxDirectoryPath(target);
  if (activeTmux) return activeTmux;
  const fallbackFileRoot = fileQuickOpenRootForFile(activeFile);
  if (fallbackFileRoot) return fallbackFileRoot;
  if (fileExplorerRoot) return fileExplorerRoot;
  return repoRoot || homePath || '/';
}

function fileQuickOpenRootsForSearch(root = fileQuickOpenRoot || fileQuickOpenRootForSearch(), query = commandPaletteSearchQuery()) {
  return fileExplorerIndexedSearchRoots(root, fileQuickOpenExtraRootsForSearchQuery(query));
}

function fileQuickOpenScopeLabel(root = fileQuickOpenRoot || fileQuickOpenRootForSearch()) {
  const roots = fileQuickOpenRootsForSearch(root);
  if (roots.length <= 1) return compactHomePath(roots[0] || root || '/');
  return `${compactHomePath(roots[0])} + ${roots.length - 1} indexed`;
}

function fileQuickOpenQueryParts(query = commandPaletteQuery) {
  const raw = String(query || '').trim();
  const match = raw.match(/^(.*?)(?::(\d+))?$/);
  return {
    query: (match?.[1] || '').trim(),
    line: match?.[2] ? Math.max(1, Number(match[2])) : null,
    commandMode: raw.startsWith('>'),
    symbolMode: raw.startsWith('@'),
  };
}

function fileQuickOpenSearchText(query = commandPaletteQuery) {
  return fileQuickOpenQueryParts(query).query.replace(/[:.]+$/g, '').trim();
}

function fileQuickOpenPathQuery(query = commandPaletteQuery) {
  const text = fileQuickOpenQueryParts(query).query;
  if (!text.startsWith('/') && !text.startsWith('~')) return {active: false, directory: '', filter: ''};
  if (text === '~') return {active: true, directory: '~', filter: ''};
  if (text.endsWith('/')) return {active: true, directory: text || '/', filter: ''};
  const slash = text.lastIndexOf('/');
  if (text.startsWith('~/') && slash <= 1) return {active: true, directory: '~', filter: text.slice(2)};
  if (slash <= 0) return {active: true, directory: '/', filter: text.slice(1)};
  return {active: true, directory: text.slice(0, slash) || '/', filter: text.slice(slash + 1)};
}

function joinDirectoryPath(directory, name) {
  if (!directory || directory === '/') return `/${name}`;
  if (directory === '~') return `~/${name}`;
  return `${directory.replace(/\/+$/, '')}/${name}`;
}

function descendFileQuickOpenDirectory(path) {
  const directory = normalizeDirectoryPath(path);
  commandPaletteQuery = `${directory}${directory.endsWith('/') ? '' : '/'}`;
  commandPaletteIndex = 0;
  const input = commandPaletteNode?.querySelector?.('.command-palette-input');
  if (input) input.value = commandPaletteQuery;
  renderCommandPaletteResults();
  refreshFileQuickOpenCandidates(commandPaletteQuery);
}

function revealOpenFileLineSoon(path, line) {
  if (!line) return;
  requestAnimationFrame(() => {
    for (const panel of fileEditorPanelsForPath(path)) {
      if (scrollFileEditorPanelToSourceLine(panel, 'editor', line)) break;
    }
  });
}

function fileQuickOpenTargetSlot() {
  return focusedActivationSlot();
}

async function openFileQuickOpenPath(path, options = {}) {
  const label = basenameOf(path);
  let openedItem = null;
  if (options.split === true) {
    const targetSlot = largestPaneSlotForFileEditor();
    const splitBaseSlot = targetSlot || slotForSession(currentActiveMenuItem()) || largestPaneSlot();
    openedItem = await openFileInEditor(path, {name: label}, splitBaseSlot
      ? {targetSlot: splitBaseSlot, targetZone: targetSlot ? 'middle' : 'right', forceNewTab: true, userInitiated: true}
      : {forceNewTab: true, userInitiated: true});
  } else {
    const targetSlot = fileQuickOpenTargetSlot();
    openedItem = await openFileInEditor(path, {name: label}, targetSlot
      ? {targetSlot, userInitiated: true}
      : {userInitiated: true});
  }
  focusQuickOpenedFile(openedItem);
  revealOpenFileLineSoon(path, options.line || null);
}

function focusQuickOpenedFile(item) {
  if (!item) return;
  focusPanel(item, {userInitiated: true});
  renderPaneTabStrips();
  requestAnimationFrame(() => focusPanel(item, {userInitiated: true}));
}

function cursorStyleFileReference(path, options = {}) {
  const fullPath = String(path || '');
  if (!fullPath || options.kind === 'dir') return null;
  if (IMAGE_EXTENSIONS.has(fileExtensionOf(fullPath))) {
    const index = Math.max(1, Math.floor(Number(options.imageIndex || 1)));
    return {label: `[Image #${index}]`, detail: `'${fullPath}'`};
  }
  return null;
}

function fileQuickOpenItem(path, options = {}) {
  const label = basenameOf(path);
  const isDir = options.kind === 'dir';
  const cursorReference = cursorStyleFileReference(path, options);
  const detail = cursorReference?.detail || compactHomePath(path);
  return {
    group: options.group || 'Files',
    category: 'file',
    label: cursorReference?.label || (isDir ? `${label}/` : label),
    detail,
    key: `file:${path}`,
    path,
    mtime: commandPaletteNumericTime(options.mtime || options.mtimeNs || 0),
    iconText: isDir ? '▸' : fileIconFor(label),
    keybinding: isDir ? 'Enter' : `${appShortcutText('Enter')} split`,
    searchFields: [label, path, detail, options.relativePath || '', cursorReference?.label || ''],
    sortBonus: Number(options.sortBonus || 0),
    run: () => isDir ? descendFileQuickOpenDirectory(path) : openFileQuickOpenPath(path, {line: fileQuickOpenQueryParts().line}),
    splitRun: isDir ? null : () => openFileQuickOpenPath(path, {line: fileQuickOpenQueryParts().line, split: true}),
  };
}

function recentFileQuickOpenItems() {
  return Array.from(openFiles.keys()).reverse().map((path, index) => fileQuickOpenItem(path, {
    group: t('palette.group.recent'),
    mtime: openFiles.get(path)?.mtime || 0,
    sortBonus: 120 - index,
  }));
}

// C15 follow-up: while a directory PATH is typed in cmd-P, offer "Open <dir> in Finder" as the pinned
// top row, so Enter (the default highlight) opens that directory in the Finder/File Explorer — while
// arrowing down to a listed entry opens a file or descends into a subfolder. The target is the directory
// the input points at: the listed dir, or its `filter` subfolder when the typed name is an exact subdir.
function fileQuickOpenOpenFolderItem() {
  const pathQuery = fileQuickOpenPathQuery();
  if (!pathQuery.active) return null;
  let target = fileQuickOpenRoot || normalizeDirectoryPath(pathQuery.directory);
  if (pathQuery.filter) {
    const filter = String(pathQuery.filter).toLowerCase();
    const match = fileQuickOpenCandidates.find(entry => entry.kind === 'dir' && String(entry.name || '').toLowerCase() === filter);
    if (match?.path) target = match.path;
  }
  if (!target) return null;
  return {
    group: t('palette.group.files'),
    label: t('palette.openFolder', {name: fileExplorerLabel()}),
    detail: compactHomePath(target),
    key: `open-folder:${target}`,
    iconText: '▸',
    keybinding: appShortcutText('Enter'),
    pinTop: true,
    searchFields: ['open folder', target],
    run: async () => { await openFileExplorerPane(); await openFileExplorerAt(target); },
  };
}

function fileQuickOpenStrictExternalIndexedQuery(query = commandPaletteSearchQuery()) {
  const text = String(query || '').trim();
  if (!text || text.includes('/') || text.startsWith('~')) return false;
  return /[.]/.test(text);
}

function fileQuickOpenExternalIndexedMatchAllowed(file, query = commandPaletteSearchQuery()) {
  if (!fileQuickOpenStrictExternalIndexedQuery(query)) return true;
  const path = String(file?.path || '');
  const basename = String(file?.name || basenameOf(path));
  const stem = basename.includes('.') ? basename.slice(0, basename.lastIndexOf('.')) : basename;
  const needle = fuzzyCanonicalPrefixText(query);
  if (!needle) return true;
  return [basename, stem]
    .map(fuzzyCanonicalPrefixText)
    .some(value => value && (value.startsWith(needle) || value.includes(needle)));
}

function fileQuickOpenItems() {
  const seen = new Set();
  const items = [];
  let imageIndex = 0;
  const add = item => {
    const path = item.searchFields?.[1] || item.detail || item.label;
    if (!path || seen.has(path)) return;
    seen.add(path);
    items.push(item);
  };
  const openFolder = fileQuickOpenOpenFolderItem();
  if (openFolder) items.push(openFolder);
  recentFileQuickOpenItems().forEach(add);
  for (const file of fileQuickOpenCandidates) {
    const path = file.path || '';
    if (!path) continue;
    // Only an entry that ACTUALLY came from an indexed-root search carries an indexed_root; path-mode
    // listing entries have none. Guard the empty case — normalizeStoredFileExplorerIndexedDir('') returns
    // '/' (empty -> root), which used to mislabel every path-mode directory row as "Indexed /".
    const indexedRoot = file.indexed_root ? normalizeStoredFileExplorerIndexedDir(file.indexed_root) : '';
    const baseRoot = normalizeStoredFileExplorerIndexedDir(fileQuickOpenRoot || '');
    const externalIndexed = Boolean(indexedRoot && indexedRoot !== baseRoot);
    if (externalIndexed && !fileQuickOpenExternalIndexedMatchAllowed(file)) continue;
    const isImage = (file.kind || 'file') !== 'dir' && IMAGE_EXTENSIONS.has(fileExtensionOf(path));
    if (isImage) imageIndex += 1;
    add(fileQuickOpenItem(path, {
      group: externalIndexed ? `Indexed ${compactHomePath(indexedRoot)}` : 'Files',
      relativePath: file.relative_path || file.name || '',
      kind: file.kind || 'file',
      imageIndex,
      mtime: file.mtime || 0,
      mtimeNs: file.mtime_ns || 0,
      sortBonus: (externalIndexed ? -250 : 250) + (file.uploaded === true ? -500 : 0),
    }));
  }
  if (fileQuickOpenError) {
    items.push({
      group: t('palette.group.files'),
      label: t('search.failed'),
      detail: fileQuickOpenError,
      searchFields: ['search failed', fileQuickOpenError],
      disabled: true,
      run: null,
    });
  }
  if (fileQuickOpenLoading) {
    items.push({
      group: t('palette.group.files'),
      label: t('search.searching'),
      detail: compactHomePath(fileQuickOpenRoot),
      searchFields: ['searching'],
      disabled: true,
      run: null,
    });
  }
  return items.map(item => ({...item, category: 'file'}));
}

function commandPaletteFilePath(item) {
  return item?.path || item?.searchFields?.[1] || fileItemPath(item?.targetItem || '') || item?.detail || item?.label || '';
}

function commandPaletteMergedItems() {
  const openTabPaths = new Set(commandPaletteAllTabItems().map(fileItemPath).filter(Boolean));
  const dedupedFileItems = fileQuickOpenItems().filter(item => !openTabPaths.has(commandPaletteFilePath(item)));
  return [...dedupedFileItems, ...commandPaletteCommandItems()];
}

function commandPaletteCandidateItems(mode = commandPaletteMode, rawQuery = commandPaletteQuery) {
  // Unified palette provider. `mode` is a priority flag: Cmd-P and Shift-Cmd-P draw from the same
  // candidate universe and differ only in searchRankWeights.domainPrior.
  const parts = fileQuickOpenQueryParts(rawQuery);
  if (parts.commandMode) return commandPaletteCommandItems();                          // `>` = actions only
  if (parts.symbolMode || fileQuickOpenPathQuery(rawQuery).active) return fileQuickOpenItems(); // `@` / path = files only
  // Lean on open: an empty box shows only the priority's home category (no command dump — #7).
  if (!commandPaletteSearchQuery(rawQuery, mode)) {
    return mode === 'files' ? fileQuickOpenItems() : commandPaletteCommandItems();
  }
  // On type: BOTH entry points search the full corpus; the priority sort floats the home category up.
  // S2: a file that is already an open tab shows ONCE — as the deduped Tabs row (which carries
  // both edit + preview chips). Drop its Recent/Files duplicate so it isn't listed twice. Only here, in
  // the merged view; the files-only and empty-box modes above have no Tabs rows, so Recent stays intact.
  return commandPaletteMergedItems();
}

function commandPaletteItems() {
  return commandPaletteCandidateItems(commandPaletteMode, commandPaletteQuery);
}

function commandPaletteRankItems(items, query, options = {}) {
  const ranked = (items || [])
    .map((item, sortIndex) => ({...item, score: commandPaletteItemScore(item, query, options), sortIndex}))
    .filter(item => Number.isFinite(item.score))
    .sort((left, right) => query
      ? right.score - left.score || left.group.localeCompare(right.group) || left.label.localeCompare(right.label)
      : right.score - left.score || left.sortIndex - right.sortIndex);
  return commandPaletteMixFirstScreenResults(ranked, query, options);
}

function commandPaletteMixDomains(options = {}) {
  const surface = commandPaletteSurface(options);
  if (surface === 'files') return {primary: 'file', secondary: 'pane'};
  if (surface === 'command') return {primary: 'pane', secondary: 'file'};
  return null;
}

function commandPaletteMixFirstScreenResults(ranked, query, options = {}) {
  if (!String(query || '').trim()) return ranked;
  const domains = commandPaletteMixDomains(options);
  if (!domains) return ranked;
  const windowSize = Math.max(0, Number(searchRankWeights.mixWindow || 0));
  const maxSecondary = Math.max(0, Number(searchRankWeights.mixSecondarySlots || 0));
  if (!windowSize || !maxSecondary) return ranked;
  const hasPrimary = ranked.slice(0, windowSize).some(item => commandPaletteItemDomain(item) === domains.primary);
  const secondaryCandidates = ranked
    .map((item, index) => ({item, index}))
    .filter(row => commandPaletteItemDomain(row.item) === domains.secondary)
    .slice(0, maxSecondary);
  if (!hasPrimary || !secondaryCandidates.length) return ranked;
  const selected = [];
  for (const [secondaryIndex, row] of secondaryCandidates.entries()) {
    const target = Math.min(
      windowSize - 1,
      searchRankWeights.mixFirstSecondaryIndex + secondaryIndex * searchRankWeights.mixSecondaryStep
    );
    if (row.index > target) selected.push({item: row.item, target});
  }
  if (!selected.length) return ranked;
  const selectedItems = new Set(selected.map(row => row.item));
  const result = ranked.filter(item => !selectedItems.has(item));
  for (const row of selected) {
    result.splice(Math.min(row.target, result.length), 0, row.item);
  }
  return result;
}

function commandPaletteMatches(item, query) {
  return Number.isFinite(commandPaletteItemScore(item, query));
}

function commandPaletteSurface(options = {}) {
  return options.surface === 'files' || options.surface === 'command' ? options.surface : commandPaletteMode;
}

function commandPaletteItemDomain(item) {
  if (item?.category === 'file') return 'file';
  if (item?.category === 'pane') return 'pane';
  if (item?.category === 'setting') return 'setting';
  return 'command';
}

function commandPaletteDomainPrior(item, options = {}) {
  const surface = commandPaletteSurface(options);
  const domain = commandPaletteItemDomain(item);
  return searchRankWeights.domainPrior[surface]?.[domain] || 0;
}

function commandPaletteNowSeconds(options = {}) {
  const explicit = Number(options.nowSeconds);
  return Number.isFinite(explicit) && explicit > 0 ? explicit : Date.now() / 1000;
}

function commandPaletteItemMtime(item) {
  return commandPaletteNumericTime(item?.mtime || item?.mtime_ns || 0);
}

function commandPaletteRecencyBonus(item, options = {}) {
  const timestamp = commandPaletteItemMtime(item);
  if (!timestamp) return 0;
  const age = Math.max(0, commandPaletteNowSeconds(options) - timestamp);
  return searchRankWeights.recencyCap * Math.pow(0.5, age / searchRankWeights.recencyHalfLifeSeconds);
}

function commandPaletteFocusedRepoRoots(options = {}) {
  if (Array.isArray(options.focusedRepoRoots)) {
    return options.focusedRepoRoots.map(normalizeDirectoryPath).filter(Boolean);
  }
  const focused = currentSessionActionTarget() || focusedPanelItem || focusedTerminal;
  const info = isTmuxSession(focused) ? sessionTranscriptInfo(focused) : null;
  const roots = [
    info?.gitRoot || '',
    focusedRepoRootForSync(info?.selectedPath || info?.gitCwd || '', sessionFilesRepoRoots()),
  ].map(normalizeDirectoryPath).filter(Boolean);
  return Array.from(new Set(roots));
}

function commandPaletteRepoAffinityBonus(item, options = {}) {
  if (item?.category !== 'file') return 0;
  const path = normalizeDirectoryPath(commandPaletteFilePath(item));
  if (!path) return 0;
  return commandPaletteFocusedRepoRoots(options).some(root => pathIsInsideDirectory(path, root))
    ? searchRankWeights.repoAffinity
    : 0;
}

function commandPaletteItemScore(item, query, options = {}) {
  if (item.disabled) return 0;
  // C15 follow-up: the path-mode "Open this folder in Finder" row always sorts to the top (and survives
  // any filter text) so it is the default Enter action while a directory path is typed.
  if (item.pinTop) return 1e9;
  const bonus = commandPaletteDomainPrior(item, options)
    + Number(item.sortBonus || 0)
    + commandPaletteRecentBonus(item)
    + commandPaletteFinderAliasBonus(item, query, options)
    + commandPaletteFileNameBonus(item, query)
    + commandPaletteRecencyBonus(item, options)
    + commandPaletteRepoAffinityBonus(item, options);
  if (!String(query || '').trim()) return bonus;
  const base = fuzzySearchScore(query, item.searchFields || [item.label, item.detail, item.group]);
  return Number.isFinite(base) ? base + bonus : base;
}

function commandPaletteFileNameBonus(item, query) {
  if (item?.category !== 'file') return 0;
  const tokens = String(query || '').trim().split(/\s+/).filter(Boolean);
  if (!tokens.length) return 0;
  const filename = String(item.searchFields?.[0] || item.label || '');
  const canonicalName = fuzzyCanonicalPrefixText(filename);
  if (!canonicalName) return 0;
  let bonus = 0;
  for (const token of tokens) {
    const canonicalToken = fuzzyCanonicalPrefixText(token);
    if (!canonicalToken) continue;
    if (canonicalName.startsWith(canonicalToken)) bonus += searchRankWeights.fileNamePrefix;
    else if (canonicalName.includes(canonicalToken)) bonus += searchRankWeights.fileNameContains;
    else if (Number.isFinite(fuzzySubsequenceScore(token, filename))) bonus += searchRankWeights.fileNameSubsequence;
  }
  return bonus;
}

function commandPaletteFinderAliasBonus(item, query, options = {}) {
  if (item?.targetItem !== fileExplorerItemId) return 0;
  const text = String(query || '').trim().toLowerCase().replace(/\s+/g, ' ');
  if (text.length < 3) return 0;
  const aliases = ['file', 'files', 'finder', 'file explorer'];
  if (!aliases.some(alias => alias === text || alias.startsWith(text))) return 0;
  return commandPaletteSurface(options) === 'files'
    ? searchRankWeights.finderAliasFilesMode
    : searchRankWeights.finderAlias;
}

function commandPaletteRecentBonus(item) {
  const key = item.key || `${item.group}:${item.label}`;
  const sequence = commandPaletteRecentKeys.get(key);
  return sequence ? searchRankWeights.recentSelectionBase + sequence : 0;
}

function rememberCommandPaletteItem(item) {
  if (!item || item.disabled) return;
  const key = item.key || `${item.group}:${item.label}`;
  setLimitedMapEntry(commandPaletteRecentKeys, key, ++commandPaletteRecentSequence, commandPaletteRecentKeyLimit);
}

function commandPaletteEffectiveMode() {
  return commandPaletteMode === 'files' && !fileQuickOpenQueryParts().commandMode ? 'files' : 'command';
}

function commandPaletteSearchQuery(query = commandPaletteQuery, mode = commandPaletteMode) {
  if (mode !== 'files') return String(query || '').trim();
  const parts = fileQuickOpenQueryParts(query);
  if (parts.commandMode) return String(query || '').replace(/^>\s*/, '').trim();
  if (parts.symbolMode) return String(query || '').replace(/^@\s*/, '').trim();
  const pathQuery = fileQuickOpenPathQuery(query);
  if (pathQuery.active) return pathQuery.filter;
  return fileQuickOpenSearchText(query);
}

function commandPalettePlaceholder() {
  // Identical for Cmd-P and Cmd-Shift-P — they differ only in result ordering, not in labels.
  const q = commandPaletteQuery.trim();
  if (q.startsWith('>')) return 'Run command';
  if (q.startsWith('@')) return 'Symbol search is not available yet';
  return 'Find files, tabs, commands, settings';
}

function commandPaletteLabel() {
  // Identical aria label for both entry points.
  return 'Quick open';
}

function commandPaletteEmptyText() {
  if (fileQuickOpenLoading) return 'Searching...';
  if (commandPaletteQuery.trim().startsWith('@')) return 'Symbol search is not available yet';
  return 'No matches';
}

function commandPaletteStatusText() {
  return fileQuickOpenLoading ? 'Searching files...' : '';
}

function ensureCommandPalette() {
  if (commandPaletteNode) return commandPaletteNode;
  const node = document.createElement('div');
  node.className = 'command-palette';
  node.hidden = true;
  node.innerHTML = `
    <div class="command-palette-dialog" role="dialog" aria-modal="true" aria-label="${esc(t('palette.aria'))}">
      <input type="search" class="command-palette-input" placeholder="${esc(t('palette.placeholder'))}" aria-label="${esc(t('palette.placeholder'))}">
      <div class="command-palette-status" aria-live="polite" hidden></div>
      <div class="command-palette-results" role="listbox"></div>
    </div>`;
  node.addEventListener('mousedown', event => {
    if (event.target === node) closeCommandPalette();
  });
  const input = node.querySelector('.command-palette-input');
  input.addEventListener('input', () => {
    commandPaletteQuery = input.value || '';
    commandPaletteIndex = 0;
    renderCommandPaletteResults();
    // Both entry points fetch files on type so a typed query can blend files into either ordering.
    scheduleFileQuickOpenSearch();
  });
  input.addEventListener('keydown', event => {
    if (event.key === 'Escape') {
      event.preventDefault();
      closeCommandPalette();
    } else if (event.key === 'ArrowDown') {
      event.preventDefault();
      commandPaletteIndex = commandPaletteItemsCache.length ? (commandPaletteIndex + 1) % commandPaletteItemsCache.length : 0;
      renderCommandPaletteResults();
    } else if (event.key === 'ArrowUp') {
      event.preventDefault();
      commandPaletteIndex = commandPaletteItemsCache.length ? (commandPaletteIndex - 1 + commandPaletteItemsCache.length) % commandPaletteItemsCache.length : 0;
      renderCommandPaletteResults();
    } else if (event.key === 'Enter') {
      event.preventDefault();
      invokeCommandPaletteSelection(event);
    }
  });
  node.querySelector('.command-palette-results').addEventListener('click', event => {
    // follow-up: a click on a view chip jumps to THAT view (edit/preview/diff) and closes the
    // palette, instead of the row's default (focus the editor view).
    const chip = event.target.closest('[data-view-item]');
    if (chip && node.contains(chip)) {
      const viewItem = chip.dataset.viewItem;
      closeCommandPalette();
      if (viewItem) selectSession(viewItem, {userInitiated: true});
      return;
    }
    const row = event.target.closest('[data-command-index]');
    if (!row || !node.contains(row)) return;
    commandPaletteIndex = Number(row.dataset.commandIndex || 0);
    invokeCommandPaletteSelection();
  });
  document.body.appendChild(node);
  commandPaletteNode = node;
  return node;
}

function renderCommandPaletteResults() {
  const node = ensureCommandPalette();
  const dialog = node.querySelector('.command-palette-dialog');
  const input = node.querySelector('.command-palette-input');
  const status = node.querySelector('.command-palette-status');
  const results = node.querySelector('.command-palette-results');
  const query = commandPaletteSearchQuery();
  dialog?.setAttribute('aria-label', commandPaletteLabel());
  if (input) {
    input.placeholder = commandPalettePlaceholder();
    input.setAttribute('aria-label', commandPaletteLabel());
    input.setAttribute('aria-busy', fileQuickOpenLoading ? 'true' : 'false');
  }
  if (status) {
    const text = commandPaletteStatusText();
    status.hidden = !text;
    status.textContent = text;
  }
  commandPaletteItemsCache = commandPaletteRankItems(commandPaletteItems(), query).slice(0, 60);
  commandPaletteIndex = Math.min(commandPaletteIndex, Math.max(0, commandPaletteItemsCache.length - 1));
  if (!commandPaletteItemsCache.length) {
    results.innerHTML = `<div class="command-palette-empty">${esc(commandPaletteEmptyText())}</div>`;
    return;
  }
  results.innerHTML = commandPaletteItemsCache.map((item, index) => `
    <button type="button" class="command-palette-row${index === commandPaletteIndex ? ' active' : ''}" data-command-index="${index}" role="option" aria-selected="${index === commandPaletteIndex ? 'true' : 'false'}"${item.disabled ? ' disabled' : ''}>
      <span class="command-palette-group">${esc(item.group)}</span>
      <span class="command-palette-main"><span class="command-palette-title">${item.iconText ? `<span class="command-palette-file-icon" aria-hidden="true">${esc(item.iconText)}</span>` : ''}<span class="command-palette-label">${fuzzyHighlightHtml(query, item.label)}</span>${(item.viewModes && item.viewModes.length) ? `<span class="command-palette-views">${item.viewModes.map(v => `<span class="command-palette-view-chip" role="button" tabindex="-1" data-view-item="${esc(v.item)}" data-view-mode="${esc(v.mode)}" title="${esc(t('palette.openView', {view: v.label}))}">${esc(v.label)}</span>`).join('')}</span>` : ''}</span><span class="command-palette-detail">${fuzzyHighlightHtml(query, item.detail || '')}</span></span>
      <span class="command-palette-keybinding">${esc(item.keybinding || '')}</span>
    </button>`).join('');
  results.querySelector('.command-palette-row.active')?.scrollIntoView?.({block: 'nearest'});
}

function openCommandPalette(options = {}) {
  const node = ensureCommandPalette();
  closeAppMenus();
  commandPaletteMode = options.mode === 'files' ? 'files' : 'command';
  commandPaletteQuery = '';
  commandPaletteIndex = 0;
  node.hidden = false;
  node.classList.add('open');
  const input = node.querySelector('.command-palette-input');
  input.value = '';
  // Reset file-search state for BOTH entry points so a typed query can blend files in either mode.
  fileQuickOpenRoot = fileQuickOpenRootForSearch();
  fileQuickOpenCandidates = [];
  fileQuickOpenLoading = false;
  fileQuickOpenError = '';
  // Only Cmd-P (files priority) shows files on an empty box, so only it searches immediately;
  // Cmd-Shift-P fetches files on the first keystroke (via the input handler).
  if (commandPaletteMode === 'files') scheduleFileQuickOpenSearch({immediate: true});
  renderCommandPaletteResults();
  input.focus({preventScroll: true});
}

function openFileQuickOpen() {
  openCommandPalette({mode: 'files'});
}

function closeCommandPalette() {
  if (!commandPaletteNode) return;
  commandPaletteNode.hidden = true;
  commandPaletteNode.classList.remove('open');
  if (fileQuickOpenDebounce) clearTimeout(fileQuickOpenDebounce);
  fileQuickOpenDebounce = null;
}

function focusCommandPaletteTarget(item) {
  const target = item?.targetItem;
  if (!isLayoutItem(target)) return;
  focusPanel(target, {userInitiated: true});
  renderPaneTabStrips();
  requestAnimationFrame(() => focusPanel(target, {userInitiated: true}));
}

async function invokeCommandPaletteSelection(event = null) {
  const item = commandPaletteItemsCache[commandPaletteIndex];
  if (!item || item.disabled) return;
  rememberCommandPaletteItem(item);
  closeCommandPalette();
  const action = appModifier(event) && item.splitRun ? item.splitRun : item.run;
  await Promise.resolve(action?.());
  focusCommandPaletteTarget(item);
}

function scheduleFileQuickOpenSearch(options = {}) {
  if (fileQuickOpenDebounce) clearTimeout(fileQuickOpenDebounce);
  const run = () => {
    const q = commandPaletteQuery.trim();
    if (!q.startsWith('>') && !q.startsWith('@')) refreshFileQuickOpenCandidates(commandPaletteQuery);
  };
  if (options.immediate) run();
  else fileQuickOpenDebounce = setTimeout(run, 160);
}

function abortFileQuickOpenSearch() {
  if (fileQuickOpenAbortController) {
    try { fileQuickOpenAbortController.abort(); } catch (_) {}
  }
  fileQuickOpenAbortController = null;
  fileQuickOpenRequestId += 1;
  fileQuickOpenLoading = false;
}

// Fold TRUE duplicate file-search hits: same path, same resolved realpath (symlink / overlay
// overlap), or same basename+size (content-mirror copies kept in two repos). Genuinely-different
// same-name files (different size) both survive; unknown-size hits dedupe by path/realpath only.
function dedupeFileSearchResults(files) {
  const seen = new Set();
  const out = [];
  for (const file of Array.isArray(files) ? files : []) {
    const path = file?.path || '';
    if (!path) continue;
    const keys = [`p:${path}`, `r:${file.realpath || path}`];
    if (Number.isFinite(Number(file.size))) keys.push(`n:${basenameOf(path)}|${Number(file.size)}`);
    if (keys.some(key => seen.has(key))) continue;
    keys.forEach(key => seen.add(key));
    out.push(file);
  }
  return out;
}

async function refreshFileQuickOpenCandidates(query = '') {
  const root = fileQuickOpenRoot || fileQuickOpenRootForSearch();
  if (!root) return;
  abortFileQuickOpenSearch();
  const requestId = ++fileQuickOpenRequestId;
  fileQuickOpenAbortController = typeof AbortController === 'function' ? new AbortController() : null;
  const fetchOptions = fileQuickOpenAbortController ? {signal: fileQuickOpenAbortController.signal} : {};
  fileQuickOpenLoading = true;
  renderCommandPaletteResults();
  try {
    const pathQuery = fileQuickOpenPathQuery(query);
    if (pathQuery.active) {
      const response = await apiFetch(`/api/fs/list?path=${encodeURIComponent(pathQuery.directory || '/')}`);
      const payload = await response.json().catch(() => ({}));
      if (!response.ok) throw new Error(payload.error || response.status);
      if (requestId !== fileQuickOpenRequestId) return;
      fileQuickOpenRoot = payload.path || pathQuery.directory || root;
      const filter = String(pathQuery.filter || '').toLowerCase();
      fileQuickOpenCandidates = (Array.isArray(payload.entries) ? payload.entries : [])
        .filter(entry => entry?.kind === 'file' || entry?.kind === 'dir')
        .filter(entry => !filter || String(entry.name || '').toLowerCase().includes(filter))
        .map(entry => ({
          name: entry.name || '',
          path: joinDirectoryPath(payload.path || pathQuery.directory || '/', entry.name || ''),
          relative_path: entry.name || '',
          kind: entry.kind || 'file',
          size: entry.size,
          mtime: entry.mtime,
        }));
    } else {
      const searchRoots = fileQuickOpenRootsForSearch(root, commandPaletteSearchQuery(query));
      const results = await Promise.all(searchRoots.map(async searchRoot => {
        try {
          const normalizedRoot = normalizeStoredFileExplorerIndexedDir(searchRoot);
          const recursive = normalizedRoot && fileExplorerDirectoryIsIndexed(normalizedRoot) ? '&recursive=1' : '';
          const response = await apiFetch(`/api/fs/search?root=${encodeURIComponent(searchRoot)}&query=${encodeURIComponent(commandPaletteSearchQuery(query))}&limit=500${recursive}`, fetchOptions);
          const payload = await response.json().catch(() => ({}));
          if (!response.ok) throw new Error(payload.error || response.status);
          return {ok: true, root: normalizeStoredFileExplorerIndexedDir(payload.root || payload.root_realpath || searchRoot) || searchRoot, files: Array.isArray(payload.files) ? payload.files : []};
        } catch (error) {
          return {ok: false, root: searchRoot, error};
        }
      }));
      if (requestId !== fileQuickOpenRequestId) return;
      const successful = results.filter(result => result.ok);
      if (!successful.length) {
        const firstError = results.find(result => result.error)?.error || 'search failed';
        throw new Error(firstError);
      }
      fileQuickOpenRoot = root;
      fileQuickOpenCandidates = dedupeFileSearchResults(
        successful.flatMap(result => result.files.map(file => ({...file, indexed_root: result.root}))),
      );
    }
    fileQuickOpenError = '';
  } catch (error) {
    if (requestId !== fileQuickOpenRequestId) return;
    if (error?.name === 'AbortError') return;
    fileQuickOpenCandidates = [];
    fileQuickOpenError = String(error);
  } finally {
    if (requestId === fileQuickOpenRequestId) {
      fileQuickOpenAbortController = null;
      fileQuickOpenLoading = false;
      renderCommandPaletteResults();
    }
  }
}

function shouldNotifyTransitionKey(key) {
  const configured = initialSetting('notifications.notify_transitions', ['needs-input', 'needs-approval', 'blocked']);
  const transitions = Array.isArray(configured) ? configured : ['needs-input', 'needs-approval', 'blocked'];
  return transitions.includes(key);
}

function shouldNotifyState(state) {
  return shouldNotifyTransitionKey(state.key);
}

function sendBrowserNotification(title, options = {}) {
  const notification = new Notification(title, options);
  notification.onclick = () => {
    window.focus();
    if (options.session) selectSession(options.session, {userInitiated: true});
    // a watched-PR notification opens the PR (no session to focus); safe blank-target open.
    else if (options.url) {
      try { window.open(options.url, '_blank', 'noopener,noreferrer'); } catch (_) {}
    }
  };
  return notification;
}

function setToastCountdown(node, durationMs) {
  if (!node) return;
  if (!Number.isFinite(durationMs)) {
    node.style.removeProperty('--toast-countdown-duration');
    return;
  }
  node.style.setProperty('--toast-countdown-duration', `${Math.max(1, durationMs)}ms`);
}

// Upload and attention/status messages share this renderer. Keep visual differences out of call sites.
function ensureToastShell(node, options = {}) {
  let bodyNode = node.querySelector('.toast-body');
  if (!bodyNode) {
    node.innerHTML = `
      <div class="toast-header">
        <div class="toast-title"></div>
        <div class="toast-control-row">
          <button type="button" class="toast-keep" data-toast-keep aria-label="${esc(options.keepLabel || t('toast.keepAlert'))}">${esc(t('toast.keep'))}</button>
          <button type="button" class="toast-close" data-toast-close aria-label="${esc(options.closeLabel || t('toast.closeAlert'))}">X</button>
        </div>
      </div>
      <div class="toast-body"></div>
      <div class="toast-actions"></div>`;
    bodyNode = node.querySelector('.toast-body');
  }
  const titleNode = node.querySelector('.toast-title');
  if (titleNode) titleNode.textContent = options.title || '';
  const actionsNode = node.querySelector('.toast-actions');
  if (actionsNode) {
    actionsNode.replaceChildren(...(options.actions || []));
    actionsNode.hidden = !actionsNode.children.length;
  }
  const closeButton = node.querySelector('[data-toast-close]');
  if (closeButton) {
    closeButton.onclick = event => {
      event.stopPropagation();
      options.onClose?.();
    };
  }
  const keepButton = node.querySelector('[data-toast-keep]');
  if (keepButton) {
    keepButton.onclick = event => {
      event.stopPropagation();
      node.classList.add('kept');
      keepButton.hidden = true;
      options.onKeep?.();
    };
  }
  return bodyNode;
}

function renderToastLines(bodyNode, lines, options = {}) {
  bodyNode.replaceChildren();
  for (const item of summarizeToastLines(lines, options)) {
    const lineText = typeof item === 'object' && item !== null ? item.text : item;
    const countdownMs = typeof item === 'object' && item !== null ? item.countdownMs : options.countdownMs;
    const line = document.createElement('div');
    line.className = 'toast-line';
    setToastCountdown(line, countdownMs || toastDurationMs);
    line.textContent = lineText;
    bodyNode.appendChild(line);
  }
}

function normalizeToastLine(item, options = {}) {
  const objectItem = typeof item === 'object' && item !== null;
  const text = objectItem ? item.text : item;
  return {
    text: compactToastText(text),
    countdownMs: objectItem ? item.countdownMs : options.countdownMs,
  };
}

function compactToastText(text) {
  const value = String(text || '').replace(/\s+/g, ' ').trim();
  if (value.length <= toastMaxLineChars) return value;
  return `${value.slice(0, toastMaxLineChars - 3)}...`;
}

function summarizeToastLines(lines, options = {}) {
  const normalized = (Array.isArray(lines) ? lines : toastTextLines(lines)).map(item => normalizeToastLine(item, options));
  if (normalized.length <= toastMaxLines) return normalized;
  const visible = normalized.slice(0, toastMaxLines - 1);
  const hidden = normalized.slice(toastMaxLines - 1);
  const countdownValues = hidden.map(item => item.countdownMs).filter(Number.isFinite);
  visible.push({
    text: t('common.more', {count: hidden.length}),
    countdownMs: countdownValues.length ? Math.max(...countdownValues) : options.countdownMs,
  });
  return visible;
}

function toastTextLines(text) {
  const lines = String(text || '').split('\n').map(line => line.trim()).filter(Boolean);
  return lines.length ? lines : [''];
}

function showToast(title, lines, options = {}) {
  const container = options.container || attentionAlerts;
  if (!container) return null;
  const id = ++attentionAlertSequence;
  const node = document.createElement('div');
  node.className = options.className || 'attention-alert toast';
  node.dataset.alertId = String(id);
  const bodyNode = ensureToastShell(node, {
    title,
    closeLabel: options.closeLabel,
    keepLabel: options.keepLabel,
    actions: options.actions,
    onKeep: () => {
      if (attentionAlertTimers.has(id)) {
        clearTimeout(attentionAlertTimers.get(id));
        attentionAlertTimers.delete(id);
      }
      options.onKeep?.();
    },
    onClose: () => {
      options.onClose?.();
      removeAttentionAlert(id);
    },
  });
  renderToastLines(bodyNode, Array.isArray(lines) ? lines : toastTextLines(lines), {
    countdownMs: options.countdownMs || toastDurationMs,
  });
  node.addEventListener('click', event => {
    if (event.target.closest('[data-toast-close], .toast-actions')) return;
    options.onClick?.();
  });
  container.appendChild(node);
  while (container.children.length > 5) {
    const first = container.firstElementChild;
    if (!first) break;
    removeAttentionAlert(Number(first.dataset.alertId || 0));
  }
  // remove the toast when its countdown bar finishes — honor options.countdownMs (the
  // reconnect toast animates over that, not the fixed toastDurationMs) so the bar and removal align.
  attentionAlertTimers.set(id, window.setTimeout(() => removeAttentionAlert(id), options.countdownMs || toastDurationMs));
  return node;
}

function startupHelperCatalog() {
  return [
    {title: t('startupHelper.tip.dragFiles.title'), lines: [t('startupHelper.tip.dragFiles.body')]},
    {title: t('startupHelper.tip.imageDrag.title'), lines: [t('startupHelper.tip.imageDrag.body')]},
    {title: t('startupHelper.tip.yoagentQuestions.title'), lines: [t('startupHelper.tip.yoagentQuestions.body')]},
    {title: t('startupHelper.tip.yoloAutoApprove.title'), lines: [t('startupHelper.tip.yoloAutoApprove.body')]},
    {title: t('startupHelper.tip.yoloRules.title'), lines: [t('startupHelper.tip.yoloRules.body')]},
    {title: t('startupHelper.tip.diffView.title'), lines: [t('startupHelper.tip.diffView.body')]},
    {title: t('startupHelper.tip.finderSync.title'), lines: [t('startupHelper.tip.finderSync.body')]},
    {title: t('startupHelper.tip.finderReload.title'), lines: [t('startupHelper.tip.finderReload.body')]},
    {title: t('startupHelper.tip.editorDiff.title'), lines: [t('startupHelper.tip.editorDiff.body')]},
    {title: t('startupHelper.tip.notifications.title'), lines: [t('startupHelper.tip.notifications.body')]},
    {title: t('startupHelper.tip.watchedPrs.title'), lines: [t('startupHelper.tip.watchedPrs.body')]},
    {title: t('startupHelper.tip.quickOpen.title'), lines: [t('startupHelper.tip.quickOpen.body')]},
    {title: t('startupHelper.tip.markdownPreview.title'), lines: [t('startupHelper.tip.markdownPreview.body')]},
    {title: t('startupHelper.tip.largeUpload.title'), lines: [t('startupHelper.tip.largeUpload.body')]},
  ];
}

function readStartupHelperIndex(count) {
  const parsed = Number(storageGet(startupHelperIndexStorageKey, '0'));
  if (!Number.isFinite(parsed) || count <= 0) return 0;
  return Math.max(0, Math.floor(parsed)) % count;
}

function writeStartupHelperIndex(index) {
  storageSet(startupHelperIndexStorageKey, Math.max(0, Math.floor(Number(index) || 0)));
}

function startupHelperWrappedIndex(index, count) {
  if (!Number.isFinite(Number(index)) || count <= 0) return 0;
  return ((Math.floor(Number(index)) % count) + count) % count;
}

function startupHelperAction(label, onClick, options = {}) {
  const button = document.createElement('button');
  button.type = 'button';
  button.textContent = label;
  if (options.className) button.className = options.className;
  if (options.title) button.title = options.title;
  if (options.ariaLabel) button.setAttribute('aria-label', options.ariaLabel);
  button.addEventListener('click', event => {
    event.stopPropagation();
    onClick?.();
  });
  return button;
}

function startupHelperNavigationGroup(index, total, showRelativeTip) {
  const group = document.createElement('span');
  group.className = 'startup-helper-nav';
  group.setAttribute('role', 'group');
  group.setAttribute('aria-label', 'Tip navigation');
  group.append(
    startupHelperAction('<', () => showRelativeTip(-1), {
      className: 'startup-helper-nav-button',
      title: 'Previous tip',
      ariaLabel: 'Previous tip',
    }),
    startupHelperAction('>', () => showRelativeTip(1), {
      className: 'startup-helper-nav-button',
      title: t('startupHelper.action.next'),
      ariaLabel: t('startupHelper.action.next'),
    }),
  );
  return group;
}

function startupHelperPromptAction(title) {
  const text = String(title || '').trim();
  if (!text) return t('startupHelper.defaultAction');
  return text.charAt(0).toLowerCase() + text.slice(1);
}

function startupHelperPromptTitle(index, total, tip) {
  return t('startupHelper.titleTemplate', {
    index: index + 1,
    total,
    action: startupHelperPromptAction(tip?.title),
  });
}

function closeStartupHelperToast(node) {
  removeAttentionAlert(Number(node?.dataset?.alertId || 0));
}

function showStartupHelperTip(options = {}) {
  if (readOnlyMode || !startupHelpersEnabled) return null;
  const tips = startupHelperCatalog();
  if (!tips.length) return null;
  const index = readStartupHelperIndex(tips.length);
  const tip = tips[index];
  writeStartupHelperIndex((index + 1) % tips.length);
  let node = null;
  const showRelativeTip = delta => {
    closeStartupHelperToast(node);
    writeStartupHelperIndex(startupHelperWrappedIndex(index + delta, tips.length));
    showStartupHelperTip({manual: true});
  };
  const navAction = startupHelperNavigationGroup(index, tips.length, showRelativeTip);
  const offAction = startupHelperAction(t('startupHelper.action.offForever'), () => {
    startupHelpersEnabled = false;
    closeStartupHelperToast(node);
    saveSettingsPatch(settingPatch('general.startup_tips', false))
      .then(() => { statusEl.textContent = t('startupHelper.status.disabled'); })
      .catch(error => { statusErr(`settings save failed: ${esc(error)}`); refreshSettings({force: true}); });
  });
  node = showToast(startupHelperPromptTitle(index, tips.length, tip), tip.lines, {
    className: 'attention-alert toast startup-helper-toast',
    container: displayToastContainer(focusedPanelItem),
    actions: [navAction, offAction],
    countdownMs: 45000,
  });
  if (node) node.dataset.toastKind = 'startup-helper';
  return node;
}

function scheduleStartupHelperTip() {
  if (readOnlyMode || !startupHelpersEnabled) return;
  if (location.protocol === 'file:') return;
  window.setTimeout(() => {
    showStartupHelperTip();
  }, 1400);
}

function displayToastContainer(session) {
  const sessionContainer = session ? document.getElementById(`panel-toasts-${session}`) : null;
  if (sessionContainer && sessionContainer.isConnected !== false) return sessionContainer;
  const candidates = [focusedPanelItem, ...activeSessions];
  for (const item of candidates) {
    const node = item ? document.getElementById(`panel-toasts-${item}`) : null;
    if (node && node.isConnected !== false) return node;
  }
  return document.querySelector('.panel-toast-stack') || attentionAlerts;
}

function compactNotificationTitle(scope, message) {
  const suffix = String(message || '').trim();
  const label = String(scope || '').trim();
  if (!label) return suffix ? `YOLOmux ${suffix}` : 'YOLOmux';
  return suffix ? `YOLOmux[${label}] ${suffix}` : `YOLOmux[${label}]`;
}

function sessionNotificationTitle(session, state) {
  return compactNotificationTitle(sessionLabel(session), state?.label || '');
}

function hostNotificationTitle(message) {
  return compactNotificationTitle(serverHostname, message);
}

function showAttentionAlert(session, state) {
  const node = showToast(
    sessionNotificationTitle(session, state),
    state.reason,
    {
      container: displayToastContainer(session),
      onClick: () => selectSession(session, {userInitiated: true}),
    },
  );
  if (node) {
    node.dataset.toastSession = session;
    node.dataset.toastKind = 'attention';
  }
}

function dismissAttentionAlertsForSession(session) {
  for (const node of document.querySelectorAll('.toast[data-toast-kind="attention"]')) {
    if (node.dataset.toastSession !== session) continue;
    removeAttentionAlert(Number(node.dataset.alertId || 0));
  }
}

function attentionAlreadyVisible(session) {
  if (document.visibilityState !== 'visible') return false;
  if (!activeSessions.includes(session)) return false;
  const panel = document.getElementById(panelDomId(session));
  if (!panel || !panel.isConnected) return false;
  return focusedPanelItem === session || focusedTerminal === session || activeSessions.length === 1;
}

function removeAttentionAlert(id) {
  if (attentionAlertTimers.has(id)) {
    clearTimeout(attentionAlertTimers.get(id));
    attentionAlertTimers.delete(id);
  }
  document.querySelector(`[data-alert-id="${id}"]`)?.remove();
}

function sendTestNotification() {
  showToast(t('notify.testTitle', {host: serverHostname}), t('notify.testBody'), {
    container: displayToastContainer(focusedPanelItem),
  });
  if (!notificationsEnabled || !('Notification' in window) || Notification.permission !== 'granted') return;
  try {
    sendBrowserNotification(t('notify.testTitle', {host: serverHostname}), {
      body: t('notify.browserTestBody'),
      tag: `yolomux:test:${Date.now()}`,
    });
    postEvent(null, 'notification_test_sent', 'notification test sent', {hostname: serverHostname});
  } catch (error) {
    statusErr(`notification failed: ${esc(error)}`);
    postEvent(null, 'notification_error', `notification test failed: ${error}`, {hostname: serverHostname});
  }
}

function notifyCurrentAttentionStates() {
  for (const session of sessions.filter(isTmuxSession)) {
    const state = sessionState(session, transcriptMeta.sessions?.[session]);
    if (shouldNotifyState(state)) maybeNotifyState(session, state, {force: true});
  }
}

function eventMessageForState(session, state) {
  return `${sessionLabel(session)} ${state.label}: ${state.reason}`;
}

function stateSignature(state) {
  return `${state.key}:${state.reason || ''}`;
}

function trackSessionStateChanges() {
  for (const session of sessions.filter(isTmuxSession)) {
    const state = sessionState(session, transcriptMeta.sessions?.[session]);
    const previous = sessionStateKeys.get(session);
    const signature = stateSignature(state);
    sessionStateKeys.set(session, {key: state.key, reason: state.reason, signature});
    if (!stateTrackingReady || previous == null || previous.signature === signature) continue;
    postEvent(session, 'state_changed', eventMessageForState(session, state), {
      from: previous.key,
      from_reason: previous.reason,
      to: state.key,
      reason: state.reason,
    });
    maybeNotifyState(session, state);
  }
  stateTrackingReady = true;
}

function maybeNotifyState(session, state, options = {}) {
  if (!notificationsEnabled) return;
  if (!shouldNotifyState(state)) return;
  const key = `${session}:${stateSignature(state)}`;
  const now = Date.now();
  if (attentionAlreadyVisible(session)) {
    setLimitedMapEntry(notificationLastSent, key, now, notificationLastSentLimit);
    dismissAttentionAlertsForSession(session);
    postEvent(session, 'alert_suppressed_visible', eventMessageForState(session, state), {
      state: state.key,
      reason: state.reason,
    });
    return;
  }
  const lastSent = notificationLastSent.get(key) || 0;
  if (options.force !== true && now - lastSent < 60_000) return;
  setLimitedMapEntry(notificationLastSent, key, now, notificationLastSentLimit);
  const body = `${state.reason} · ${projectDirName(session, transcriptMeta.sessions?.[session])}`;
  showAttentionAlert(session, state);
  postEvent(session, 'alert_shown', eventMessageForState(session, state), {
    state: state.key,
    reason: state.reason,
  });
  if (!('Notification' in window) || Notification.permission !== 'granted') return;
  try {
    sendBrowserNotification(sessionNotificationTitle(session, state), {
      body,
      tag: key,
      renotify: true,
      session,
    });
    postEvent(session, 'notification_sent', eventMessageForState(session, state), {
      state: state.key,
      reason: state.reason,
    });
  } catch (error) {
    postEvent(session, 'notification_error', `notification failed: ${error}`, {
      state: state.key,
    });
  }
}

// a stable snapshot of the watched-PR status dimensions we diff for notifications.
function watchedPrStatusSnapshot(pr) {
  return {
    merged: pr?.merged === true || pullRequestStatusLabel(pr).toLowerCase() === 'merged',
    ci: String(pr?.checks?.state || '').toLowerCase(),
    review: String(pr?.review_decision || '').toUpperCase(),
  };
}

// Pure transition detector: which notifiable transitions fired between two status snapshots. Merged
// (→ merged), CI flipped into failing, review decision changed. No previous snapshot → no transition
// (first sighting only records a baseline, so a load with already-merged/failing PRs does not storm).
function watchedPrTransitionKeys(prev, next) {
  const keys = [];
  if (!prev || !next) return keys;
  if (!prev.merged && next.merged) keys.push('pr-merged');
  if (prev.ci !== 'failing' && next.ci === 'failing') keys.push('pr-ci-failing');
  if (prev.review !== next.review && next.review) keys.push('pr-review');
  return keys;
}

// Diff each watched PR's new status against the last-seen one and notify on a transition.
function notifyWatchedPrTransitions(prs) {
  for (const pr of Array.isArray(prs) ? prs : []) {
    const ref = String(pr?.ref || (pr?.number ? `#${pr.number}` : ''));
    if (!ref) continue;
    const next = watchedPrStatusSnapshot(pr);
    const prev = watchedPrLastStatus.get(ref);
    watchedPrLastStatus.set(ref, next);
    for (const key of watchedPrTransitionKeys(prev, next)) {
      let message;
      if (key === 'pr-merged') message = t('notify.pr.merged', {ref});
      else if (key === 'pr-ci-failing') message = t('notify.pr.ciFailing', {ref});
      else message = t('notify.pr.review', {ref, decision: pullRequestApprovalLabel(next.review) || next.review});
      maybeNotifyWatchedPr(ref, key, message, pr.url);
    }
  }
}

// Fire a watched-PR transition through the shared notification channel: an in-page toast (clicks open
// the PR) + a browser Notification, gated by notificationsEnabled + notify_transitions, deduped and
// throttled by notifications.throttle_seconds via the shared notificationLastSent map.
function maybeNotifyWatchedPr(ref, key, message, url) {
  if (!notificationsEnabled) return;
  if (!shouldNotifyTransitionKey(key)) return;
  const signature = `watched-pr:${ref}:${key}`;
  const now = Date.now();
  const throttleMs = Math.max(0, (Number(initialSetting('notifications.throttle_seconds', 60)) || 0) * 1000);
  const lastSent = notificationLastSent.get(signature) || 0;
  if (now - lastSent < throttleMs) return;
  setLimitedMapEntry(notificationLastSent, signature, now, notificationLastSentLimit);
  showToast(message, [ref], {
    onClick: () => { try { window.open(url, '_blank', 'noopener,noreferrer'); } catch (_) {} },
  });
  postEvent(null, 'watched_pr_alert', message, {ref, transition: key});
  if (!('Notification' in window) || Notification.permission !== 'granted') return;
  try {
    sendBrowserNotification(hostNotificationTitle(message), {
      body: ref,
      tag: signature,
      renotify: true,
      url,
    });
    postEvent(null, 'watched_pr_notification', message, {ref, transition: key});
  } catch (error) {
    postEvent(null, 'watched_pr_notification_error', `notification failed: ${error}`, {ref, transition: key});
  }
}

function updateTopbarMetrics() {
  if (!topbar) return;
  const height = Math.ceil(topbar.getBoundingClientRect().height || 38);
  document.documentElement?.style?.setProperty('--topbar-height', `${height}px`);
}

function scheduleTopbarMetricsUpdate() {
  requestAnimationFrame(updateTopbarMetrics);
}

function bindTopbarMetrics() {
  updateTopbarMetrics();
  if (topbarResizeObserver || !topbar || !window.ResizeObserver) return;
  topbarResizeObserver = new ResizeObserver(updateTopbarMetrics);
  topbarResizeObserver.observe(topbar);
}

function scheduleTabStripOverflowCheck(strip) {
  if (!strip) return;
  if (strip === sessionButtons || strip.classList?.contains('pane-tabs')) {
    strip.classList.remove('tabs-overflowing');
    scheduleTopbarMetricsUpdate();
    return;
  }
  strip.classList.remove('tabs-overflowing');
  requestAnimationFrame(() => {
    strip.classList.toggle('tabs-overflowing', strip.scrollWidth > strip.clientWidth + 1);
  });
}

function scheduleAllTabStripOverflowChecks() {
  scheduleTabStripOverflowCheck(sessionButtons);
  for (const strip of document.querySelectorAll('.pane-tabs')) {
    scheduleTabStripOverflowCheck(strip);
  }
}

function normalizedSessionOrder(nextSessions) {
  if (!Array.isArray(nextSessions)) return null;
  const next = [];
  for (const session of nextSessions) {
    if (typeof session === 'string' && session && !next.includes(session)) next.push(session);
  }
  return next;
}

function setSessionOrder(next) {
  sessions = next;
  visibleSessions = sessions.slice(0, maxSessionTabs);
  layoutItems = computeLayoutItems();
}

function updateSessionList(nextSessions) {
  const next = normalizedSessionOrder(nextSessions);
  if (!next) return false;
  const changed = next.length !== sessions.length || next.some((session, index) => session !== sessions[index]);
  if (!changed) return false;
  const removedSessions = visibleSessions.filter(session => !next.includes(session));
  setSessionOrder(next);
  layoutSlots = normalizeLayoutSlots(layoutSlots, {
    preserveRemovedItems: removedSessions,
    preserveRemovedSlots: true,
  });
  activeSessions = sessionsFromLayout();
  clearFocusForInactiveLayout();
  updateActiveSessionParam();
  return true;
}

function applyLayoutSlots(nextSlots, options = {}) {
  const previousActive = activeSessions.slice();
  // detect a same-shape change (reorder/activate/move/replace) so we can skip the full
  // topbar + grid teardown. Compute the shape signature before and after the slot reassignment.
  const prevShape = layoutShapeSignature(layoutSlots);
  layoutSlots = normalizeLayoutSlots(nextSlots);
  activeSessions = sessionsFromLayout();
  clearFocusForInactiveLayout();
  updateActiveSessionParam();
  requestLayoutRender({
    previousActive,
    prevShape,
    nextShape: layoutShapeSignature(layoutSlots),
    options: {prune: options.prune},
    reason: 'applyLayoutSlots',
    forceFull: options.forceFull === true,
  });
  for (const session of activeSessions.filter(isTmuxSession)) ensureTerminalRunning(session);
  // do NOT re-poll the server on a pure client-side layout change. refreshTranscripts()
  // fires 3..(3+N) network round-trips and a second full render wave gated behind their latency —
  // the bulk of the "moving a tab takes several seconds" delay. Freshness is already covered by the
  // metadata interval (50_editor_settings_runtime.js), and the session-changing mutations
  // (create/rename/kill, 70_layout_actions.js) call refreshTranscripts() at their own sites.
  renderAutoApproveButtons();
  updatePanelInactiveOverlays();
  if (autoFocusEnabled && options.focusSession && activeSessions.includes(options.focusSession)) {
    setTimeout(() => focusPanel(options.focusSession), 80);
  } else if (options.message && activeSessions.length) {
    statusEl.textContent = options.message;
  } else {
    updateStatus();
  }
  if (clientPushCanSupplyData() && typeof syncServerWatchRoots === 'function') syncServerWatchRoots();
}

function layoutRenderRequest(request = {}) {
  return {
    previousActive: Array.isArray(request.previousActive) ? request.previousActive.slice() : [],
    prevShape: String(request.prevShape || ''),
    nextShape: String(request.nextShape || ''),
    options: request.options || {},
    reason: request.reason || '',
    forceFull: request.forceFull === true,
  };
}

function mergePendingLayoutRender(current, next) {
  if (!current) return next;
  return layoutRenderRequest({
    previousActive: current.previousActive,
    prevShape: current.prevShape,
    nextShape: next.nextShape || current.nextShape,
    options: {...current.options, ...next.options},
    reason: [current.reason, next.reason].filter(Boolean).join('+'),
    forceFull: current.forceFull || next.forceFull,
  });
}

function layoutRenderCanUseCheap(request) {
  return !request.forceFull
    && request.prevShape === request.nextShape
    && grid.querySelector('.drop-slot[data-slot]');
}

function performLayoutRender(request = {}) {
  const renderRequest = layoutRenderRequest(request);
  const previousActive = renderRequest.previousActive;
  if (layoutRenderCanUseCheap(renderRequest)) {
    // Cheap path: the tree shape is unchanged. Swap only the slots whose active item changed and
    // reconcile the (already keyed) tab strips — no innerHTML='', no topbar rebuild.
    syncActivePanelsInPlace();
    renderPaneTabStrips();
    syncPanelVisibility(previousActive);
    return;
  }
  renderSessionButtons();
  renderPanels(previousActive, {prune: renderRequest.options.prune});
}

function requestLayoutRender(request = {}) {
  const renderRequest = layoutRenderRequest(request);
  if (dragSession != null) {
    pendingLayoutRender = mergePendingLayoutRender(pendingLayoutRender, renderRequest);
    return;
  }
  performLayoutRender(renderRequest);
}

function flushPendingLayoutRender(reason = 'drag-flush') {
  const renderRequest = pendingLayoutRender;
  pendingLayoutRender = null;
  if (renderRequest) requestLayoutRender({...renderRequest, reason});
}

function updateActiveSessionParam() {
  const params = new URLSearchParams(location.search);
  params.delete('active');
  params.delete('sessions');
  params.delete('layout');
  params.delete('tabs');
  const queryParts = [];
  const inactiveItems = inactiveTabItems();
  if (activeSessions.length || inactiveItems.length) {
    if (activeSessions.length) {
      queryParts.push(`sessions=${activeSessions.map(readableItemParam).join(',')}`);
    }
    queryParts.push(`layout=${layoutParamValue(layoutSlots)}`);
    const tabs = layoutTabsParamValue(layoutSlots);
    if (tabs) queryParts.push(`tabs=${tabs}`);
  }
  const remaining = params.toString();
  if (remaining) queryParts.push(remaining);
  const query = queryParts.join('&');
  history.replaceState(null, '', `${location.pathname}${query ? `?${query}` : ''}${location.hash}`);
}

function syncInitialLayoutUrl() {
  updateActiveSessionParam();
}
function menuCommand(label, action, options = {}) {
  const command = {type: 'command', label, action, ...options};
  if (command.keepOpen === undefined && Object.prototype.hasOwnProperty.call(options, 'checked')) {
    command.keepOpen = true;
  }
  return command;
}

function menuSubmenu(label, items, options = {}) {
  return {type: 'submenu', label, items, ...options};
}

function menuSeparator() {
  return {type: 'separator'};
}

function menuGroups(...groups) {
  const items = [];
  for (const group of groups) {
    const commands = (Array.isArray(group) ? group : [group]).filter(Boolean);
    if (!commands.length) continue;
    if (items.length) items.push(menuSeparator());
    items.push(...commands);
  }
  return items;
}

function layoutMenuCommand(mode) {
  const normalized = normalizeLayoutMode(mode);
  const detail = normalized === 'single'
    ? t('menu.view.layout.single.detail', {name: fileExplorerLabel()})
    : normalized === 'split'
      ? t('menu.view.layout.split.detail', {name: fileExplorerLabel()})
      : '';
  return menuCommand(t(`menu.view.layout.${normalized}`), () => applyLayoutMode(normalized), {detail});
}

const aboutLinkedInUrl = 'https://www.linkedin.com/in/keiven/';

function aboutDateTimeText() {
  if (bootstrap.versionCommitTime) return bootstrap.versionCommitTime;
  try {
    return new Date().toLocaleString([], {dateStyle: 'medium', timeStyle: 'medium'});
  } catch (_) {
    return new Date().toString();
  }
}

function openAboutLinkedIn() {
  window.open(aboutLinkedInUrl, '_blank', 'noopener,noreferrer');
}

function aboutCommitShaText() {
  return bootstrap.versionCommit || bootstrap.commitSha || bootstrap.commit_sha || bootstrap.gitSha || bootstrap.git_sha || '';
}

function aboutBrandHtml() {
  return `<span class="about-brand-yo" style="--yolo-rotate-delay: ${esc(yoloRotationDelay())}">${esc(t('brand.wordmark.yo'))}</span><span class="about-brand-lo">${esc(t('brand.wordmark.lo'))}</span><span class="about-brand-m">m</span><span class="about-brand-u">u</span><span class="about-brand-x">x</span>`;
}

function showAboutModal() {
  const modal = document.getElementById('modal');
  const title = document.getElementById('modalTitle');
  const body = document.getElementById('modalBody');
  const close = document.getElementById('closeModal');
  if (!modal || !title || !body) return;
  title.textContent = t('menu.help.about');
  if (close) {
    close.title = t('common.close');
    close.setAttribute('aria-label', t('common.close'));
  }
  modal.classList.add('about-open');
  const version = bootstrap.version || '';
  const sha = aboutCommitShaText();
  body.innerHTML = `<div class="about-modal">
    <div class="about-brand-row">${aboutBrandHtml()}${version ? `<span class="about-version">${esc(version)}</span>` : ''}</div>
    <dl class="about-details">
      <div><dt>${esc(t('menu.help.about.datetime'))}</dt><dd>${esc(aboutDateTimeText())}</dd></div>
      <div><dt>SHA</dt><dd>${esc(sha || t('common.unknown'))}</dd></div>
      <div><dt>${esc(t('menu.help.about.version'))}</dt><dd>${esc(version || t('common.unknown'))}</dd></div>
    </dl>
    <a class="about-author" href="${esc(aboutLinkedInUrl)}" target="_blank" rel="noopener noreferrer">${esc(t('menu.help.about.author'))}</a>
  </div>`;
  modal.classList.add('open');
}

function currentActiveMenuItem() {
  if (focusedPanelItem && itemIsActivePaneTab(focusedPanelItem)) return focusedPanelItem;
  if (focusedTerminal && itemIsActivePaneTab(focusedTerminal)) return focusedTerminal;
  return activePaneItems()[0] || null;
}

function currentSessionActionTarget() {
  const current = currentActiveMenuItem();
  if (isTmuxSession(current)) return current;
  if (isTmuxSession(lastFocusedTmuxSession) && activeSessions.includes(lastFocusedTmuxSession)) return lastFocusedTmuxSession;
  const activeTmuxSessions = activeSessions.filter(isTmuxSession);
  return activeTmuxSessions.length === 1 ? activeTmuxSessions[0] : null;
}

function orderedPaneItems(items = activePaneItems()) {
  const unique = [];
  for (const group of [
    items.filter(isTmuxSession),
    items.filter(isFileEditorItem),
    items.filter(item => !isTmuxSession(item) && !isFileEditorItem(item)),
  ]) {
    for (const item of group) {
      if (!unique.includes(item)) unique.push(item);
    }
  }
  return unique;
}

function menuTabDetail(item) {
  const type = tabTypeForItem(item);
  if (type?.detail) return type.detail(item);
  const detail = tabMenuDetailText(item, transcriptMeta.sessions?.[item]);
  // A non-numeric tmux session name (e.g. "PA exploration") is shown in the tab label only as its
  // assigned number (e.g. "9"), so the real name is otherwise invisible. Surface it in the menu/search
  // detail so a result like label "9" reads "9 · PA exploration · main · …" and is identifiable.
  if (numericSessionName(item) === null) return detail ? `${item} · ${detail}` : String(item);
  return detail;
}

function menuTabRowHtml(item, options = {}) {
  const type = tabTypeForItem(item);
  if (type?.rowHtml) return type.rowHtml(item, options);
  const info = transcriptMeta.sessions?.[item];
  const auto = autoApproveStates.get(item)?.enabled === true;
  const state = sessionState(item, info);
  const pr = displayPullRequest(info);
  const desc = sessionTabDescription(item, info);
  const detailHtml = desc ? `<span class="session-button-dir tab-inline-detail">${esc(desc)}</span>` : '';
  return `<span class="pane-tab-core">${yoloMarkerHtml(item, auto, {enabledOnly: false, toggle: options.toggleYolo === true && !readOnlyMode, yoloWorking: sessionYoloIsWorking(item)})}<span class="session-button-prefix">${sessionNumberNameHtml(item)}</span>
    <span class="session-button-text">${state ? sessionStateHtml(state) : ''}${defaultBranchBadgeHtml(item, info)}${pullRequestCompactBadgesHtml(item, pr)}${detailHtml}</span></span>`;
}

function menuTabCommand(item, options = {}) {
  const slot = slotForSession(item);
  const visible = itemIsActivePaneTab(item);
  const active = item === currentActiveMenuItem();
  const detail = options.detail || (visible ? menuTabDetail(item) : (itemIsBackgroundPaneTab(item) ? t('menu.tabs.minimizedDetail') : t('menu.tabs.inactiveDetail')));
  return menuCommand(itemLabel(item), () => {
    if (slot && visible && !options.openAsPane) return activatePaneTab(slot, item, {userInitiated: true});
    return selectSession(item, {userInitiated: true});
  }, {
    checked: options.checked ?? active,
    detail: '',
    ariaLabel: [itemLabel(item), detail].filter(Boolean).join(' - '),
    html: stripTitleAttrs(menuTabRowHtml(item, {...options, menu: true})),
    className: 'app-menu-tab-command',
    targetItem: item,
  });
}

function tmuxSessionActionCommands(session, options = {}) {
  const hasSession = isTmuxSession(session);
  const autoPayload = hasSession ? autoApproveStates.get(session) : null;
  const autoHere = hasSession ? autoApproveEnabledHere(autoPayload) : false;
  const includeYolo = options.includeYolo !== false;
  const includeKill = options.includeKill !== false;
  const readonlyDetail = t('menu.common.adminOnly');
  const focusDetail = hasSession ? menuTabDetail(session) : t('menu.tmux.focusSessionFirst');
  const visibleDetail = readOnlyMode ? readonlyDetail : (hasSession ? '' : t('menu.tmux.noTabFocused'));
  const yoloLabel = hasSession
    ? t(autoHere ? 'menu.tmux.yolo.disableFor' : 'menu.tmux.yolo.enableFor', {session})
    : t(autoHere ? 'menu.tmux.yolo.disable' : 'menu.tmux.yolo.enable');
  const renameLabel = hasSession ? t('menu.tmux.rename.for', {session}) : t('menu.tmux.rename');
  const renameAction = options.renameAction || (() => renameTmuxSession(session));
  const commands = [];
  if (includeYolo) commands.push(menuCommand(yoloLabel, async () => {
      if (!hasSession) return;
      await toggleAutoApprove(session);
      renderSessionButtons();
      renderPaneTabStrips();
    }, {
      checked: autoHere,
      disabled: readOnlyMode || !hasSession,
      detail: visibleDetail,
      iconHtml: hasSession ? yoloMarkerHtml(session, autoHere, {enabledOnly: false, yoloWorking: sessionYoloIsWorking(session)}) : '',
      ariaLabel: [yoloLabel, hasSession ? focusDetail : t('menu.tmux.focusSessionFirst')].filter(Boolean).join(' - '),
    }));
  commands.push(
    menuCommand(renameLabel, renameAction, {
      disabled: readOnlyMode || !hasSession,
      detail: visibleDetail,
      ariaLabel: [renameLabel, focusDetail].filter(Boolean).join(' - '),
    })
  );
  if (includeKill) commands.push(tmuxSessionKillCommand(session));
  return commands;
}

function tmuxSessionKillCommand(session) {
  const hasSession = isTmuxSession(session);
  const readonlyDetail = t('menu.common.adminOnly');
  const focusDetail = hasSession ? menuTabDetail(session) : t('menu.tmux.focusSessionFirst');
  const visibleDetail = readOnlyMode ? readonlyDetail : (hasSession ? '' : t('menu.tmux.noTabFocused'));
  const label = hasSession ? t('menu.tmux.kill.for', {session}) : t('menu.tmux.kill');
  return menuCommand(label, () => killTmuxSession(session), {
    disabled: readOnlyMode || !hasSession,
    detail: visibleDetail,
    ariaLabel: [label, focusDetail].filter(Boolean).join(' - '),
  });
}

function yoloRulePath() {
  return yoloRulesPayload.path
    || nestedSetting(clientSettings, 'yolo.rule_file_path', nestedSetting(clientSettingsDefaults, 'yolo.rule_file_path', '~/.config/yolomux/yolo-rules.yaml'));
}

function settingsConfigPath() {
  return clientSettingsPayload.path || clientSettingsPayload.display_path || '~/.config/yolomux/settings.yaml';
}

// Map the global theme mode to the terminal_theme setting value for the lockstep View -> Theme toggle.
function terminalThemeSettingForGlobalMode(mode) {
  if (mode === 'system') return 'follow-app';
  if (mode === 'light') return 'light';
  return 'dark';
}

// Apply a resolved global theme mode live and persist it — shared by the one-click Theme submenu
// (setGlobalThemeMode) and the View cycle shortcut (cycleGlobalThemeSetting). #258: APPLY live (the menu
// used to only save the patch, so body.theme-* never flipped). #261: do NOT pin appearance.terminal_theme
// — the terminal keeps its own setting (default follow-app/System) and follows the app on its own.
function applyAndSaveGlobalTheme(next) {
  globalThemeMode = next;
  applyGlobalThemeMode({updateEditor: true, updateTerminals: true});
  renderSessionButtons();  // rebuild the menu bar so the View -> Theme active marker tracks the new mode
  return saveSettingsPatch(settingPatch('appearance.theme', next))
    .then(() => {
      statusEl.textContent = `theme: ${globalThemeLabel(next)}`;
    })
    .catch(error => {
      statusErr(`theme save failed: ${esc(error)}`);
      refreshSettings({force: true});
    });
}

// One-click from the Theme submenu: any target (system/dark/light) applies in one click, both directions.
function setGlobalThemeMode(mode) {
  return applyAndSaveGlobalTheme(normalizeGlobalThemeMode(mode));
}

function cycleGlobalThemeSetting() {
  return applyAndSaveGlobalTheme(nextGlobalThemeMode());
}

function yoloRuleStatusDetail() {
  const source = yoloRulesPayload.source || 'unknown';
  const count = Number(yoloRulesPayload.rule_count || 0);
  const countText = tPlural('menu.yolo.ruleCount', count);
  const dryRun = yoloRulesPayload.dry_run ? t('menu.yolo.dryRunSuffix') : '';
  return yoloRulesPayload.error
    ? t('menu.yolo.errorDetail', {error: yoloRulesPayload.error})
    : t('menu.yolo.statusDetail', {source, rules: countText, dryRun});
}

async function openYoloRuleFile() {
  if (readOnlyMode) {
    statusErr('readonly access cannot create YOLO rule files');
    return;
  }
  try {
    const payload = await apiFetchJson('/api/yolo-rules/open', {method: 'POST'});
    yoloRulesPayload = payload;
    renderPreferencesPanels();
    await openFileInEditor(payload.path || yoloRulePath(), {name: basenameOf(payload.path || yoloRulePath())});
    statusEl.textContent = t('status.openedYoloRule');
  } catch (error) {
    statusErr(`open YOLO rule file failed: ${esc(error)}`);
  }
}

async function reloadYoloRules() {
  try {
    const payload = await apiFetchJson('/api/yolo-rules/reload', {method: 'POST'});
    yoloRulesPayload = payload;
    renderPreferencesPanels();
    const level = payload.error ? 'error' : '';
    statusEl.innerHTML = payload.error
      ? `<span class="err">YOLO rule reload failed: ${esc(payload.error)}</span>`
      : `<span class="ok">reloaded YOLO rules</span>`;
    showToast('YOLO rules', payload.error || yoloRuleStatusDetail(), {level});
  } catch (error) {
    statusErr(`reload YOLO rules failed: ${esc(error)}`);
  }
}

async function refreshYoloRulesStatus(options = {}) {
  try {
    const payload = await apiFetchJson('/api/yolo-rules');
    yoloRulesPayload = payload;
    renderPreferencesPanels();
    return payload;
  } catch (error) {
    if (!options.silent) statusErr(`YOLO rule status failed: ${esc(error)}`);
    return null;
  }
}

function tmuxYoloMenuItems() {
  return [
    menuCommand(t('menu.yolo.openRuleFile'), openYoloRuleFile, {
      disabled: readOnlyMode,
      detail: compactHomePath(yoloRulePath()),
    }),
    menuCommand(t('menu.yolo.reloadRules'), reloadYoloRules, {
      detail: yoloRuleStatusDetail(),
    }),
  ];
}

function tmuxCurrentYoloCommand(session) {
  const hasSession = isTmuxSession(session);
  const payload = hasSession ? autoApproveStates.get(session) : null;
  const enabled = hasSession ? autoApproveEnabledHere(payload) : false;
  const elsewhere = hasSession ? autoApproveEnabledElsewhere(payload) : false;
  const label = hasSession ? t(enabled ? 'menu.tmux.yo.on' : elsewhere ? 'menu.tmux.yo.elsewhere' : 'menu.tmux.yo.off') : t('menu.tmux.yo.none');
  return menuCommand(label, async () => {
    if (!hasSession) return;
    await toggleAutoApprove(session);
    renderSessionButtons({force: true});
    renderPaneTabStrips();
  }, {
    disabled: readOnlyMode || !hasSession,
    detail: hasSession ? t('menu.tmux.sessionLabel', {session}) : t('menu.tmux.focusTabFirst'),
    iconHtml: hasSession ? yoloMarkerHtml(session, enabled, {enabledOnly: false, yoloWorking: sessionYoloIsWorking(session)}) : '',
    keepOpen: true,
    ariaLabel: hasSession ? t(enabled ? 'menu.tmux.yolo.disableFor' : 'menu.tmux.yolo.enableFor', {session}) : t('menu.tmux.focusTabFirst'),
  });
}

function tmuxSessionViewCommands(session) {
  const hasSession = isTmuxSession(session);
  const active = hasSession && activeSessions.includes(session);
  const focusDetail = hasSession ? menuTabDetail(session) : t('menu.tmux.focusSessionFirst');
  const disabledDetail = hasSession ? t('menu.tmux.openInPaneFirst') : t('menu.tmux.noTabFocused');
  const viewLabel = sessionLabel(session);
  const transcriptName = t('menu.tmux.transcript', {session: viewLabel});
  const summaryName = t('menu.tmux.aiTranscript', {session: viewLabel});
  const eventLogName = t('menu.tmux.eventLog', {session: viewLabel});
  return [
    menuCommand(transcriptName, () => {
      if (active) activateTab(session, 'transcript');
    }, {
      disabled: !active,
      detail: active ? '' : disabledDetail,
      checked: active && panelActiveTabName(session) === 'transcript',
      ariaLabel: [transcriptName, focusDetail].filter(Boolean).join(' - '),
    }),
    menuCommand(summaryName, () => {
      if (active) activateTab(session, 'summary');
    }, {
      disabled: readOnlyMode || !active,
      detail: readOnlyMode ? t('menu.common.adminOnly') : (active ? '' : disabledDetail),
      checked: active && panelActiveTabName(session) === 'summary',
      ariaLabel: [summaryName, focusDetail].filter(Boolean).join(' - '),
    }),
    menuCommand(eventLogName, () => {
      if (active) activateTab(session, 'events');
    }, {
      disabled: !active,
      detail: active ? '' : disabledDetail,
      checked: active && panelActiveTabName(session) === 'events',
      ariaLabel: [eventLogName, focusDetail].filter(Boolean).join(' - '),
    }),
    menuCommand(t('menu.tmux.paneDetails'), () => {
      if (!active) return;
      const panel = document.getElementById(panelDomId(session));
      if (panel) setPanelDetailsCollapsed(panel, !panel.classList.contains('details-collapsed'));
    }, {
      disabled: !active,
      detail: active ? '' : disabledDetail,
      ariaLabel: [t('menu.tmux.paneDetails'), focusDetail].filter(Boolean).join(' - '),
    }),
  ];
}

// The flags/params YOLOmux launches an agent with, shown as the new-session item's detail (e.g.
// "--dangerously-skip-permissions"). Strips the binary name from the launch command; for a plain Term
// it's just the shell ("bash"). Empty when the command carries no extra flags.
function agentLaunchParams(agent) {
  const command = String(agentLaunchCommands[agent] || '').trim();
  if (!command) return '';
  const space = command.indexOf(' ');
  return space >= 0 ? command.slice(space + 1).trim() : command;
}

function newTmuxSessionItems() {
  return ['claude', 'codex', 'term'].map(agent => {
    const available = availableAgents.has(agent);
    const capped = visibleSessions.length >= maxSessionTabs;
    // #39: an installed agent that is not logged in is greyed with its login command, instead of
    // silently starting a session that the CLI will reject for auth.
    const loggedOut = available && !agentLoggedIn(agent);
    // Drop the "+" prefix (label is just the agent name); when launchable, the detail shows the params
    // actually passed (the --dangerously-* flags in YOLO mode) so you can see what command will run.
    return menuCommand(agentName(agent), () => createNextSession(agent), {
      iconHtml: agentIcon(agent),
      disabled: readOnlyMode || !available || loggedOut || capped,
      detail: readOnlyMode
        ? t('menu.common.adminOnly')
        : (!available
          ? t('menu.tmux.agentUnavailable', {name: agentName(agent)})
          : (loggedOut
            ? t('menu.tmux.runLogin', {command: agentLoginCommand(agent)})
            : (capped ? t('menu.tmux.limitReached') : agentLaunchParams(agent)))),
    });
  });
}

function tabCommandsForItems(items, options) {
  return items.map(item => menuTabCommand(item, options));
}

// a PR number in any of the forms a user types (#N, PR#N, PR N, N).
function prNumberSearchForms(number) {
  if (!number) return [];
  return [`#${number}`, `PR#${number}`, `PR ${number}`, String(number)];
}

function finderSearchAliases(item) {
  if (!isFileExplorerItem(item)) return [];
  return ['Finder', 'File Explorer', t('finder.label.finder'), t('finder.label.explorer')];
}

function tabSearchFields(item) {
  const info = transcriptMeta.sessions?.[item] || {};
  const filePath = fileItemPath(item) || '';
  const pr = displayPullRequest(info);
  // also index the repo's OTHER-branch PRs/branches/Linear IDs (the same data YO!info shows),
  // so a session is findable by ANY PR (e.g. #10289 on a non-current branch), branch name, or Linear ID
  // — not just its current-branch PR. Already in the metadata payload, so no extra fetch.
  const otherBranches = info.project?.git?.other_branches?.branches || [];
  return [
    item,
    itemLabel(item),
    sessionLabel(item),
    menuTabDetail(item),
    filePath,
    compactHomePath(filePath),
    info.cwd,
    info.branch,
    info.status,
    info.description,
    info.goal,
    ...finderSearchAliases(item),
    pr?.title,
    pr?.url,
    pr?.number ? 'PR' : '',
    ...prNumberSearchForms(pr?.number),
    ...(Array.isArray(info.linear) ? info.linear : []),
    ...otherBranches.flatMap(branch => [
      branch.name,
      branch.pull_request?.title,
      ...prNumberSearchForms(branch.pull_request?.number),
      ...(Array.isArray(branch.linear_ids) ? branch.linear_ids : []),
    ]),
  ].filter(Boolean);
}

function tabSearchScore(item, query = tabsMenuSearchText) {
  if (!String(query || '').trim()) return 0;
  return fuzzySearchScore(query, tabSearchFields(item));
}

function filterTabItemsForSearch(items, query = tabsMenuSearchText) {
  if (!String(query || '').trim()) return items;
  return items
    .map((item, index) => ({item, index, score: tabSearchScore(item, query)}))
    .filter(entry => Number.isFinite(entry.score))
    .sort((left, right) => right.score - left.score || left.index - right.index)
    .map(entry => entry.item);
}

function backgroundTabMenuItems() {
  return tabCommandsForItems(filterTabItemsForSearch(backgroundTabItems()), {
    checked: false,
    detail: t('menu.tabs.minimized'),
    openAsPane: true,
    toggleYolo: true,
  });
}

function inactiveTabMenuItems() {
  return tabCommandsForItems(filterTabItemsForSearch(inactiveTabItems()), {
    checked: false,
    detail: t('menu.tabs.notInPane'),
    openAsPane: true,
    toggleYolo: true,
  });
}

// P0 menu-bar: the Tabs navigator's order. 'attention' floats needs-* sessions to the top (the "Needs
// me" view) using the shared state priority; 'name' sorts by label; 'default' keeps the
// tmux/editors/other grouping. Stable (preserves the incoming order within equal keys).
function tabMenuSortPriority(item) {
  if (!isTmuxSession(item)) return 50;   // non-session tabs (editors/Finder/Prefs) sit after sessions
  const priority = sessionState(item)?.priority;
  return Number.isFinite(priority) ? priority : 50;
}

function sortTabItemsForMenu(items) {
  if (tabsMenuSortMode === 'attention') {
    return items
      .map((item, index) => ({item, index}))
      .sort((a, b) => tabMenuSortPriority(a.item) - tabMenuSortPriority(b.item) || a.index - b.index)
      .map(entry => entry.item);
  }
  if (tabsMenuSortMode === 'name') {
    return items
      .map((item, index) => ({item, index}))
      .sort((a, b) => String(itemLabel(a.item)).localeCompare(String(itemLabel(b.item))) || a.index - b.index)
      .map(entry => entry.item);
  }
  return items;
}

function setTabsMenuSortMode(mode) {
  tabsMenuSortMode = tabsMenuSortModes.includes(mode) ? mode : 'default';
  storageSet('yolomux.tabsMenuSort.v1', tabsMenuSortMode);
  renderSessionButtons({force: true});
}

function tabMenuItems(openItems = orderedPaneItems(activePaneItems())) {
  const query = tabsMenuSearchText.trim();
  const filteredOpenItems = sortTabItemsForMenu(filterTabItemsForSearch(openItems, query));
  const groupedItems = menuGroups(
    filteredOpenItems.map(item => menuTabCommand(item, {toggleYolo: true})),
    backgroundTabMenuItems(),
    inactiveTabMenuItems()
  );
  const resultItems = groupedItems.length ? groupedItems : [menuCommand(t('menu.tabs.noMatch'), null, {disabled: true})];
  return resultItems;
}

function fileMenuVirtualCommand(item, detail) {
  return menuCommand(itemLabel(item), () => selectSession(item, {userInitiated: true}), {
    checked: itemInLayout(item),
    detail,
    iconHtml: tabTypeIconHtml(item, {menu: true}),
    targetItem: item,
  });
}

function appMenuTree() {
  const activeTmux = currentSessionActionTarget();
  const openItems = orderedPaneItems(activePaneItems());
  const yoloCount = yoloEnabledSessions().length;
  const debugMenuItems = debugModeEnabled ? [
    fileMenuVirtualCommand(debugPaneItemId, t('menu.file.debug.detail')),
  ] : [];
  return [
    {
      id: 'file',
      label: t('menu.file'),
      items: menuGroups(
        [
          menuCommand(fileExplorerLabel(), () => toggleFinderPane(), {
            checked: itemInLayout(fileExplorerItemId),
            detail: t('menu.file.browseFiles'),
            iconHtml: tabTypeIconHtml(fileExplorerItemId, {menu: true}),
            targetItem: fileExplorerItemId,
          }),
          fileMenuVirtualCommand(infoItemId, t('menu.file.info.detail')),
          // #40: YO!agent is now a sub-tab of the merged YO!info pane — this entry opens that pane on it.
          menuCommand(yoagentTabLabel(), () => openInfoSubTab('yoagent'), {
            checked: itemInLayout(infoItemId) && infoPanelSubTab === 'yoagent',
            detail: t('menu.file.yoagent.detail'),
            iconHtml: appMenuUiIcon('yoagent'),
          }),
          menuCommand(t('menu.file.openFile'), openFileQuickOpen, {
            detail: appShortcutText('P'),
            iconHtml: appMenuUiIcon('document'),
          }),
          menuCommand(t('menu.file.preferences'), () => selectSession(prefsItemId, {userInitiated: true}), {
            checked: itemInLayout(prefsItemId),
            detail: compactHomePath(settingsConfigPath()),
            iconHtml: tabTypeIconHtml(prefsItemId, {menu: true}),
            targetItem: prefsItemId,
          }),
          ...debugMenuItems,
        ],
        [
          menuCommand(t('menu.file.logout'), logOut, {
            detail: t('menu.file.logout.detail'),
            iconHtml: appMenuUiIcon('logout'),
          }),
        ]
      ),
    },
    {
      id: 'view',
      label: t('menu.view'),
      items: [
        menuCommand(tabMetaVisible ? t('menu.view.tabMeta.hide') : t('menu.view.tabMeta.show'), toggleTabMetadata, {
          checked: tabMetaVisible,
          detail: t('menu.view.tabMeta.detail'),
          iconHtml: appMenuUiIcon('tab-meta', tabMetaVisible),
        }),
        menuCommand(t('menu.view.alert'), toggleNotifications, {
          checked: notificationsEnabled,
          disabled: readOnlyMode,
          detail: readOnlyMode ? t('menu.view.alert.adminDetail') : '',
          iconHtml: appMenuUiIcon('notify', notificationsEnabled),
        }),
        menuCommand(t('menu.view.refresh'), refreshAll, {
          iconHtml: appMenuUiIcon('refresh'),
        }),
        menuSubmenu(t('menu.view.theme'), [
          menuCommand(t('menu.view.theme.system'), () => setGlobalThemeMode('system'), {checked: normalizeGlobalThemeMode() === 'system', detail: t('menu.view.theme.system.detail', {mode: t('menu.view.theme.' + resolvedGlobalThemeMode())})}),
          menuCommand(t('menu.view.theme.dark'), () => setGlobalThemeMode('dark'), {checked: normalizeGlobalThemeMode() === 'dark'}),
          menuCommand(t('menu.view.theme.light'), () => setGlobalThemeMode('light'), {checked: normalizeGlobalThemeMode() === 'light'}),
        ]),
        menuSubmenu(t('menu.view.layout'), layoutModeValues.map(layoutMenuCommand)),
        menuSubmenu(t('menu.view.sortTabs'), [
          menuCommand(t('menu.view.sortTabs.default'), () => setTabsMenuSortMode('default'), {checked: tabsMenuSortMode === 'default', detail: t('menu.view.sortTabs.default.detail')}),
          menuCommand(t('menu.view.sortTabs.attention'), () => setTabsMenuSortMode('attention'), {checked: tabsMenuSortMode === 'attention', detail: t('menu.view.sortTabs.attention.detail')}),
          menuCommand(t('menu.view.sortTabs.name'), () => setTabsMenuSortMode('name'), {checked: tabsMenuSortMode === 'name'}),
        ]),
      ],
    },
    {
      id: 'tmux',
      label: 'tmux',
      items: menuGroups(
        [tmuxCurrentYoloCommand(activeTmux)],
        newTmuxSessionItems(),
        tmuxSessionViewCommands(activeTmux),
        [
          ...tmuxSessionActionCommands(activeTmux, {includeYolo: false}),
          menuCommand(t('menu.tmux.resume'), null, {
            disabled: true,
            detail: t('menu.common.comingSoon'),
          }),
        ],
        [
          menuSubmenu(t('menu.tmux.yoloSubmenu'), tmuxYoloMenuItems()),
        ]
      ),
    },
    {
      id: 'tabs',
      label: t('menu.tabs'),
      badgeText: yoloCount ? String(yoloCount) : '',
      badgeTitle: yoloCount ? tPlural('menu.tabs.yoloBadge', yoloCount) : '',
      items: tabMenuItems(openItems),
    },
    {
      id: 'help',
      label: t('menu.help'),
      items: menuGroups(
        [menuCommand(t('menu.help.commandPalette'), openCommandPalette, {
          detail: appShortcutText('P', {shift: true}),
        })],
        [
          menuCommand(`YOLOmux ${bootstrap.version || ''}`.trim(), null, {
            disabled: true,
            detail: bootstrap.versionCommitTime ? t('menu.help.lastCommit', {time: bootstrap.versionCommitTime}) : '',
          }),
          menuCommand(t('menu.help.shortcuts'), openKeyboardShortcutsOverlay, {
            detail: '?',
          }),
          menuCommand(t('menu.help.openReadme'), openProjectReadme, {
            disabled: !projectReadmePath(),
            detail: t('menu.help.localReadme'),
          }),
        ],
        [
          menuCommand(t('menu.help.about'), showAboutModal),
        ]
      ),
    },
  ];
}

function appMenuIsOpen() {
  return Boolean(sessionButtons?.querySelector('.app-menu.open'));
}

function renderSessionButtons(options = {}) {
  if (!sessionButtons) return;
  if (!options.force && appMenuIsOpen()) {
    scheduleTopbarMetricsUpdate();
    return;
  }
  const openMenu = sessionButtons.querySelector('.app-menu.open');
  if (openMenu) {
    openAppMenuId = openMenu.dataset.appMenu || null;
  } else {
    openAppMenuId = null;
    openAppMenuPinned = false;
    openAppMenuOpenedAt = 0;
  }
  sessionButtons.innerHTML = '';
  sessionButtons.ondragover = event => {
    const payload = dragPayload(event);
    if (!payload?.session || !itemInLayout(payload.session)) return;
    event.preventDefault();
    event.dataTransfer.dropEffect = 'move';
    clearDropPreview();
    sessionButtons.classList.add(CLS.dragOver);
  };
  sessionButtons.ondragleave = event => {
    if (!sessionButtons.contains(event.relatedTarget)) sessionButtons.classList.remove(CLS.dragOver);
  };
  sessionButtons.ondrop = event => {
    const payload = dragPayload(event);
    sessionButtons.classList.remove(CLS.dragOver);
    if (!payload?.session) return;
    event.preventDefault();
    event.stopPropagation();
    removeSessionFromLayout(payload.session);
  };
  sessionButtons.classList.remove(CLS.dragOver);
  sessionButtons.appendChild(createAppMenuBar());
  sessionButtons.appendChild(createTopbarNav());
  sessionButtons.appendChild(createTopbarSearch());
  updateEditorNavButtons();   // sync ←/→ disabled state to the global editorNav stack after (re)assembly
  // Topbar right group: Language | Activity (activity pinned far-right). #257: the theme switcher was
  // removed as redundant — theme is set via View -> Theme and the Preferences Global color theme.
  sessionButtons.appendChild(createTopbarLanguageSwitcher());
  sessionButtons.appendChild(createTopbarActivityStatus());
  updateTopbarActivityStatus();
  scheduleTopbarMetricsUpdate();
}

// #52: the wordmark is server-rendered (YO/LO/m/u/x); localize the YO/LO glyphs client-side so a
// Chinese locale shows 優樂mux / 优乐mux (優/优 boxed-green, 樂/乐 green) and updates on a language switch
// without a reload. The m/u/x colorful spans and the version are untouched.
function renderBrandWordmark() {
  for (const yo of document.querySelectorAll('.brand-title .brand-yolo')) yo.textContent = t('brand.wordmark.yo');
  for (const lo of document.querySelectorAll('.brand-title .brand-lo')) lo.textContent = t('brand.wordmark.lo');
}

function createAppMenuBar() {
  const bar = document.createElement('nav');
  bar.className = 'app-menu-bar';
  bar.setAttribute('aria-label', t('menu.bar.aria'));
  bar.setAttribute('role', 'menubar');
  for (const menu of appMenuTree()) bar.appendChild(createAppMenu(menu));
  return bar;
}

// the editor back/forward history control lives in the GLOBAL topbar (left of the search
// box), not per editor pane — it's one file-history control for the whole window, like a browser's.
// Buttons are always visible; updateEditorNavButtons() toggles their disabled state from editorNav.
function createTopbarNav() {
  const group = document.createElement('div');
  group.className = 'topbar-nav';
  group.setAttribute('role', 'group');
  group.setAttribute('aria-label', t('editor.nav.aria'));
  const back = makeButton({
    id: 'topbarNavBack',
    className: 'topbar-nav-button',
    title: t('editor.nav.back'),
    ariaLabel: t('editor.nav.back'),
    disabled: true,
    label: '←',
    onClick: event => { event.preventDefault(); editorNavBack(); },
  });
  const forward = makeButton({
    id: 'topbarNavForward',
    className: 'topbar-nav-button',
    title: t('editor.nav.forward'),
    ariaLabel: t('editor.nav.forward'),
    disabled: true,
    label: '→',
    onClick: event => { event.preventDefault(); editorNavForward(); },
  });
  group.append(back, forward);
  return group;
}

// Universal search affordance in the topbar's empty middle gap: a launcher that
// opens the existing unified palette (files/tabs/settings by default, `>` for
// commands) — it reuses openFileQuickOpen, it does not fork the palette logic.
function createTopbarSearch() {
  const isMac = /Mac|iP(hone|ad|od)/.test(navigator.platform || navigator.userAgent || '');
  const mod = isMac ? 'Cmd' : 'Ctrl';
  const button = makeButton({
    id: 'topbarSearch',
    className: 'topbar-search',
    ariaLabel: t('topbar.search.aria'),
    title: t('topbar.search.title', {mod}),
  });
  const icon = document.createElement('span');
  icon.className = 'topbar-search-icon';
  icon.setAttribute('aria-hidden', 'true');
  icon.textContent = '⌕';
  const label = document.createElement('span');
  label.className = 'topbar-search-label';
  label.textContent = t('topbar.search.label');
  const hint = document.createElement('kbd');
  hint.className = 'topbar-search-hint';
  hint.textContent = isMac ? '⌘P' : 'Ctrl+P';
  button.append(icon, label, hint);
  button.addEventListener('click', () => openFileQuickOpen());
  return button;
}

// Phase 1: a top-right language switcher (entry point #2). It writes the SAME general.language
// setting as the Preferences picker and applies the locale optimistically (no settings-poll round-trip).
// 'system' resolves against navigator.language; the <select> shows the raw pref so 'system' reads as Auto.
function createTopbarLanguageSwitcher() {
  const pref = String(initialSetting('general.language', 'system'));
  const select = document.createElement('select');
  select.className = 'topbar-language';
  select.setAttribute('aria-label', t('language.switcher'));
  select.title = t('language.switcher');
  for (const choice of i18nLocaleChoices()) {
    const option = document.createElement('option');
    option.value = choice.value;
    option.textContent = choice.label;
    if (choice.value === pref) option.selected = true;
    select.appendChild(option);
  }
  select.addEventListener('change', () => {
    const value = select.value;
    applyLocale(resolveLocalePref(value));
    if (readOnlyMode) return;
    saveSettingsPatch(settingPatch('general.language', value))
      .catch(error => { statusErr(`settings save failed: ${esc(error)}`); refreshSettings({force: true}); });
  });
  return select;
}

function appMenuAnchorInlineSize(popover) {
  const anchor = popover?.parentElement?.querySelector?.(':scope > .app-menu-button, :scope > .app-menu-command');
  return Math.ceil(anchor?.getBoundingClientRect?.().width || 0);
}

function measureAppMenuContentWidth(popover) {
  if (!popover?.cloneNode || !document.body) return null;
  const clone = popover.cloneNode(true);
  clone.style.position = 'fixed';
  clone.style.insetInlineStart = '0';
  clone.style.insetBlockStart = '0';
  clone.style.transform = 'translateX(-100%)';
  clone.style.visibility = 'hidden';
  clone.style.pointerEvents = 'none';
  clone.style.opacity = '0';
  clone.style.width = 'max-content';
  clone.style.minWidth = '0';
  clone.style.maxWidth = 'none';
  clone.style.maxHeight = 'none';
  clone.style.removeProperty('--app-menu-fit-width');
  clone.style.removeProperty('--app-menu-fit-offset');
  // C14: a standalone submenu popover (measured on its own, with no .open parent) matches the base
  // `.app-submenu-popover { display:none }` rule and would measure 0 — force it visible for measurement.
  if (clone.classList?.contains('app-submenu-popover')) clone.style.display = 'block';
  clone.querySelectorAll('.app-submenu-popover').forEach(submenu => {
    submenu.style.display = 'block';
    submenu.style.width = 'max-content';
    submenu.style.minWidth = '0';
    submenu.style.maxWidth = 'none';
  });
  clone.querySelectorAll('.app-menu-command').forEach(command => {
    command.style.width = 'max-content';
    command.style.minWidth = '0';
    command.style.maxWidth = 'none';
  });
  clone.querySelectorAll('.app-menu-rich, .pane-tab-core, .session-button-text, .session-button-name, .session-button-dir, .session-button-detail, .tab-inline-detail, .pane-tab-info-label').forEach(node => {
    node.style.maxWidth = 'none';
    node.style.overflow = 'visible';
    node.style.textOverflow = 'clip';
    node.style.whiteSpace = 'nowrap';
  });
  // C14: the command label + detail spans were OMITTED above, so their truncation CSS (overflow:hidden,
  // nowrap, min-width:0 / max-width:42ch) collapsed them in max-content sizing and the menu was measured
  // to the LABELS — ellipsizing the longer detail sub-lines. Un-clip them so each command's full one-line
  // width is counted. Keep the detail's 42ch cap so a genuinely longer detail still ellipsizes by design.
  clone.querySelectorAll('.app-menu-label').forEach(node => {
    node.style.maxWidth = 'none';
    node.style.minWidth = 'auto';
    node.style.overflow = 'visible';
    node.style.textOverflow = 'clip';
    node.style.whiteSpace = 'nowrap';
  });
  clone.querySelectorAll('.app-menu-detail').forEach(node => {
    node.style.minWidth = 'auto';
    node.style.overflow = 'visible';
    node.style.textOverflow = 'clip';
    node.style.whiteSpace = 'nowrap';
  });
  document.body.appendChild(clone);
  const width = Math.ceil(clone.getBoundingClientRect().width || clone.scrollWidth || 0);
  clone.remove();
  return width || null;
}

function fitAppMenuPopover(popover) {
  if (!popover) return;
  popover.style.setProperty('--app-menu-fit-offset', '0px');
  popover.style.removeProperty('--app-menu-fit-width');
  const measured = measureAppMenuContentWidth(popover);
  const anchorWidth = appMenuAnchorInlineSize(popover);
  const desiredWidth = Math.max(anchorWidth, measured || 0);
  if (desiredWidth > 0) popover.style.setProperty('--app-menu-fit-width', `${desiredWidth}px`);

  const rect = popover.getBoundingClientRect();
  const viewportRight = viewportBounds(popoverEdgeGapPx()).right;
  if (!rect.width || !viewportRight) return;
  const overflow = Math.max(0, rect.right - viewportRight);
  if (!overflow) return;
  const maxShift = Math.max(0, rect.width - anchorWidth);
  popover.style.setProperty('--app-menu-fit-offset', `${-Math.min(overflow, maxShift)}px`);
  // C14: a cold first measurement taken before web fonts settle sizes with fallback-font metrics and can
  // come out too narrow. Re-fit ONCE when fonts are ready (guarded so it schedules a single time) so the
  // very first menu open is corrected without waiting for a reopen.
  if (document.fonts?.ready && !popover._appMenuFontsRefit) {
    popover._appMenuFontsRefit = true;
    document.fonts.ready.then(() => { if (popover.isConnected) fitAppMenuPopover(popover); }).catch(() => {});
  }
}

function createAppMenu(menu) {
  const wrapper = document.createElement('div');
  wrapper.className = 'app-menu';
  wrapper.dataset.appMenu = menu.id;
  const button = document.createElement('button');
  button.type = 'button';
  button.className = 'app-menu-button';
  button.setAttribute('aria-haspopup', 'true');
  button.setAttribute('aria-expanded', openAppMenuId === menu.id ? 'true' : 'false');
  button.setAttribute('role', 'menuitem');
  button.innerHTML = `${esc(menu.label)}${menu.badgeText ? `<span class="app-menu-button-badge" title="${esc(menu.badgeTitle || '')}">${esc(menu.badgeText)}</span>` : ''}`;
  const popover = document.createElement('div');
  popover.className = 'app-menu-popover';
  popover.setAttribute('role', 'menu');
  popover.setAttribute('aria-label', menu.label);
  for (const item of menu.items) popover.appendChild(createAppMenuItem(item));
  fitAppMenuPopover(popover);
  button.addEventListener('click', event => {
    event.preventDefault();
    event.stopPropagation();
    if (wrapper.classList.contains('open')) {
      const openMs = Date.now() - openAppMenuOpenedAt;
      if (openAppMenuPinned && openMs >= menuClickCloseGraceMs) closeAppMenus();
      else openAppMenu(wrapper, {focusFirst: false, pinned: true});
      return;
    }
    openAppMenu(wrapper, {focusFirst: false, pinned: true});
  });
  button.addEventListener('keydown', event => handleAppMenuButtonKeydown(event, wrapper));
  wrapper.append(button, popover);
  if (openAppMenuId === menu.id) wrapper.classList.add('open');
  bindAppMenuHover(wrapper);
  return wrapper;
}

function createAppMenuItem(item) {
  if (item.type === 'separator') {
    const node = document.createElement('div');
    node.className = 'app-menu-separator';
    node.role = 'separator';
    return node;
  }
  if (item.type === 'section') {
    const node = document.createElement('div');
    node.className = 'app-menu-section';
    node.textContent = item.label;
    return node;
  }
  if (item.type === 'submenu') return createAppSubmenu(item);
  return createAppMenuCommand(item);
}

function createAppSubmenu(item) {
  const wrapper = document.createElement('div');
  wrapper.className = 'app-menu-submenu-wrap open';
  const button = createAppMenuCommand({
    label: item.label,
    disabled: item.disabled,
    detail: item.detail,
    className: 'app-menu-submenu-button',
  }, {asSubmenu: true});
  const submenu = document.createElement('div');
  submenu.className = 'app-submenu-popover';
  submenu.setAttribute('role', 'menu');
  submenu.setAttribute('aria-label', item.label);
  for (const child of item.items || []) submenu.appendChild(createAppMenuItem(child));
  fitAppMenuPopover(submenu);
  button.addEventListener('click', event => {
    event.preventDefault();
    event.stopPropagation();
    if (button.disabled) return;
    wrapper.classList.add('open');
    button.setAttribute('aria-expanded', 'true');
  });
  button.addEventListener('keydown', event => {
    if (event.key === 'ArrowRight') {
      event.preventDefault();
      wrapper.classList.add('open');
      button.setAttribute('aria-expanded', 'true');
      focusFirstAppMenuCommand(submenu);
    }
  });
  button.setAttribute('aria-haspopup', 'true');
  button.setAttribute('aria-expanded', 'true');
  wrapper.append(button, submenu);
  return wrapper;
}

function createAppMenuCommand(item, options = {}) {
  const button = document.createElement('button');
  button.type = 'button';
  button.className = ['app-menu-command', item.className || '', options.asSubmenu ? 'has-submenu' : ''].filter(Boolean).join(' ');
  button.setAttribute('role', item.checked !== undefined ? 'menuitemcheckbox' : 'menuitem');
  if (item.checked !== undefined) {
    button.dataset.checked = item.checked ? 'true' : 'false';
    button.setAttribute('aria-checked', item.checked ? 'true' : 'false');
  }
  if (item.disabled) button.disabled = true;
  const ariaLabel = item.ariaLabel || [item.label, item.detail].filter(Boolean).join(' - ');
  if (ariaLabel) button.setAttribute('aria-label', ariaLabel);
  const richHtml = item.html ? stripTitleAttrs(item.html) : '';
  const iconHtml = item.iconHtml ? stripTitleAttrs(item.iconHtml) : '';
  const contentHtml = richHtml
    ? `<span class="app-menu-rich">${richHtml}</span>`
    : `<span class="app-menu-line">${iconHtml ? `<span class="app-menu-icon">${iconHtml}</span>` : ''}<span class="app-menu-label">${esc(item.label)}</span></span>`;
  const detailHtml = item.detail ? `<span class="app-menu-detail" title="${esc(item.detail)}">${esc(item.detail)}</span>` : '';
  button.innerHTML = `<span class="app-menu-check" aria-hidden="true"></span><span class="app-menu-content">${contentHtml}${detailHtml}</span>${options.asSubmenu ? '<span class="app-menu-submenu-arrow" aria-hidden="true">&gt;</span>' : ''}`;
  if (!options.asSubmenu) {
    button.addEventListener('click', event => {
      event.preventDefault();
      event.stopPropagation();
      const autoTarget = event.target.closest('[data-auto-session]');
      if (autoTarget && button.contains(autoTarget)) {
        if (readOnlyMode) {
          statusEl.textContent = t('status.yoloAdminRequired');
          return;
        }
        toggleAutoApprove(autoTarget.dataset.autoSession).then(() => {
          renderSessionButtons({force: true});
          renderPaneTabStrips();
        });
        return;
      }
      runAppMenuCommand(item);
    });
  }
  button.addEventListener('keydown', event => handleAppMenuCommandKeydown(event, button, item, options));
  return button;
}

function runAppMenuCommand(item) {
  if (item.disabled || typeof item.action !== 'function') return;
  const keepOpen = item.keepOpen === true;
  if (!keepOpen) closeAppMenus();
  try {
    Promise.resolve(item.action())
      .then(() => {
        if (keepOpen) renderSessionButtons({force: true});
      })
      .catch(error => {
        statusErr(`menu command failed: ${esc(error)}`);
        if (keepOpen) renderSessionButtons({force: true});
      });
  } catch (error) {
    statusErr(`menu command failed: ${esc(error)}`);
    if (keepOpen) renderSessionButtons({force: true});
  }
}

function appMenuCommands(container) {
  const scope = container.classList?.contains('app-menu')
    ? container.querySelector(':scope > .app-menu-popover')
    : container;
  if (!scope) return [];
  return Array.from(scope.querySelectorAll('.app-menu-command'))
    .filter(button => !button.disabled && button.closest('.app-menu-popover, .app-submenu-popover') === scope);
}

function focusFirstAppMenuCommand(container) {
  appMenuCommands(container)[0]?.focus();
}

function focusAdjacentAppMenuCommand(button, direction) {
  const popover = button.closest('.app-menu-popover, .app-submenu-popover');
  if (!popover) return;
  const commands = appMenuCommands(popover);
  const index = commands.indexOf(button);
  if (!commands.length || index < 0) return;
  const next = commands[(index + direction + commands.length) % commands.length];
  next.focus();
}

function focusAdjacentTopMenu(wrapper, direction) {
  const menus = Array.from(sessionButtons.querySelectorAll('.app-menu'));
  const index = menus.indexOf(wrapper);
  if (index < 0 || !menus.length) return;
  const next = menus[(index + direction + menus.length) % menus.length];
  openAppMenu(next, {focusFirst: false});
  next.querySelector('.app-menu-button')?.focus();
}

function handleAppMenuButtonKeydown(event, wrapper) {
  if (event.key === 'ArrowDown' || event.key === 'Enter' || event.key === ' ') {
    event.preventDefault();
    openAppMenu(wrapper, {focusFirst: true, pinned: true});
  } else if (event.key === 'ArrowRight') {
    event.preventDefault();
    focusAdjacentTopMenu(wrapper, 1);
  } else if (event.key === 'ArrowLeft') {
    event.preventDefault();
    focusAdjacentTopMenu(wrapper, -1);
  } else if (event.key === 'Escape') {
    closeAppMenus();
  }
}

function handleAppMenuCommandKeydown(event, button, item, options = {}) {
  if (event.key === 'ArrowDown') {
    event.preventDefault();
    focusAdjacentAppMenuCommand(button, 1);
  } else if (event.key === 'ArrowUp') {
    event.preventDefault();
    focusAdjacentAppMenuCommand(button, -1);
  } else if (event.key === 'Escape') {
    event.preventDefault();
    closeAppMenus();
    button.closest('.app-menu')?.querySelector('.app-menu-button')?.focus();
  } else if (event.key === 'ArrowLeft') {
    event.preventDefault();
    const submenu = button.closest('.app-submenu-popover');
    if (submenu) {
      submenu.closest('.app-menu-submenu-wrap')?.querySelector(':scope > .app-menu-command')?.focus();
      return;
    }
    const wrapper = button.closest('.app-menu');
    if (wrapper) focusAdjacentTopMenu(wrapper, -1);
  } else if (event.key === 'ArrowRight') {
    event.preventDefault();
    const submenu = button.closest('.app-menu-submenu-wrap')?.querySelector(':scope > .app-submenu-popover');
    if (submenu && options.asSubmenu) {
      focusFirstAppMenuCommand(submenu);
      return;
    }
    const wrapper = button.closest('.app-menu');
    if (wrapper) focusAdjacentTopMenu(wrapper, 1);
  } else if (!options.asSubmenu && (event.key === 'Enter' || event.key === ' ')) {
    event.preventDefault();
    runAppMenuCommand(item);
  }
}

function bindAppMenuHover(wrapper) {
  createHoverPopover({
    anchor: wrapper,
    popover: () => wrapper.querySelector(':scope > .app-menu-popover'),
    stateClass: '',
    canOpen: () => autoFocusEnabled || appMenuIsOpen(),
    showDelay: () => (appMenuIsOpen() ? 0 : menuHoverOpenDelayMs),
    hideDelay: () => menuHoverCloseDelayMs,
    stillActive: () => wrapper.matches?.(':hover'),
    onOpen: () => {
      const menuId = wrapper.dataset.appMenu || '';
      const currentWrapper = document.querySelector(`.app-menu[data-app-menu="${cssEscape(menuId)}"]`) || wrapper;
      if (!currentWrapper.classList.contains('open')) openAppMenu(currentWrapper, {focusFirst: false, pinned: false});
    },
    onClose: () => {
      const menuId = wrapper.dataset.appMenu || '';
      if (!wrapper.matches?.(':hover') && openAppMenuId === menuId) closeAppMenus();
    },
  });
}

function openAppMenu(wrapper, options = {}) {
  if (!wrapper) return;
  closeContextMenus();
  closeOtherSessionPopovers(null, {force: true});
  closeFileImagePreview();
  closeAppMenus(wrapper);
  fitAppMenuPopover(wrapper.querySelector(':scope > .app-menu-popover'));
  wrapper.querySelectorAll(':scope > .app-menu-popover .app-submenu-popover').forEach(fitAppMenuPopover);
  wrapper.classList.add('open');
  wrapper.querySelectorAll('.app-menu-submenu-wrap').forEach(submenu => {
    submenu.classList.add('open');
    submenu.querySelector(':scope > .app-menu-command')?.setAttribute('aria-expanded', 'true');
  });
  openAppMenuId = wrapper.dataset.appMenu || null;
  openAppMenuPinned = options.pinned === true;
  openAppMenuOpenedAt = Date.now();
  wrapper.querySelector('.app-menu-button')?.setAttribute('aria-expanded', 'true');
  if (options.focusFirst) requestAnimationFrame(() => focusFirstAppMenuCommand(wrapper));
}

function closeAppMenus(keepOpen = null) {
  for (const menu of document.querySelectorAll('.app-menu.open')) {
    if (menu === keepOpen) continue;
    menu.classList.remove('open');
    menu.querySelector('.app-menu-button')?.setAttribute('aria-expanded', 'false');
  }
  for (const submenu of document.querySelectorAll('.app-menu-submenu-wrap.open')) {
    if (keepOpen?.contains(submenu)) continue;
    submenu.classList.remove('open');
    submenu.querySelector(':scope > .app-menu-command')?.setAttribute('aria-expanded', 'false');
  }
  openAppMenuId = keepOpen?.dataset?.appMenu || null;
  if (!openAppMenuId) {
    openAppMenuPinned = false;
    openAppMenuOpenedAt = 0;
  }
}
function toggleFileExplorer() {
  if (!fileExplorer) return;
  const opening = fileExplorer.hasAttribute('hidden');
  if (opening) {
    fileExplorer.removeAttribute('hidden');
    document.body.classList.add('file-explorer-open');
    openFileExplorerAt(fileExplorerRootForOpen());
  } else {
    fileExplorer.setAttribute('hidden', '');
    document.body.classList.remove('file-explorer-open');
  }
}

async function openFileExplorerAt(path, options = {}) {
  const root = normalizeDirectoryPath(expandUserPath(path));
  const entries = await fetchDirectory(root, {user: options.user === true || options.manualSelection === true});
  if (!entries) {
    const error = currentFileExplorerListError(root);
    if (error) setFileExplorerPathDisplay(root, {error});
    return false;
  }
  const previousExpanded = options.preserveExpanded ? Array.from(fileExplorerExpanded) : [];
  const scrollPositions = options.preserveScroll ? captureFileExplorerScrollPositions() : null;
  fileExplorerRoot = root;
  pruneFileExplorerSelectionForRoot(fileExplorerRoot);
  fileExplorerManualSelectionActive = options.manualSelection === true;
  cancelPendingFileExplorerActiveSync();
  setFileExplorerPathDisplay(fileExplorerRoot);
  renderFileExplorerRootModeControls();
  fileExplorerExpanded.clear();
  if (fileExplorerTree) {
    renderTreeChildren(fileExplorerTree, fileExplorerRoot, entries, 0);
  }
  if (options.refreshPanels !== false) {
    await refreshFileExplorerPanelTrees({root: fileExplorerRoot, entries, restoreState: false});
  }
  if (previousExpanded.length) await restoreFileExplorerExpandedPaths(previousExpanded, fileExplorerRoot);
  if (scrollPositions) restoreFileExplorerScrollPositions(scrollPositions);
  updateFileExplorerCurrentFileHighlight();
  return true;
}

function resetFileExplorerAppliedSyncPlan() {
  fileExplorerLastAppliedSyncPlanKey = '';
}

async function saveFileExplorerRootMode(mode) {
  if (readOnlyMode) return;
  try {
    await saveSettingsPatch(settingPatch('file_explorer.root_mode', mode));
  } catch (_) {}
}

// Short-TTL cache of directory listings. A live Differ/Finder of a busy session re-renders many times a
// second and each render walks every expanded dir, which without this fans out into a /api/fs/list storm
// (one request per dir per render — the cause of the 8001 fs/list loop). Repeated fetches of the same dir
// within the TTL reuse the listing; the change-detection sweep and explicit reloads pass {fresh:true}.
const fileExplorerDirListingCache = new Map();
const fileExplorerDirListingInflight = new Map();
const fileExplorerPathInfoCache = new Map();
const fileExplorerPathInfoInflight = new Map();
const fileExplorerFsBatchQueue = [];
const fileExplorerFsBatchPending = new Map();
const fileExplorerFsBatchDelayMs = 8;
let fileExplorerFsBatchSeq = 0;
let fileExplorerFsBatchTimer = null;
let fileExplorerPushRefreshDepth = 0;

function clearFileExplorerListError(path = '') {
  const root = normalizeDirectoryPath(path || '');
  if (!root || !fileExplorerLastListError || normalizeDirectoryPath(fileExplorerLastListError.path) === root) {
    fileExplorerPathError = '';
    fileExplorerLastListError = null;
  }
}

function setFileExplorerListError(path, error, status = 0) {
  const root = normalizeDirectoryPath(path || '');
  fileExplorerPathError = error || '';
  fileExplorerLastListError = root && error ? {path: root, status, error, network: !status} : null;
}

function currentFileExplorerListError(path) {
  const root = normalizeDirectoryPath(path || '');
  return root && normalizeDirectoryPath(fileExplorerLastListError?.path || '') === root
    ? fileExplorerLastListError.error || ''
    : '';
}

function fileExplorerFsCacheTtlMs() {
  return Math.max(0, numberSetting('file_explorer.dir_cache_ms', 1500) || 0);
}

function fileExplorerFsBatchKey(type, path) {
  return `${type}\x1f${normalizeDirectoryPath(path)}`;
}

function fileExplorerFsBatchSingleUrl(type, path) {
  const normalized = normalizeDirectoryPath(path);
  return type === 'list'
    ? `/api/fs/list?path=${encodeURIComponent(normalized)}`
    : `/api/fs/info?path=${encodeURIComponent(normalized)}`;
}

function suppressBackgroundFilesystemFetch(options = {}) {
  if (options.force === true || options.user === true) return false;
  return clientPushConnectedForData() && !fileExplorerUserIsActive();
}

function scheduleFileExplorerFsBatchFlush() {
  if (fileExplorerFsBatchTimer) return;
  fileExplorerFsBatchTimer = setTimeout(flushFileExplorerFsBatch, fileExplorerFsBatchDelayMs);
}

function fetchFilesystemBatchItem(type, path, options = {}) {
  const normalized = normalizeDirectoryPath(path);
  const key = fileExplorerFsBatchKey(type, normalized);
  if (options.dedupe !== false) {
    const existing = fileExplorerFsBatchPending.get(key);
    if (existing) return existing.promise;
  }
  let resolve;
  let reject;
  const promise = new Promise((ok, fail) => {
    resolve = ok;
    reject = fail;
  });
  const item = {id: ++fileExplorerFsBatchSeq, type, path: normalized, key, resolve, reject};
  if (options.dedupe !== false) fileExplorerFsBatchPending.set(key, {promise, item});
  fileExplorerFsBatchQueue.push(item);
  scheduleFileExplorerFsBatchFlush();
  return promise;
}

async function settleFileExplorerFsBatchItemFallback(item) {
  try {
    item.resolve(await apiFetchJson(fileExplorerFsBatchSingleUrl(item.type, item.path)));
  } catch (error) {
    item.reject(error);
  } finally {
    if (fileExplorerFsBatchPending.get(item.key)?.item === item) {
      fileExplorerFsBatchPending.delete(item.key);
    }
  }
}

function settleFileExplorerFsBatchItem(item, response) {
  if (fileExplorerFsBatchPending.get(item.key)?.item === item) {
    fileExplorerFsBatchPending.delete(item.key);
  }
  if (response?.ok) {
    item.resolve(response.payload || {});
    return;
  }
  const error = new Error(response?.error || `fs ${item.type} failed`);
  error.status = Number(response?.status) || 0;
  error.payload = response || {};
  item.reject(error);
}

async function flushFileExplorerFsBatch() {
  fileExplorerFsBatchTimer = null;
  const items = fileExplorerFsBatchQueue.splice(0);
  if (!items.length) return;
  const requests = items.map(item => ({id: item.id, type: item.type, path: item.path}));
  try {
    const payload = await apiFetchJson('/api/fs/batch', {
      method: 'POST',
      headers: {'Content-Type': 'application/json'},
      body: JSON.stringify({requests}),
    });
    const responses = new Map((payload.responses || []).map(response => [response.id, response]));
    for (const item of items) {
      settleFileExplorerFsBatchItem(item, responses.get(item.id) || {ok: false, status: 500, error: 'missing fs batch response'});
    }
  } catch (_) {
    await Promise.all(items.map(settleFileExplorerFsBatchItemFallback));
  }
}

async function fetchDirectory(path, options = {}) {
  const root = normalizeDirectoryPath(path);
  const canReuse = options.fresh !== true;
  const dirListingTtlMs = fileExplorerFsCacheTtlMs();
  if (canReuse && dirListingTtlMs > 0) {
    const cached = fileExplorerDirListingCache.get(root);
    if (cached && Date.now() - cached.at < dirListingTtlMs) {
      clearFileExplorerListError(root);
      return cached.entries;
    }
  }
  if (fileExplorerPushRefreshDepth > 0) {
    clearFileExplorerListError(root);
    return null;
  }
  if (suppressBackgroundFilesystemFetch(options)) {
    clearFileExplorerListError(root);
    return null;
  }
  return dedupeInflight(fileExplorerDirListingInflight, root, canReuse, () => (async () => {
    try {
      hydrateFileExplorerRepoInfoCache();
      const payload = await fetchFilesystemBatchItem('list', root, {dedupe: canReuse});
      const entries = payload.entries || [];
      clearFileExplorerListError(root);
      cacheFileExplorerRepoInfoEntries(root, entries);
      markNewDirectoryEntries(root, entries);
      if (options.recordSignature !== false) recordDirectorySignature(root, entries);
      setLimitedMapEntry(fileExplorerDirListingCache, root, {entries, at: Date.now()}, fileExplorerMemoryCacheLimit);
      return entries;
    } catch (err) {
      const status = Number(err?.status) || 0;
      fileExplorerPathError = status
        ? err.message || `Cannot open ${root} (${status})`
        : `Cannot open ${root}: ${err}`;
      setFileExplorerListError(root, fileExplorerPathError, status);
      console.warn(status ? 'fs list failed' : 'fs list error', root, status || err, fileExplorerPathError);
      return null;
    }
  })());
}

function invalidateFileExplorerFsCaches() {
  fileExplorerDirListingCache.clear();
  fileExplorerPathInfoCache.clear();
  fileExplorerDirectorySignatures.clear();
}

function entriesByDirFromFilesystemPush(payload = {}) {
  const entriesByDir = new Map();
  const directories = Array.isArray(payload.directories) ? payload.directories : [];
  for (const item of directories) {
    const path = normalizeDirectoryPath(item?.path || item?.data?.path || '');
    const data = item?.data && typeof item.data === 'object' ? item.data : {};
    const entries = Array.isArray(data.entries) ? data.entries : null;
    if (!path || !entries || item.ok === false || Number(item.status || 200) >= 400) continue;
    entriesByDir.set(path, entries);
    cacheFileExplorerRepoInfoEntries(path, entries);
    markNewDirectoryEntries(path, entries);
    recordDirectorySignature(path, entries);
    setLimitedMapEntry(fileExplorerDirListingCache, path, {entries, at: Date.now()}, fileExplorerMemoryCacheLimit);
  }
  return entriesByDir;
}

function fileEntryStatusFromWatchFilePayload(item) {
  const signature = Array.isArray(item?.signature) ? item.signature : [];
  const path = String(item?.path || signature[0] || '');
  if (!path) return {path: '', entry: null, missing: false, error: '', network: false};
  const kind = String(signature[1] || '');
  if (kind === 'missing') return {path, entry: null, missing: true, error: `path not found: ${path}`, network: false};
  if (kind !== 'file' && kind !== 'dir') return {path, entry: null, missing: false, error: `invalid file signature: ${path}`, network: false};
  const mtime = Number(signature[2]) || 0;
  const size = Number(signature[3]);
  return {
    path,
    entry: {
      name: basenameOf(path),
      kind,
      mtime_ns: mtime,
      mtime,
      size: Number.isFinite(size) ? size : null,
    },
    missing: false,
    error: '',
    network: false,
  };
}

async function refreshOpenFilesFromPush(payload = {}) {
  const files = Array.isArray(payload.files) ? payload.files : [];
  for (const item of files) {
    const fetched = fileEntryStatusFromWatchFilePayload(item);
    if (!fetched.path) continue;
    const state = openFiles.get(fetched.path);
    if (!state || state.loading) continue;
    await refreshOpenFileFromFetchedStatus(fetched.path, state, fetched);
  }
}

async function refreshFileExplorerFromPush(payload = {}) {
  const entriesByDir = entriesByDirFromFilesystemPush(payload);
  if (!entriesByDir.size) return;
  fileExplorerPushRefreshDepth += 1;
  try {
    const root = normalizeDirectoryPath(currentFileExplorerRoot());
    if (fileExplorerPaneIsOpen() && entriesByDir.has(root)) {
      await refreshFileExplorerTreesInPlace({
        root,
        entries: entriesByDir.get(root),
        preserveExpanded: true,
        preserveScroll: true,
        entriesByDir,
      });
    }
    const openFileDirs = Array.from(openFiles.keys()).map(path => normalizeDirectoryPath(dirnameOf(path)));
    if (openFileDirs.every(path => fileExplorerDirListingCache.has(path))) await refreshOpenFilesIfChanged();
  } finally {
    fileExplorerPushRefreshDepth = Math.max(0, fileExplorerPushRefreshDepth - 1);
  }
}

function expandUserPath(path) {
  const text = String(path || '').trim();
  if (text === '~') return homePath || text;
  if (text.startsWith('~/')) return homePath ? `${homePath}${text.slice(1)}` : text;
  return text;
}

function directoryEntriesSignature(entries) {
  if (!Array.isArray(entries)) return '';
  return entries
    .map(entry => [
      entry?.name || '',
      entry?.kind || '',
      Number.isFinite(Number(entry?.size)) ? Number(entry.size) : '',
      Number.isFinite(Number(entry?.mtime)) ? Number(entry.mtime) : '',
      entry?.is_symlink ? '1' : '0',
    ].join('\x1f'))
    .sort()
    .join('\x1e');
}

function recordDirectorySignature(path, entries) {
  setLimitedMapEntry(fileExplorerDirectorySignatures, normalizeDirectoryPath(path), directoryEntriesSignature(entries), fileExplorerMemoryCacheLimit);
}

function pruneExpiredNewFileEntries(now = Date.now()) {
  for (const [path, until] of fileExplorerNewEntryUntil.entries()) {
    if (!until || until <= now) fileExplorerNewEntryUntil.delete(path);
  }
}

function markNewDirectoryEntries(path, entries) {
  const root = normalizeDirectoryPath(path);
  const names = new Set((Array.isArray(entries) ? entries : []).map(entry => entry?.name).filter(Boolean));
  const previous = fileExplorerKnownEntryNames.get(root);
  const now = Date.now();
  pruneExpiredNewFileEntries(now);
  if (previous && fileExplorerNewEntryHighlightMs > 0) {
    for (const name of names) {
      if (!previous.has(name)) setLimitedMapEntry(fileExplorerNewEntryUntil, childPath(root, name), now + fileExplorerNewEntryHighlightMs, fileExplorerMemoryCacheLimit);
    }
  }
  setLimitedMapEntry(fileExplorerKnownEntryNames, root, names, fileExplorerMemoryCacheLimit);
}

function fileExplorerEntryIsNew(path) {
  const until = fileExplorerNewEntryUntil.get(path);
  if (!until) return false;
  if (until <= Date.now()) {
    fileExplorerNewEntryUntil.delete(path);
    return false;
  }
  return true;
}

function scheduleNewEntryClassRemoval(row, path) {
  const until = fileExplorerNewEntryUntil.get(path);
  if (!row || !until) return;
  const delay = Math.max(0, until - Date.now());
  setTimeout(() => {
    if (row.isConnected && fileExplorerEntryIsNew(path) === false) row.classList.remove('new-entry');
    else if (row.isConnected && fileExplorerNewEntryUntil.get(path) <= Date.now()) row.classList.remove('new-entry');
  }, delay + 50);
}

function normalizeDirectoryPath(path) {
  const text = String(path || '').replace(/\/+$/, '');
  return text || '/';
}

function normalizeFileExplorerRepoInfo(repo, fallbackRoot = '') {
  if (!repo || typeof repo !== 'object') return null;
  const root = normalizeDirectoryPath(repo.root || fallbackRoot);
  if (!root) return null;
  const dirtyCount = Number(repo.dirty_count);
  const ahead = Number(repo.ahead);
  const behind = Number(repo.behind);
  return {
    root,
    name: String(repo.name || basenameOf(root) || ''),
    branch: String(repo.branch || ''),
    dirty_count: Number.isFinite(dirtyCount) ? dirtyCount : null,
    upstream: String(repo.upstream || ''),
    ahead: Number.isFinite(ahead) ? ahead : 0,
    behind: Number.isFinite(behind) ? behind : 0,
  };
}

function hydrateFileExplorerRepoInfoCache() {
  if (fileExplorerRepoInfoCacheLoaded) return;
  fileExplorerRepoInfoCacheLoaded = true;
  try {
    const raw = window.localStorage?.getItem(fileExplorerRepoInfoStorageKey);
    if (!raw) return;
    const parsed = JSON.parse(raw);
    const repos = Array.isArray(parsed?.repos) ? parsed.repos : [];
    for (const item of repos) {
      const path = normalizeDirectoryPath(item?.path || item?.repo?.root || '');
      const repo = normalizeFileExplorerRepoInfo(item?.repo, path);
      if (path && repo) setLimitedMapEntry(fileExplorerRepoInfoCache, path, repo, fileExplorerMemoryCacheLimit);
    }
  } catch (_) {}
}

function persistFileExplorerRepoInfoCache() {
  try {
    const repos = Array.from(fileExplorerRepoInfoCache.entries())
      .filter(([path, repo]) => path && repo?.root && normalizeDirectoryPath(repo.root) === path)
      .sort(([leftPath], [rightPath]) => leftPath.localeCompare(rightPath))
      .slice(-200)
      .map(([path, repo]) => ({path, repo}));
    window.localStorage?.setItem(fileExplorerRepoInfoStorageKey, JSON.stringify({repos}));
  } catch (_) {}
}

function cacheFileExplorerRepoInfo(path, repo, options = {}) {
  hydrateFileExplorerRepoInfoCache();
  const normalized = normalizeDirectoryPath(path || repo?.root || '');
  const info = normalizeFileExplorerRepoInfo(repo, normalized);
  if (!normalized || !info) return false;
  const repoRoot = normalizeDirectoryPath(info.root);
  setLimitedMapEntry(fileExplorerRepoInfoCache, normalized, info, fileExplorerMemoryCacheLimit);
  if (repoRoot && repoRoot !== normalized) setLimitedMapEntry(fileExplorerRepoInfoCache, repoRoot, info, fileExplorerMemoryCacheLimit);
  if (options.persist !== false) persistFileExplorerRepoInfoCache();
  return true;
}

function cacheFileExplorerRepoInfoEntries(parentPath, entries) {
  if (!Array.isArray(entries)) return;
  hydrateFileExplorerRepoInfoCache();
  let changed = false;
  for (const entry of entries) {
    if (entry?.kind !== 'dir' || entry.is_repo !== true || !entry.repo) continue;
    const fullPath = childPath(parentPath, entry.name);
    changed = cacheFileExplorerRepoInfo(fullPath, entry.repo, {persist: false}) || changed;
  }
  if (changed) persistFileExplorerRepoInfoCache();
}

function currentFileExplorerRoot() {
  return normalizeDirectoryPath(fileExplorerRoot || homePath || '/');
}

function pruneFileExplorerSelectionForRoot(root) {
  const normalizedRoot = normalizeDirectoryPath(root);
  for (const selectedPath of Array.from(fileExplorerSelectedPaths)) {
    if (!pathIsInsideDirectory(selectedPath, normalizedRoot) || selectedPath === normalizedRoot) {
      fileExplorerSelectedPaths.delete(selectedPath);
    }
  }
  if (
    fileExplorerSelectionAnchor
    && (!pathIsInsideDirectory(fileExplorerSelectionAnchor, normalizedRoot) || fileExplorerSelectionAnchor === normalizedRoot)
  ) {
    fileExplorerSelectionAnchor = null;
    fileExplorerSelectionLead = null;
  }
  if (!fileExplorerSelectedPaths.size) { fileExplorerSelectionAnchor = null; fileExplorerSelectionLead = null; }
}

function fileExplorerIsOpen() {
  return fileExplorerPaneIsOpen() || (fileExplorer && !fileExplorer.hasAttribute('hidden'));
}

function fileExplorerRootModeButtons() {
  return [
    fileExplorerRootModeButton,
    ...Array.from(document.querySelectorAll('.file-explorer-root-mode-toggle-panel')),
  ].filter(Boolean);
}

function syncFileExplorerRootModeButton(button) {
  const label = t('finder.toolbar.syncLabel');
  const title = t('finder.toolbar.syncTitle');
  syncPressedButton(button, fileExplorerRootMode === 'sync', {labelOn: title, labelOff: title});
  if (button) button.textContent = label;
}

function renderFileExplorerRootModeControls() {
  for (const button of fileExplorerRootModeButtons()) {
    syncFileExplorerRootModeButton(button);
  }
  renderFileExplorerQuickAccessControls();
}

function fileExplorerQuickAccessPaths() {
  const paths = initialSetting('file_explorer.quick_access_paths', ['~', '/', '/tmp']);
  return Array.isArray(paths) ? paths.filter(path => typeof path === 'string' && path.trim()) : ['~', '/', '/tmp'];
}

function displayQuickAccessPath(path) {
  const value = String(path || '').trim();
  if (value === '~') return '~';
  if (value === '/' || value === '/*') return '/*';
  if (value.startsWith('/')) return normalizeDirectoryPath(value);
  return value;
}

function expandQuickAccessPath(path) {
  const value = String(path || '').trim();
  if (value === '~') return homePath || '/';
  if (value === '/' || value === '/*') return '/';
  if (value.startsWith('~/')) return normalizeDirectoryPath(`${homePath || ''}/${value.slice(2)}`);
  return value;
}

function renderQuickAccessInto(container) {
  if (!container) return;
  const currentRoot = normalizeDirectoryPath(currentFileExplorerRoot());
  const sync = fileExplorerRootMode === 'sync';
  container.replaceChildren(...fileExplorerQuickAccessPaths().map(path => {
    const expanded = normalizeDirectoryPath(expandQuickAccessPath(path));
    const active = !sync && expanded === currentRoot;
    const button = document.createElement('button');
    button.type = 'button';
    button.className = 'file-explorer-quick-access-button';
    button.textContent = displayQuickAccessPath(path);
    button.title = `Open ${path}`;
    button.dataset.quickPath = path;
    syncPressedButton(button, active, {labelOn: button.title, labelOff: button.title});
    button.addEventListener('click', event => {
      event.preventDefault();
      event.stopPropagation();
      openFileExplorerQuickAccessPath(path);
    });
    return button;
  }));
}

function renderFileExplorerQuickAccessControls() {
  renderQuickAccessInto(fileExplorerQuickAccess);
  document.querySelectorAll('.file-explorer-quick-access-panel').forEach(renderQuickAccessInto);
}

function setFileExplorerRootMode(mode, options = {}) {
  resetFileExplorerAppliedSyncPlan();
  fileExplorerRootMode = mode === 'sync' ? 'sync' : 'fixed';
  writeStoredFileExplorerRootMode(fileExplorerRootMode);
  renderFileExplorerRootModeControls();
  updateFileExplorerSessionHighlightRows();
  if (options.persist === true) saveFileExplorerRootMode(fileExplorerRootMode);
  if (fileExplorerRootMode === 'sync' && options.sync !== false) {
    scheduleFileExplorerActiveTabSync(fileExplorerExplicitSyncSessionTarget(), {explicit: true});
  }
}

function fileExplorerRootModeValue() {
  return fileExplorerRootMode;
}

function toggleFileExplorerRootMode() {
  const mode = fileExplorerRootMode === 'sync' ? 'fixed' : 'sync';
  setFileExplorerRootMode(mode, {persist: true});
}

function setFileExplorerManualRootMode() {
  if (fileExplorerRootMode !== 'fixed') {
    setFileExplorerRootMode('fixed', {sync: false, persist: true});
  } else {
    renderFileExplorerRootModeControls();
  }
}

function openFileExplorerManualRoot(path) {
  setFileExplorerManualRootMode();
  return openFileExplorerAt(path, {manualSelection: true});
}

function openFileExplorerQuickAccessPath(path) {
  openFileExplorerManualRoot(expandQuickAccessPath(path));
}

function tmuxDirectoryForItem(item) {
  if (!isTmuxSession(item)) return '';
  const path = terminalCurrentPath(item);
  return path ? normalizeDirectoryPath(path) : '';
}

function tmuxGitRootForItem(item) {
  if (!isTmuxSession(item)) return '';
  const root = transcriptMeta.sessions?.[item]?.project?.git?.root || '';
  return root ? normalizeDirectoryPath(root) : '';
}

function activeTmuxDirectoryPath(preferredItem = null) {
  if (preferredItem && !isTmuxSession(preferredItem)) return '';
  for (const item of finderCandidateItems(preferredItem)) {
    const path = tmuxDirectoryForItem(item);
    if (path) return path;
  }
  return '';
}

function activeTmuxGitRootPath(preferredItem = null) {
  if (preferredItem && !isTmuxSession(preferredItem)) return '';
  for (const item of finderCandidateItems(preferredItem)) {
    const root = tmuxGitRootForItem(item);
    if (root) return root;
  }
  return '';
}

function activeTmuxSessionForFinder(preferredItem = null) {
  if (preferredItem) return isTmuxSession(preferredItem) ? preferredItem : '';
  for (const item of finderCandidateItems(preferredItem)) {
    if (isTmuxSession(item)) return item;
  }
  return '';
}

function fileExplorerExplicitSyncSessionTarget() {
  return fileExplorerExplicitSyncSession && isTmuxSession(fileExplorerExplicitSyncSession) && activeSessions.includes(fileExplorerExplicitSyncSession)
    ? fileExplorerExplicitSyncSession
    : '';
}

function fileExplorerSyncCommandSessionTarget() {
  const explicitSession = fileExplorerExplicitSyncSessionTarget();
  if (explicitSession) return explicitSession;
  const payloadSession = String(fileExplorerSessionFilesPayload?.session || '');
  if (isTmuxSession(payloadSession) && activeSessions.includes(payloadSession)) return payloadSession;
  return activeTmuxSessionForFinder();
}

function rememberFileExplorerExplicitSyncSession(session) {
  if (!isTmuxSession(session) || !activeSessions.includes(session)) return false;
  fileExplorerExplicitSyncSession = session;
  return true;
}

function fileExplorerRootForOpen(preferredItem = null) {
  if (fileExplorerRootMode === 'sync') {
    const syncPlan = typeof fileExplorerSyncPlan === 'function' ? fileExplorerSyncPlan(preferredItem) : null;
    if (syncPlan?.root) return syncPlan.root;
    return normalizeDirectoryPath(homePath || '/');
  }
  return fileExplorerRoot || homePath || '/';
}

function fileExplorerSyncTargetKey(session, root) {
  const normalizedRoot = normalizeDirectoryPath(root || '');
  const normalizedSession = String(session || '');
  return normalizedSession && normalizedRoot ? `${normalizedSession}\x1f${normalizedRoot}` : '';
}

function fileExplorerExpandedPathsForRoot(root, paths = Array.from(fileExplorerExpanded)) {
  const normalizedRoot = normalizeDirectoryPath(root || '');
  if (!normalizedRoot) return [];
  return Array.from(new Set((paths || [])
    .map(path => normalizeDirectoryPath(path))
    .filter(path => path && path !== normalizedRoot && pathIsInsideDirectory(path, normalizedRoot))))
    .sort((left, right) => (
      childPathParts(normalizedRoot, left).length - childPathParts(normalizedRoot, right).length
      || left.localeCompare(right)
    ));
}

function rememberFileExplorerSyncExpandedState(session = fileExplorerVisibleSyncSession, root = fileExplorerVisibleSyncRoot) {
  if (fileExplorerRootMode !== 'sync') return;
  const key = fileExplorerSyncTargetKey(session, root);
  if (!key) return;
  setLimitedMapEntry(fileExplorerExpandedBySyncTarget, key, fileExplorerExpandedPathsForRoot(root), fileExplorerMemoryCacheLimit);
}

function rememberedFileExplorerSyncExpandedPaths(session, root) {
  const key = fileExplorerSyncTargetKey(session, root);
  const paths = key ? fileExplorerExpandedBySyncTarget.get(key) : null;
  return Array.isArray(paths) ? fileExplorerExpandedPathsForRoot(root, paths) : [];
}

function setFileExplorerVisibleSyncTarget(session, root) {
  fileExplorerVisibleSyncSession = String(session || '');
  fileExplorerVisibleSyncRoot = normalizeDirectoryPath(root || '');
}

function sessionFilesRepoRoots(payload = fileExplorerSessionFilesPayload) {
  return Array.from(new Set((Array.isArray(payload?.repos) ? payload.repos : [])
    .map(repo => normalizeDirectoryPath(repo?.repo || repo?.root || ''))
    .filter(path => path && path.startsWith('/'))));
}

function sessionFileAbsolutePath(file) {
  const raw = String(file?.abs_path || file?.path || '');
  if (raw.startsWith('/')) return normalizeDirectoryPath(raw);
  const repo = normalizeDirectoryPath(file?.repo || '');
  return repo && raw ? normalizeDirectoryPath(childPath(repo, raw)) : '';
}

function sessionFileDirectory(file) {
  const path = sessionFileAbsolutePath(file);
  return path ? normalizeDirectoryPath(dirnameOf(path)) : '';
}

function sessionFilesAffectedDirs(payload = fileExplorerSessionFilesPayload) {
  const dirs = new Set(sessionFilesRepoRoots(payload));
  for (const file of Array.isArray(payload?.files) ? payload.files : []) {
    const dir = sessionFileDirectory(file);
    if (dir) dirs.add(dir);
  }
  return Array.from(dirs);
}

function commonAncestorPath(paths) {
  const normalized = Array.from(new Set((paths || [])
    .map(path => normalizeDirectoryPath(path))
    .filter(path => path && path.startsWith('/'))));
  if (!normalized.length) return '';
  if (normalized.length === 1) return normalized[0];
  const partsList = normalized.map(path => path === '/' ? [] : path.slice(1).split('/').filter(Boolean));
  const common = [];
  for (let index = 0; ; index += 1) {
    const part = partsList[0]?.[index];
    if (!part || !partsList.every(parts => parts[index] === part)) break;
    common.push(part);
  }
  return common.length ? `/${common.join('/')}` : '/';
}

function pathIsShallowerThanHome(path) {
  const root = normalizeDirectoryPath(path);
  const home = normalizeDirectoryPath(homePath || '');
  return Boolean(root && home && root !== home && pathIsInsideDirectory(home, root));
}

function focusedRepoRootForSync(focusedDir, repoRoots = sessionFilesRepoRoots()) {
  const normalizedFocusedDir = normalizeDirectoryPath(focusedDir || '');
  if (!normalizedFocusedDir) return '';
  return repoRoots
    .filter(repo => repo && pathIsInsideDirectory(normalizedFocusedDir, repo))
    .sort((left, right) => right.length - left.length)[0] || normalizedFocusedDir;
}

function sessionFilesPayloadOverlapsFocusedRoot(payload, focusedGitRoot) {
  const root = normalizeDirectoryPath(focusedGitRoot || '');
  if (!root) return true;
  const paths = Array.from(new Set([
    ...sessionFilesRepoRoots(payload),
    ...sessionFilesAffectedDirs(payload),
  ]));
  if (!paths.length) return true;
  return paths.some(path => pathIsInsideDirectory(path, root) || pathIsInsideDirectory(root, path));
}

function firstChildPathUnderRoot(root, path) {
  const parts = childPathParts(root, path);
  return parts.length ? childPath(root, parts[0]) : '';
}

function fileExplorerSyncExpansionTargets(root, affectedDirs = [], repoRoots = []) {
  const normalizedRoot = normalizeDirectoryPath(root || '');
  if (!normalizedRoot) return [];
  const normalizedRepoRoots = Array.from(new Set(repoRoots
    .map(path => normalizeDirectoryPath(path))
    .filter(Boolean)));
  const repoTargets = normalizedRepoRoots
    .filter(path => path !== normalizedRoot && pathIsInsideDirectory(path, normalizedRoot));
  const candidates = normalizedRepoRoots.length
    ? repoTargets
    : affectedDirs.map(path => firstChildPathUnderRoot(normalizedRoot, path));
  return Array.from(new Set(candidates
    .map(path => normalizeDirectoryPath(path))
    .filter(path => path && path !== normalizedRoot && pathIsInsideDirectory(path, normalizedRoot))))
    .sort((left, right) => (
      childPathParts(normalizedRoot, left).length - childPathParts(normalizedRoot, right).length
      || left.localeCompare(right)
    ));
}

function fileExplorerSyncPlan(preferredItem = null) {
  const session = isTmuxSession(preferredItem) ? preferredItem : fileExplorerExplicitSyncSessionTarget();
  if (!session) return {session: '', root: normalizeDirectoryPath(homePath || '/'), expandPaths: [], affectedDirs: []};
  const focusedDir = tmuxDirectoryForItem(session);
  const focusedGitRoot = tmuxGitRootForItem(session);
  const payload = fileExplorerSessionFilesPayload;
  const payloadUsable = (!session || !payload?.session || String(payload.session) === String(session))
    && sessionFilesPayloadOverlapsFocusedRoot(payload, focusedGitRoot);
  const affectedDirs = payloadUsable ? sessionFilesAffectedDirs(payload) : [];
  if (!affectedDirs.length && focusedGitRoot && (!focusedDir || pathIsInsideDirectory(focusedDir, focusedGitRoot))) affectedDirs.push(focusedGitRoot);
  if (!affectedDirs.length && focusedDir) affectedDirs.push(focusedDir);
  const repoRoots = payloadUsable ? sessionFilesRepoRoots(payload) : [];
  if (focusedGitRoot && !repoRoots.includes(focusedGitRoot)) repoRoots.push(focusedGitRoot);
  let root = commonAncestorPath(affectedDirs);
  if (!root) root = normalizeDirectoryPath(homePath || '/');
  if (root && pathIsShallowerThanHome(root)) {
    root = focusedRepoRootForSync(focusedDir, repoRoots) || normalizeDirectoryPath(homePath || '/');
  }
  const normalizedRoot = normalizeDirectoryPath(root || '');
  const expandPaths = fileExplorerSyncExpansionTargets(normalizedRoot, affectedDirs, repoRoots);
  return {session, root: normalizedRoot, expandPaths, affectedDirs: Array.from(new Set(affectedDirs.map(path => normalizeDirectoryPath(path))))};
}

function fileExplorerSyncPlanForFile(path) {
  const target = normalizeDirectoryPath(path || '');
  if (!target) return {session: '', root: '', expandPaths: [], affectedDirs: []};
  const repo = typeof fileRepoForPath === 'function' ? normalizeDirectoryPath(fileRepoForPath(target)) : '';
  const currentRoot = normalizeDirectoryPath(currentFileExplorerRoot());
  let root = repo && pathIsInsideDirectory(target, repo) ? repo : '';
  if (!root && currentRoot && pathIsInsideDirectory(target, currentRoot) && target !== currentRoot) root = currentRoot;
  if (!root) root = normalizeDirectoryPath(dirnameOf(target));
  const session = typeof sessionForFileRepo === 'function' ? sessionForFileRepo(target) : '';
  const expandPaths = root && target !== root && pathIsInsideDirectory(target, root) ? [target] : [];
  return {
    session,
    root,
    expandPaths,
    affectedDirs: [normalizeDirectoryPath(dirnameOf(target))].filter(Boolean),
  };
}

function fileExplorerSyncPlanSignature(plan) {
  if (!plan?.root) return '';
  return [plan.session || '', plan.root, ...(plan.expandPaths || [])].join('\x1f');
}

function fileExplorerSyncPlanKey(plan) {
  if (!plan?.root) return '';
  const expandPaths = fileExplorerSyncExpansionPaths(plan)
    .map(path => normalizeDirectoryPath(path))
    .filter(Boolean)
    .sort();
  return [String(plan.session || ''), normalizeDirectoryPath(plan.root), ...expandPaths].join('\x1f');
}

function fileExplorerSyncPlanAlreadyApplied(plan) {
  const key = fileExplorerSyncPlanKey(plan);
  return Boolean(key)
    && key === fileExplorerLastAppliedSyncPlanKey
    && normalizeDirectoryPath(plan.root) === normalizeDirectoryPath(currentFileExplorerRoot());
}

function markFileExplorerSyncPlanApplied(plan) {
  fileExplorerLastAppliedSyncPlanKey = fileExplorerSyncPlanKey(plan);
}

function fileExplorerSyncManualCollapseKey(plan) {
  return plan?.root ? fileExplorerSyncTargetKey(plan.session, plan.root) : '';
}

function rememberFileExplorerSyncManualCollapseState(targetKey = fileExplorerSyncManualCollapseTargetKey) {
  if (!targetKey) return;
  setLimitedMapEntry(fileExplorerSyncManualCollapsedByTarget, targetKey, Array.from(fileExplorerSyncManualCollapsedPaths), fileExplorerMemoryCacheLimit);
}

function resetFileExplorerSyncManualCollapsesIfNeeded(plan) {
  const targetKey = fileExplorerSyncManualCollapseKey(plan);
  if (targetKey !== fileExplorerSyncManualCollapseTargetKey) {
    rememberFileExplorerSyncManualCollapseState();
    fileExplorerSyncManualCollapseTargetKey = targetKey;
    fileExplorerSyncManualCollapsedPaths = new Set(fileExplorerSyncManualCollapsedByTarget.get(targetKey) || []);
  }
  return targetKey;
}

function fileExplorerSyncManualCollapsePlanForPath(path) {
  const normalized = normalizeDirectoryPath(path || '');
  if (!normalized) return null;
  const visibleRoot = normalizeDirectoryPath(fileExplorerVisibleSyncRoot || currentFileExplorerRoot());
  if (
    fileExplorerVisibleSyncSession
    && visibleRoot
    && pathIsInsideDirectory(normalized, visibleRoot)
  ) {
    return {session: fileExplorerVisibleSyncSession, root: visibleRoot};
  }
  const explicitSession = fileExplorerExplicitSyncSessionTarget();
  const explicitPlan = fileExplorerSyncPlan(explicitSession);
  if (explicitPlan?.root && pathIsInsideDirectory(normalized, explicitPlan.root)) return explicitPlan;
  const currentRoot = normalizeDirectoryPath(currentFileExplorerRoot());
  const fallbackSession = explicitSession || fileExplorerVisibleSyncSession || '';
  if (fallbackSession && currentRoot && pathIsInsideDirectory(normalized, currentRoot)) {
    return {session: fallbackSession, root: currentRoot};
  }
  return null;
}

function fileExplorerSyncPathSuppressed(path) {
  const normalized = normalizeDirectoryPath(path || '');
  if (!normalized) return false;
  for (const collapsedPath of fileExplorerSyncManualCollapsedPaths) {
    if (pathIsInsideDirectory(normalized, collapsedPath)) return true;
  }
  return false;
}

function fileExplorerSyncExpansionPaths(plan) {
  resetFileExplorerSyncManualCollapsesIfNeeded(plan);
  return (plan?.expandPaths || []).filter(path => !fileExplorerSyncPathSuppressed(path));
}

function fileExplorerSyncExplicitExpansionTargets(plan, root = plan?.root || currentFileExplorerRoot()) {
  const normalizedRoot = normalizeDirectoryPath(root || '');
  if (!normalizedRoot) return [];
  return Array.from(new Set([
    ...(plan?.expandPaths || []),
    ...(plan?.affectedDirs || []),
  ]
    .map(path => normalizeDirectoryPath(path))
    .filter(path => path && path !== normalizedRoot && pathIsInsideDirectory(path, normalizedRoot))))
    .sort((left, right) => (
      childPathParts(normalizedRoot, left).length - childPathParts(normalizedRoot, right).length
      || left.localeCompare(right)
    ));
}

function fileExplorerSyncHighlightedRepoRoots(plan, repoRoots) {
  const expansionPaths = new Set(fileExplorerSyncExpansionPaths(plan));
  const root = normalizeDirectoryPath(plan?.root || '');
  return Array.from(repoRoots || [])
    .map(path => normalizeDirectoryPath(path))
    .filter(path => path && root && path !== root && pathIsInsideDirectory(path, root) && expansionPaths.has(path));
}

function rememberFileExplorerSyncManualCollapse(path) {
  if (fileExplorerRootMode !== 'sync') return;
  const plan = fileExplorerSyncManualCollapsePlanForPath(path);
  if (!plan?.root || !pathIsInsideDirectory(path, plan.root)) return;
  resetFileExplorerSyncManualCollapsesIfNeeded(plan);
  fileExplorerSyncManualCollapsedPaths.add(normalizeDirectoryPath(path));
  rememberFileExplorerSyncManualCollapseState();
  resetFileExplorerAppliedSyncPlan();
}

function forgetFileExplorerSyncManualCollapse(path) {
  if (!path) return;
  if (fileExplorerRootMode === 'sync') {
    const plan = fileExplorerSyncManualCollapsePlanForPath(path);
    if (plan) resetFileExplorerSyncManualCollapsesIfNeeded(plan);
  }
  const normalized = normalizeDirectoryPath(path);
  let changed = false;
  for (const collapsedPath of Array.from(fileExplorerSyncManualCollapsedPaths)) {
    if (pathIsInsideDirectory(collapsedPath, normalized) || pathIsInsideDirectory(normalized, collapsedPath)) {
      fileExplorerSyncManualCollapsedPaths.delete(collapsedPath);
      changed = true;
    }
  }
  if (changed) rememberFileExplorerSyncManualCollapseState();
  if (changed) resetFileExplorerAppliedSyncPlan();
}

function emptyFileExplorerSessionHighlightSets() {
  return {repoRoots: new Set(), touchedDirs: new Set(), expandedDirs: new Set()};
}

function fileExplorerSessionHighlightSets(preferredItem = null) {
  if (fileExplorerRootMode !== 'sync') return emptyFileExplorerSessionHighlightSets();
  const targetSession = isTmuxSession(preferredItem) ? preferredItem : fileExplorerExplicitSyncSessionTarget();
  if (!targetSession) return emptyFileExplorerSessionHighlightSets();
  const focusedGitRoot = tmuxGitRootForItem(targetSession);
  const payload = fileExplorerSessionFilesPayload;
  if (
    !payload?.session
    || (targetSession && String(payload.session) !== String(targetSession))
    || !sessionFilesPayloadOverlapsFocusedRoot(payload, focusedGitRoot)
  ) {
    return emptyFileExplorerSessionHighlightSets();
  }
  const repoRoots = new Set(sessionFilesRepoRoots(payload));
  const expandedDirs = new Set(fileExplorerSyncHighlightedRepoRoots(fileExplorerSyncPlan(targetSession), repoRoots));
  return {repoRoots: new Set(), touchedDirs: new Set(), expandedDirs};
}

function fileExplorerSessionHighlightClassForPath(path, kind = 'dir', options = {}) {
  if (options.differMode === true || kind !== 'dir') return '';
  const normalized = normalizeDirectoryPath(path || '');
  if (!normalized) return '';
  const sets = options.sessionHighlightSets || fileExplorerSessionHighlightSets();
  if (sets.expandedDirs?.has(normalized)) return 'file-tree-row--sync-expanded';
  if (sets.repoRoots?.has(normalized)) return 'file-tree-row--session-repo';
  if (sets.touchedDirs?.has(normalized)) return 'file-tree-row--session-touched';
  return '';
}

function applyFileExplorerSessionHighlightRow(row, sets = fileExplorerSessionHighlightSets()) {
  if (!row) return;
  const highlightClass = fileExplorerSessionHighlightClassForPath(row.dataset?.path || '', row.dataset?.kind || '', {sessionHighlightSets: sets});
  applySessionHighlightRowClass(row, highlightClass);
}

function updateFileExplorerSessionHighlightRows(preferredItem = null) {
  const sets = fileExplorerSessionHighlightSets(preferredItem);
  for (const row of document.querySelectorAll('.file-tree-row[data-path]')) {
    applyFileExplorerSessionHighlightRow(row, sets);
  }
}

function fileExplorerPathInputs() {
  return [
    fileExplorerPath,
    ...Array.from(document.querySelectorAll('.file-explorer-path-inline')),
  ].filter(Boolean);
}

function setFileExplorerPathElementValue(node, path) {
  if (!node) return;
  if ('value' in node) node.value = path;
  else node.textContent = path;
}

function setFileExplorerPathError(node, message = '') {
  if (!node) return;
  node.classList.toggle('invalid', Boolean(message));
  if (message) node.title = message;
  else node.removeAttribute('title');
}

function setFileExplorerPathDisplay(path = currentFileExplorerRoot(), options = {}) {
  const normalized = normalizeDirectoryPath(path);
  const error = options.error || '';
  for (const input of fileExplorerPathInputs()) {
    setFileExplorerPathElementValue(input, normalized);
    setFileExplorerPathError(input, error);
  }
  document.querySelectorAll('.file-explorer-head, .file-explorer-toolbar').forEach(node => {
    node.title = error || normalized;
  });
  refreshFileExplorerRepoDisplay(normalized, {error});
}

function repoInfoSummary(repo) {
  if (!repo?.root) return '';
  const dirty = Number.isFinite(Number(repo.dirty_count)) && Number(repo.dirty_count) > 0 ? `, ${Number(repo.dirty_count)} dirty` : '';
  const ahead = Number.isFinite(Number(repo.ahead)) && Number(repo.ahead) > 0 ? `, ${Number(repo.ahead)} ahead` : '';
  const behind = Number.isFinite(Number(repo.behind)) && Number(repo.behind) > 0 ? `, ${Number(repo.behind)} behind` : '';
  const branch = repo.branch || 'detached';
  return `${repo.name || basenameOf(repo.root)} (${branch}${dirty}${ahead}${behind})`;
}

function setFileExplorerRepoSummary(path, repo, error = '') {
  const summary = error ? '' : repoInfoSummary(repo);
  const title = error || (repo?.root ? [`repo: ${repo.root}`, `branch: ${repo.branch || 'unknown'}`, repo.upstream ? `upstream: ${repo.upstream}` : '', Number.isFinite(Number(repo.dirty_count)) ? `dirty files: ${repo.dirty_count}` : '', Number(repo.ahead) ? `ahead: ${repo.ahead}` : '', Number(repo.behind) ? `behind: ${repo.behind}` : ''].filter(Boolean).join('\n') : '');
  for (const node of document.querySelectorAll('.file-explorer-repo-summary')) {
    node.textContent = summary;
    node.hidden = !summary;
    if (title) node.title = title;
    else node.removeAttribute('title');
  }
  for (const input of fileExplorerPathInputs()) {
    if (title) input.title = title;
    else if (!error) input.removeAttribute('title');
  }
}

async function refreshFileExplorerRepoDisplay(path, options = {}) {
  if (options.error) {
    setFileExplorerRepoSummary(path, null, options.error);
    return;
  }
  const normalized = normalizeDirectoryPath(path);
  const cached = fileExplorerRepoInfoCache.get(normalized);
  if (cached) {
    setFileExplorerRepoSummary(normalized, cached);
    return;
  }
  try {
    const info = await fetchFilePathInfo(normalized);
    if (normalizeDirectoryPath(fileExplorerRoot || normalized) !== normalized) return;
    const repo = info.repo || null;
    if (repo) cacheFileExplorerRepoInfo(normalized, repo);
    setFileExplorerRepoSummary(normalized, repo);
  } catch (_) {
    setFileExplorerRepoSummary(normalized, null);
  }
}

// Rich git info shown in a styled hover popover for a repo dir (replaces the native title tooltip).
function repoInfoPopoverHtml(repo) {
  if (!repo?.root) return '';
  const rows = [`<div class="file-tree-repo-popover-title">${esc(repo.name || basenameOf(repo.root))}</div>`];
  rows.push(`<div class="file-tree-repo-popover-branch">⎇ ${esc(repo.branch || 'detached')}</div>`);
  if (repo.upstream) rows.push(`<div class="meta-muted">↗ ${esc(repo.upstream)}</div>`);
  const stat = [];
  if (Number(repo.ahead) > 0) stat.push(`${Number(repo.ahead)} ahead`);
  if (Number(repo.behind) > 0) stat.push(`${Number(repo.behind)} behind`);
  if (Number.isFinite(Number(repo.dirty_count))) stat.push(`${Number(repo.dirty_count)} dirty`);
  if (stat.length) rows.push(`<div class="file-tree-repo-popover-stat">${esc(stat.join(' · '))}</div>`);
  rows.push(`<div class="file-tree-repo-popover-path">${esc(repo.root)}</div>`);
  return rows.join('');
}

function fileTreeRepoPopoverNode() {
  let node = document.getElementById('fileTreeRepoPopover');
  if (!node) {
    node = document.createElement('div');
    node.id = 'fileTreeRepoPopover';
    node.className = 'file-tree-repo-popover';
    node.hidden = true;
    document.body.appendChild(node);
  }
  return node;
}

let fileTreeRepoPopoverTimer = null;
let fileTreeRepoPopoverHoverToken = 0;
let fileTreeRepoPopoverCursor = {x: 0, y: 0};   // last pointer pos over the hovered repo row; popover anchors to its RIGHT

function cancelFileTreeRepoPopoverTimer() {
  if (fileTreeRepoPopoverTimer) {
    clearTimeout(fileTreeRepoPopoverTimer);
    fileTreeRepoPopoverTimer = null;
  }
  fileTreeRepoPopoverHoverToken += 1;
}

function showFileTreeRepoPopover(row, repo) {
  if (!repo?.root) return;
  const node = fileTreeRepoPopoverNode();
  node.innerHTML = repoInfoPopoverHtml(repo);
  node.hidden = false;
  // Anchor to the RIGHT of the cursor (like a tooltip following the pointer), not centered under the row.
  // Clamp to the viewport so it stays fully on-screen near the right/bottom edge.
  const popRect = node.getBoundingClientRect?.();
  const pos = clampToViewport(
    Math.round(fileTreeRepoPopoverCursor.x + 14),
    Math.round(fileTreeRepoPopoverCursor.y + 4),
    Math.ceil(popRect?.width || 0),
    Math.ceil(popRect?.height || 0),
  );
  node.style.left = `${Math.round(pos.left)}px`;
  node.style.top = `${Math.round(pos.top)}px`;
}

function hideFileTreeRepoPopover() {
  cancelFileTreeRepoPopoverTimer();
  fileTreeRepoPopoverPath = null;
  const node = document.getElementById('fileTreeRepoPopover');
  if (node) node.hidden = true;
}

function scheduleRepoRowHoverPopover(row, path) {
  cancelFileTreeRepoPopoverTimer();
  const token = fileTreeRepoPopoverHoverToken;
  const delay = Math.max(0, Number(popoverShowDelayMs) || 0);
  fileTreeRepoPopoverTimer = setTimeout(() => {
    fileTreeRepoPopoverTimer = null;
    if (token !== fileTreeRepoPopoverHoverToken || !row?.isConnected) return;
    showRepoRowHoverPopover(row, path);
  }, delay);
}

async function showRepoRowHoverPopover(row, path) {
  const normalized = normalizeDirectoryPath(path);
  fileTreeRepoPopoverPath = normalized;
  // Show immediately from cache (branch/ahead/behind), then lazily fetch full status (incl dirty).
  showFileTreeRepoPopover(row, fileExplorerRepoInfoCache.get(normalized));
  const cached = fileExplorerRepoInfoCache.get(normalized);
  if (cached && Number.isFinite(Number(cached.dirty_count))) return;
  if (row.dataset.repoTitleLoaded === 'true') return;
  row.dataset.repoTitleLoaded = 'true';
  try {
    const info = await fetchFilePathInfo(normalized);
    if (info.repo) {
      cacheFileExplorerRepoInfo(normalized, info.repo);
      updateFileTreeGitStatusRows();
      if (fileTreeRepoPopoverPath === normalized) showFileTreeRepoPopover(row, info.repo);
    }
  } catch (_) {}
}

async function commitFileExplorerPathInput(input) {
  const raw = 'value' in input ? input.value : input.textContent;
  const target = expandUserPath(raw);
  if (!target) return false;
  const opened = await openFileExplorerManualRoot(target);
  if (!opened) {
    const error = currentFileExplorerListError(target);
    if (error) setFileExplorerPathError(input, error);
  }
  return opened;
}

function bindFileExplorerPathInput(input) {
  if (!input || input.dataset.pathInputBound === 'true') return;
  input.dataset.pathInputBound = 'true';
  input.addEventListener('keydown', event => {
    if (event.key === 'Enter') {
      event.preventDefault();
      event.stopPropagation();
      commitFileExplorerPathInput(input);
    } else if (event.key === 'Escape') {
      event.preventDefault();
      event.stopPropagation();
      setFileExplorerPathDisplay();
      input.blur?.();
    }
  });
  input.addEventListener('focus', () => input.select?.());
}

function pathIsInsideDirectory(path, root) {
  const child = normalizeDirectoryPath(path);
  const parent = normalizeDirectoryPath(root);
  if (parent === '/') return child.startsWith('/');
  return child === parent || child.startsWith(`${parent}/`);
}

function childPathParts(root, path) {
  const parent = normalizeDirectoryPath(root);
  const child = normalizeDirectoryPath(path);
  if (!pathIsInsideDirectory(child, parent) || child === parent) return [];
  const relative = parent === '/' ? child.slice(1) : child.slice(parent.length + 1);
  return relative.split('/').filter(Boolean);
}

function finderDirectoryForItem(item) {
  if (isFileEditorItem(item)) return normalizeDirectoryPath(dirnameOf(fileItemPath(item)));
  return '';
}

function finderTargetPathForItem(item) {
  if (isFileEditorItem(item)) return fileItemPath(item) || '';
  return '';
}

function finderCandidateItems(preferredItem = null) {
  const explicitSession = fileExplorerExplicitSyncSessionTarget();
  const candidates = [];
  // Finder follows the last explicit click/type target. Visual focus may move on hover when auto-focus
  // is enabled, but passive focus must not move the Finder path, root, current-directory mark, or diff
  // target.
  for (const item of [preferredItem, explicitSession]) {
    if (item && !candidates.includes(item)) candidates.push(item);
  }
  return candidates.filter(item => !isFileExplorerItem(item) && !isInfoItem(item));
}

function firstFinderPath(preferredItem, pathForItem, options = {}) {
  const normalize = options.normalize === true;
  for (const item of finderCandidateItems(preferredItem)) {
    const path = pathForItem(item);
    if (path) return normalize ? normalizeDirectoryPath(path) : path;
  }
  return '';
}

function activeFinderDirectoryPath(preferredItem = null) {
  return firstFinderPath(preferredItem, finderDirectoryForItem);
}

function activeFinderTargetPath(preferredItem = null) {
  return firstFinderPath(preferredItem, finderTargetPathForItem, {normalize: true});
}

function explicitFinderTargetPath(preferredItem = null) {
  const path = finderTargetPathForItem(preferredItem);
  return path ? normalizeDirectoryPath(path) : '';
}

function fileExplorerPaneIsOpen() {
  return itemInLayout(fileExplorerItemId);
}

function scheduleFileExplorerActiveTabSync(preferredItem = null, options = {}) {
  if (!fileExplorerIsOpen()) return;
  if (fileExplorerRootMode !== 'sync') return;
  const explicit = options.explicit === true;
  if (fileExplorerManualSelectionActive && !explicit) return;
  if (explicit) fileExplorerManualSelectionActive = false;
  if (options.explicit === true && isTmuxSession(preferredItem)) rememberFileExplorerExplicitSyncSession(preferredItem);
  const explicitSession = fileExplorerExplicitSyncSessionTarget();
  const fileSyncPath = explicit && isFileEditorItem(preferredItem) ? fileItemPath(preferredItem) : '';
  if (fileSyncPath) forgetFileExplorerSyncManualCollapse(fileSyncPath);
  const syncItem = fileSyncPath ? preferredItem : (isTmuxSession(preferredItem) ? preferredItem : explicitSession);
  if (!syncItem || (!fileSyncPath && syncItem !== explicitSession)) return;
  const syncPlan = fileSyncPath ? fileExplorerSyncPlanForFile(fileSyncPath) : fileExplorerSyncPlan(syncItem);
  const expandPaths = fileExplorerSyncExpansionPaths(syncPlan);
  const syncSignature = fileExplorerSyncPlanSignature(syncPlan);
  if (
    syncPlan.root
    && (syncPlan.root !== currentFileExplorerRoot() || expandPaths.length)
    && fileExplorerSyncPathInFlight !== syncSignature
    && (explicit || !fileExplorerSyncPlanAlreadyApplied(syncPlan))
  ) {
    const interactionGeneration = fileExplorerInteractionGeneration;
    requestAnimationFrame(() => {
      if (interactionGeneration !== fileExplorerInteractionGeneration) return;
      const syncPromise = fileSyncPath
        ? syncFileExplorerRootToActiveFile(fileSyncPath, {force: explicit})
        : syncFileExplorerRootToActiveTmux(syncItem, {force: explicit});
      syncPromise.catch(error => {
        console.warn('Finder root sync failed', error);
      });
    });
    return;
  }
}

function cancelPendingFileExplorerActiveSync() {
  fileExplorerInteractionGeneration += 1;
  resetFileExplorerAppliedSyncPlan();
}

async function syncFileExplorerRootToActiveTmux(preferredItem = null, options = {}) {
  if (!fileExplorerIsOpen() || fileExplorerRootMode !== 'sync') return false;
  return syncFileExplorerRootToPlan(fileExplorerSyncPlan(preferredItem), preferredItem, options);
}

async function syncFileExplorerRootToActiveFile(path, options = {}) {
  if (!fileExplorerIsOpen() || fileExplorerRootMode !== 'sync') return false;
  forgetFileExplorerSyncManualCollapse(path);
  return syncFileExplorerRootToPlan(fileExplorerSyncPlanForFile(path), fileEditorItemFor(path), options);
}

async function syncFileExplorerRootToPlan(plan, preferredItem = null, options = {}) {
  const signature = fileExplorerSyncPlanSignature(plan);
  const expandPaths = fileExplorerSyncExpansionPaths(plan);
  if (!plan.root || fileExplorerSyncPathInFlight === signature) return false;
  if (options.force !== true && fileExplorerSyncPlanAlreadyApplied(plan)) {
    setFileExplorerVisibleSyncTarget(plan.session, plan.root);
    updateFileExplorerSessionHighlightRows(preferredItem);
    return false;
  }
  fileExplorerSyncPathInFlight = signature;
  try {
    let changed = false;
    const previousTargetKey = fileExplorerSyncTargetKey(fileExplorerVisibleSyncSession, fileExplorerVisibleSyncRoot);
    const nextTargetKey = fileExplorerSyncTargetKey(plan.session, plan.root);
    if (nextTargetKey && nextTargetKey !== previousTargetKey) {
      rememberFileExplorerSyncExpandedState();
    }
    if (plan.root !== currentFileExplorerRoot()) {
      changed = await openFileExplorerAt(plan.root, {preserveExpanded: false, preserveScroll: false});
      if (!changed) return false;
    }
    const rememberedExpandedPaths = rememberedFileExplorerSyncExpandedPaths(plan.session, plan.root);
    if (rememberedExpandedPaths.length) {
      changed = await restoreFileExplorerExpandedPaths(rememberedExpandedPaths, plan.root) || changed;
    }
    if (expandPaths.length) {
      const generation = ++fileExplorerSyncGeneration;
      for (const path of expandPaths) {
        if (generation !== fileExplorerSyncGeneration) return changed;
        changed = await expandFileExplorerTreesToPath(path, plan.root, generation, {scrollIntoView: false, auto: true}) || changed;
      }
    }
    setFileExplorerVisibleSyncTarget(plan.session, plan.root);
    rememberFileExplorerSyncExpandedState(plan.session, plan.root);
    markFileExplorerSyncPlanApplied(plan);
    updateFileExplorerSessionHighlightRows(preferredItem);
    return changed;
  } finally {
    if (fileExplorerSyncPathInFlight === signature) fileExplorerSyncPathInFlight = '';
  }
}

async function syncFileExplorerToActiveTab(preferredItem = null, options = {}) {
  if (!fileExplorerIsOpen()) return false;
  if (fileExplorerRootMode !== 'sync' && options.explicit !== true) return false;
  const path = options.explicit === true ? explicitFinderTargetPath(preferredItem) : activeFinderTargetPath(preferredItem);
  if (!path || fileExplorerSyncPathInFlight === path) return false;
  const root = currentFileExplorerRoot();
  if (!pathIsInsideDirectory(path, root) || path === root) return false;
  fileExplorerSyncPathInFlight = path;
  const generation = ++fileExplorerSyncGeneration;
  try {
    return await expandFileExplorerTreesToPath(path, root, generation);
  } finally {
    if (fileExplorerSyncPathInFlight === path) fileExplorerSyncPathInFlight = '';
  }
}

function fileExplorerTreeContainers() {
  const containers = [];
  if (fileExplorerTree) containers.push(fileExplorerTree);
  document.querySelectorAll('.file-explorer-tree-panel').forEach(tree => {
    if (!containers.includes(tree)) containers.push(tree);
  });
  return containers;
}

function captureFileExplorerScrollPositions() {
  return fileExplorerTreeContainers().map(container => container.scrollTop || 0);
}

function restoreFileExplorerScrollPositions(positions) {
  requestAnimationFrame(() => {
    fileExplorerTreeContainers().forEach((container, index) => {
      if (positions[index] != null) container.scrollTop = positions[index];
    });
  });
}

function markFileExplorerInteraction() {
  fileExplorerLastInteractionAt = Date.now();
}

function eventTargetIsFileExplorerSurface(target) {
  return Boolean(target?.closest?.('#fileExplorer, .panel.file-explorer-panel, .file-explorer-tree-panel'));
}

function fileExplorerUserIsActive() {
  if (isFileExplorerItem(focusedPanelItem)) return true;
  if (Date.now() - fileExplorerLastInteractionAt < fileExplorerRefreshIdleMs) return true;
  if (fileExplorer?.matches?.(':hover')) return true;
  return Array.from(document.querySelectorAll('.panel.file-explorer-panel, .file-explorer-tree-panel')).some(node => node.matches?.(':hover'));
}

function deferFileExplorerRefresh() {
  if (fileExplorerRefreshDeferred) return;
  fileExplorerRefreshDeferred = true;
  setTimeout(() => {
    fileExplorerRefreshDeferred = false;
    refreshFileExplorerIfChanged().catch(error => console.warn('deferred file explorer refresh failed', error));
  }, fileExplorerRefreshIdleMs);
}

document.addEventListener('pointerdown', event => {
  if (eventTargetIsFileExplorerSurface(event.target)) markFileExplorerInteraction();
}, true);
document.addEventListener('scroll', event => {
  if (eventTargetIsFileExplorerSurface(event.target)) markFileExplorerInteraction();
}, true);

function directFileTreeRow(container, fullPath) {
  return Array.from(container?.children || []).find(node => (
    node.classList?.contains('file-tree-row') && node.dataset?.path === fullPath
  )) || null;
}

function childContainerForRow(row, fullPath) {
  const next = row?.nextElementSibling;
  return next?.classList?.contains('file-tree-children') && next.dataset?.parent === fullPath ? next : null;
}

function createFileTreeChildContainer(fullPath) {
  const children = document.createElement('div');
  children.className = 'file-tree-children';
  children.dataset.parent = fullPath;
  return children;
}

async function ensureFileTreeRootRendered(container, root) {
  if (!container) return false;
  const firstRow = container.querySelector?.('.file-tree-row[data-path]');
  if (firstRow) {
    if (pathIsInsideDirectory(firstRow.dataset.path, root) && childPathParts(root, firstRow.dataset.path).length === 1) return true;
    container.replaceChildren();
  }
  const entries = await fetchDirectory(root);
  if (!entries) return false;
  container.replaceChildren();
  renderTreeChildren(container, root, entries, 0);
  return true;
}

function childPath(parent, name) {
  return parent === '/' ? `/${name}` : `${parent}/${name}`;
}

async function ensureDirectoryRowExpanded(row, fullPath, options = {}) {
  if (!row || row.dataset?.kind !== 'dir') return null;
  const existing = childContainerForRow(row, fullPath);
  if (existing) return existing;
  await expandDirectoryRow(row, fullPath, options);
  return childContainerForRow(row, fullPath);
}

function nextAnimationFrame() {
  return new Promise(resolve => requestAnimationFrame(resolve));
}

function scrollFileTreeRowIntoView(container, row) {
  if (!container || !row || container.isConnected === false || row.isConnected === false) return false;
  const containerRect = container.getBoundingClientRect?.();
  const rowRect = row.getBoundingClientRect?.();
  const containerHeight = container.clientHeight || containerRect?.height || 0;
  if (!containerRect || !rowRect || !containerHeight || !rowRect.height) return false;
  const currentTop = container.scrollTop || 0;
  const rowTop = currentTop + rowRect.top - containerRect.top;
  const rowBottom = rowTop + rowRect.height;
  const margin = 8;
  const visibleTop = currentTop + margin;
  const visibleBottom = currentTop + containerHeight - margin;
  if (rowTop >= visibleTop && rowBottom <= visibleBottom) return true;
  const centeredTop = rowTop - Math.max(0, (containerHeight - rowRect.height) / 2);
  container.scrollTop = Math.max(0, centeredTop);
  return true;
}

async function expandFileTreeContainerToPath(container, root, path, generation = fileExplorerSyncGeneration, options = {}) {
  const parts = childPathParts(root, path);
  if (!parts.length) return false;
  const rendered = await ensureFileTreeRootRendered(container, root);
  if (!rendered) return false;
  if (generation !== fileExplorerSyncGeneration) return false;
  let scope = container;
  let parent = root;
  let row = null;
  for (const part of parts) {
    const fullPath = childPath(parent, part);
    row = directFileTreeRow(scope, fullPath);
    if (!row) return false;
    if (row.dataset?.kind === 'dir') {
      const childScope = await ensureDirectoryRowExpanded(row, fullPath, {auto: options.auto === true});
      if (generation !== fileExplorerSyncGeneration) return false;
      if (fullPath !== path) {
        if (!childScope) return false;
        scope = childScope;
      }
    } else if (fullPath !== path) {
      return false;
    }
    parent = fullPath;
  }
  await nextAnimationFrame();
  if (generation !== fileExplorerSyncGeneration) return false;
  if (options.scrollIntoView !== false) scrollFileTreeRowIntoView(container, row);
  updateFileExplorerCurrentFileHighlight();
  return Boolean(row);
}

async function expandFileExplorerTreesToPath(path, root = currentFileExplorerRoot(), generation = fileExplorerSyncGeneration, options = {}) {
  let expanded = false;
  if (!fileExplorerRoot) fileExplorerRoot = root;
  setFileExplorerPathDisplay(root);
  for (const container of fileExplorerTreeContainers()) {
    if (generation !== fileExplorerSyncGeneration) return false;
    expanded = await expandFileTreeContainerToPath(container, root, path, generation, options) || expanded;
  }
  return expanded;
}

async function restoreFileExplorerExpandedPaths(paths, root = currentFileExplorerRoot()) {
  const expandedPaths = Array.from(new Set(paths))
    .filter(path => pathIsInsideDirectory(path, root) && path !== root)
    .filter(path => fileExplorerRootMode !== 'sync' || !fileExplorerSyncPathSuppressed(path))
    .sort((left, right) => childPathParts(root, left).length - childPathParts(root, right).length);
  const generation = ++fileExplorerSyncGeneration;
  for (const path of expandedPaths) {
    if (generation !== fileExplorerSyncGeneration) return false;
    await expandFileExplorerTreesToPath(path, root, generation, {scrollIntoView: false});
  }
  return true;
}

function fileTreeDirectRows(container) {
  return Array.from(container?.children || []).filter(node => node.classList?.contains('file-tree-row'));
}

function fileTreeChangedFile(path) {
  const files = Array.isArray(fileExplorerSessionFilesPayload?.files) ? fileExplorerSessionFilesPayload.files : [];
  return files.find(item => item?.abs_path === path) || null;
}

function sessionFileAgentKinds(item) {
  const raw = Array.isArray(item?.agents) ? item.agents : (item?.agent ? [item.agent] : []);
  const order = {claude: 0, codex: 1};
  const seen = new Set();
  return raw
    .map(value => String(value || '').toLowerCase())
    .filter(value => value && !seen.has(value) && seen.add(value))
    .sort((a, b) => (order[a] ?? 2) - (order[b] ?? 2) || a.localeCompare(b));
}

function fileTreeChangedAncestorStats(payload = fileExplorerSessionFilesPayload) {
  const stats = new Map();
  const seen = new Set();
  for (const file of Array.isArray(payload?.files) ? payload.files : []) {
    if (!sessionFileIsDifferVisible(file)) continue;
    const absPath = sessionFileAbsolutePath(file);
    if (!absPath) continue;
    const agents = sessionFileAgentKinds(file);
    let dir = normalizeDirectoryPath(dirnameOf(absPath));
    while (dir && dir !== '/') {
      const key = `${dir}\x1f${absPath}`;
      const current = stats.get(dir) || {count: 0, agents: [], mtime: 0};
      if (!seen.has(key)) {
        seen.add(key);
        current.count += 1;
      }
      const mtime = Number(file.mtime || 0);
      if (Number.isFinite(mtime) && mtime > Number(current.mtime || 0)) current.mtime = mtime;
      for (const agent of agents) {
        if (!current.agents.includes(agent)) current.agents.push(agent);
      }
      stats.set(dir, current);
      const parent = normalizeDirectoryPath(dirnameOf(dir));
      if (!parent || parent === dir) break;
      dir = parent;
    }
  }
  return stats;
}

function fileTreeGitStatus(path) {
  return String(fileTreeChangedFile(path)?.status || '').toUpperCase();
}

function fileTreeNumstatText(path) {
  const match = fileTreeChangedFile(path);
  if (!match) return '';
  const added = Number(match.added || 0);
  const removed = Number(match.removed || 0);
  if (!Number.isFinite(added) || !Number.isFinite(removed)) return '';
  if (added === 0 && removed === 0) return '';
  return ` (+${added}/-${removed})`;
}

function fileTreeRepoBranch(path) {
  hydrateFileExplorerRepoInfoCache();
  const normalized = normalizeDirectoryPath(path);
  const repo = fileExplorerRepoInfoCache.get(normalized);
  if (!repo?.root || normalizeDirectoryPath(repo.root) !== normalized) return '';
  return repo.branch || 'detached';
}

// Compact ahead/behind/dirty markers for a repo dir's inline annotation, read from cached repo info.
function fileTreeRepoSyncMeta(path) {
  hydrateFileExplorerRepoInfoCache();
  const normalized = normalizeDirectoryPath(path);
  const repo = fileExplorerRepoInfoCache.get(normalized);
  if (!repo?.root || normalizeDirectoryPath(repo.root) !== normalized) return [];
  const parts = [];
  const ahead = Number(repo.ahead);
  const behind = Number(repo.behind);
  const dirty = Number(repo.dirty_count);
  if (Number.isFinite(ahead) && ahead > 0) parts.push({cls: 'file-tree-repo-ahead', text: `↑${ahead}`});
  if (Number.isFinite(behind) && behind > 0) parts.push({cls: 'file-tree-repo-behind', text: `↓${behind}`});
  if (Number.isFinite(dirty) && dirty > 0) parts.push({cls: 'file-tree-repo-dirty', text: `●${dirty}`});
  return parts;
}

function fileTreeRepoNumstat(path) {
  const normalized = normalizeDirectoryPath(path);
  const repos = Array.isArray(fileExplorerSessionFilesPayload?.repos) ? fileExplorerSessionFilesPayload.repos : [];
  const repo = repos.find(item => normalizeDirectoryPath(item?.repo || '') === normalized);
  let added = Number(repo?.added);
  let removed = Number(repo?.removed);
  if (!Number.isFinite(added) || !Number.isFinite(removed)) {
    const files = Array.isArray(fileExplorerSessionFilesPayload?.files) ? fileExplorerSessionFilesPayload.files : [];
    const repoFiles = files.filter(item => normalizeDirectoryPath(item?.repo || '') === normalized);
    added = repoFiles.reduce((sum, item) => sum + (Number.isFinite(Number(item.added)) ? Number(item.added) : 0), 0);
    removed = repoFiles.reduce((sum, item) => sum + (Number.isFinite(Number(item.removed)) ? Number(item.removed) : 0), 0);
  }
  if (!Number.isFinite(added) || !Number.isFinite(removed)) return '';
  if (added === 0 && removed === 0) return '';
  return `+${added}/-${removed}`;
}

function fileTreeRepoBranchIsNonMain(path) {
  const branch = fileTreeRepoBranch(path);
  return Boolean(branch && !['main', 'master'].includes(branch));
}

function fileTreeDisplayParts(path, entry) {
  // a symlink shows where it points inline — "name → target" (the raw link text, rel or abs).
  const linkTarget = entry.is_symlink === true && entry.symlink_target ? String(entry.symlink_target) : '';
  const linkSuffixText = linkTarget ? ` → ${linkTarget}` : '';
  const linkSuffixHtml = linkTarget ? ` <span class="file-tree-symlink-target">→ ${esc(linkTarget)}</span>` : '';
  if (entry.kind === 'dir' && entry.is_repo === true) {
    const branch = fileTreeRepoBranch(path);
    const numstat = fileTreeRepoNumstat(path);
    const sync = fileTreeRepoSyncMeta(path);
    const textParts = [branch, ...sync.map(part => part.text), numstat].filter(Boolean);
    const htmlParts = [];
    if (branch) htmlParts.push(`<span class="file-tree-repo-branch">${esc(branch)}</span>`);
    for (const part of sync) htmlParts.push(`<span class="${part.cls}">${esc(part.text)}</span>`);
    if (numstat) htmlParts.push(`<span class="file-tree-repo-delta">${esc(numstat)}</span>`);
    return {
      text: (textParts.length ? `${entry.name} [${textParts.join(' ')}]` : entry.name) + linkSuffixText,
      html: (htmlParts.length
        ? `${esc(entry.name)} <span class="file-tree-repo-meta">[${htmlParts.join(' ')}]</span>`
        : esc(entry.name)) + linkSuffixHtml,
    };
  }
  const baseText = entry.name;
  if (linkTarget) return {text: baseText + linkSuffixText, html: esc(baseText) + linkSuffixHtml};
  return {text: baseText, html: ''};
}

function fileTreeMtimeText(entry) {
  return sessionFileDisplayTimeText(entry?.mtime);
}

function sortedFileTreeEntries(entries, sortMode = fileExplorerTreeSortMode, options = {}) {
  const includeHidden = options.includeHidden === true;
  const visible = entries.filter(entry => includeHidden || fileExplorerShowHidden || !entry.name.startsWith('.'));
  const mode = ['az', 'za', 'newest', 'oldest'].includes(sortMode) ? sortMode : 'az';
  const direction = mode === 'za' ? -1 : 1;
  return visible.sort((left, right) => {
    const leftKind = left.kind === 'dir' ? 0 : 1;
    const rightKind = right.kind === 'dir' ? 0 : 1;
    if (leftKind !== rightKind) return leftKind - rightKind;
    if (mode === 'newest' || mode === 'oldest') {
      const mtimeResult = Number(right.mtime || 0) - Number(left.mtime || 0);
      if (mtimeResult !== 0) return mode === 'newest' ? mtimeResult : -mtimeResult;
    }
    return String(left.name || '').localeCompare(String(right.name || ''), undefined, {numeric: true, sensitivity: 'base'}) * direction;
  });
}

// one source for the git-status row classes (the toggle loop hardcoded this 5-element list in
// two places — updateFileTreeRow + updateFileTreeGitStatusRows — so a status that maps elsewhere or a row
// that changes status could leave a stale class behind on one path but not the other). applyGitStatusRowClass
// toggles exactly this set so the stale class is always cleared.
const GIT_STATUS_ROW_CLASSES = Object.freeze(['git-modified', 'git-untracked', 'git-deleted', 'git-staged', 'git-transcript']);
// The session-highlight row classes (sync-expanded / session-repo / session-touched), likewise toggled in
// two places (applyFileExplorerSessionHighlightRow + updateFileTreeRow).
const SESSION_HIGHLIGHT_ROW_CLASSES = Object.freeze(['file-tree-row--sync-expanded', 'file-tree-row--session-repo', 'file-tree-row--session-touched']);

function applyGitStatusRowClass(row, gitClass) {
  for (const className of GIT_STATUS_ROW_CLASSES) {
    row.classList.toggle(className, className === gitClass);
  }
}

function applySessionHighlightRowClass(row, highlightClass) {
  for (const className of SESSION_HIGHLIGHT_ROW_CLASSES) {
    row.classList.toggle(className, className === highlightClass);
  }
}

function gitStatusRowClass(status) {
  const key = String(status || '').toUpperCase();
  if (key === 'A' || key === 'U' || key === '?') return 'git-untracked';
  if (key === 'D') return 'git-deleted';
  if (key === 'S') return 'git-staged';
  if (key === 'M') return 'git-modified';
  if (key === 'T') return 'git-transcript';
  const fallback = String(status || '').toLowerCase();
  return /^[a-z0-9_-]+$/.test(fallback) ? `git-${fallback}` : '';
}

function fileTreeGitStatusClass(status) {
  return gitStatusRowClass(status);
}

function fileTreeGitStatusBadgeClass(status) {
  return String(status || '').toUpperCase() === '?' ? 'file-tree-git-status-unknown' : '';
}

function gitStatusBadgeTitle(status) {
  const key = String(status || '').toUpperCase();
  const labels = {
    M: 'modified',
    A: 'added',
    D: 'deleted',
    T: 'touched by AI transcript',
    '?': 'untracked',
    U: 'untracked',
    S: 'staged',
    R: 'renamed',
    C: 'copied',
  };
  return labels[key] ? `${key}: ${labels[key]}` : '';
}

function fileIconClassFor(name, kind = 'file') {
  if (kind === 'dir') return 'file-icon-dir';
  const lowerName = String(name || '').toLowerCase();
  const ext = fileExtensionOf(lowerName);
  if (IMAGE_EXTENSIONS.has(ext)) return 'file-icon-image';
  if (['.md', '.markdown', '.txt', '.rst', 'readme', 'license'].includes(ext || lowerName)) return 'file-icon-doc';
  if (['.json', '.yaml', '.yml', '.toml', '.ini', '.cfg', '.conf', '.env', 'dockerfile', 'makefile'].includes(ext || lowerName)) return 'file-icon-config';
  if (['.py', '.js', '.ts', '.tsx', '.jsx', '.rs', '.go', '.c', '.h', '.cpp', '.hpp', '.rb', '.lua', '.sql', '.sh', '.bash', '.zsh'].includes(ext)) return 'file-icon-code';
  if (['.zip', '.tar', '.gz', '.tgz', '.bz2', '.xz'].includes(ext)) return 'file-icon-archive';
  return 'file-icon-generic';
}

function reconcileChildNodes(parent, nextNodes, options = {}) {
  if (!parent) return;
  const lockedNodes = new Set(options.lockedNodes || []);
  const arranged = nextNodes.slice();
  if (lockedNodes.size) {
    Array.from(parent.children || []).forEach((child, index) => {
      if (!lockedNodes.has(child)) return;
      const desiredIndex = arranged.indexOf(child);
      if (desiredIndex < 0 || desiredIndex === index || index >= arranged.length) return;
      arranged.splice(desiredIndex, 1);
      arranged.splice(index, 0, child);
    });
  }
  arranged.forEach((node, index) => {
    if (parent.children[index] !== node) parent.insertBefore(node, parent.children[index] || null);
  });
  while (parent.children.length > arranged.length) parent.lastElementChild?.remove();
}

function setClassNameIfChanged(node, className) {
  if (node && node.className !== className) node.className = className;
}

function setHiddenIfChanged(node, hidden) {
  if (node && node.hidden !== hidden) node.hidden = hidden;
}

function syncFileTreeRowKindClass(row, kind) {
  row.classList.add('file-tree-row');
  const nextKindClass = `kind-${kind}`;
  if (row.dataset.kind === kind && row.classList.contains(nextKindClass)) return;
  for (const className of Array.from(row.classList || [])) {
    if (className.startsWith('kind-')) row.classList.remove(className);
  }
  row.classList.add(nextKindClass);
}

function updateFileTreeRowContents(row, iconText, nameText, options = {}) {
  let icon = row.querySelector(':scope > .file-tree-icon');
  if (!icon) {
    icon = document.createElement('span');
    icon.className = 'file-tree-icon';
    row.appendChild(icon);
  }
  let name = row.querySelector(':scope > .file-tree-name');
  if (!name) {
    name = document.createElement('span');
    name.className = 'file-tree-name';
    row.appendChild(name);
  }
  let dirCount = row.querySelector(':scope > .file-tree-dir-count');
  if (!dirCount) {
    dirCount = document.createElement('span');
    dirCount.className = 'file-tree-dir-count';
    row.appendChild(dirCount);
  }
  let agent = row.querySelector(':scope > .file-tree-agent');
  if (!agent) {
    agent = document.createElement('span');
    agent.className = 'file-tree-agent';
    row.appendChild(agent);
  }
  let diff = row.querySelector(':scope > .file-tree-diff');
  if (!diff) {
    diff = document.createElement('span');
    diff.className = 'file-tree-diff';
    row.appendChild(diff);
  }
  let status = row.querySelector(':scope > .file-tree-git-status');
  if (!status) {
    status = document.createElement('span');
    status.className = 'file-tree-git-status';
    row.appendChild(status);
  }
  let date = row.querySelector(':scope > .file-tree-date');
  if (!date) {
    date = document.createElement('span');
    date.className = 'file-tree-date';
    row.appendChild(date);
  }
  // Keep DOM order: icon → name → agent → dir-count → diff → status → date.
  if (name.nextElementSibling !== agent) row.insertBefore(agent, name.nextElementSibling);
  if (agent.nextElementSibling !== dirCount) row.insertBefore(dirCount, agent.nextElementSibling);
  if (dirCount.nextElementSibling !== diff) row.insertBefore(diff, dirCount.nextElementSibling);
  if (diff.nextElementSibling !== status) row.insertBefore(status, diff.nextElementSibling);
  if (status.nextElementSibling !== date) row.insertBefore(date, status.nextElementSibling);
  setClassNameIfChanged(icon, ['file-tree-icon', options.iconClass || ''].filter(Boolean).join(' '));
  if (icon.textContent !== iconText) icon.textContent = iconText;
  if (options.nameHtml) {
    if (name.innerHTML !== options.nameHtml) name.innerHTML = options.nameHtml;
    if (!name.children?.length && name.textContent !== nameText) name.textContent = nameText;
  } else if (name.textContent !== nameText || name.innerHTML) {
    name.innerHTML = '';
    name.textContent = nameText;
  }
  const agentHtml = options.agentHtml || '';
  if (agent.innerHTML !== agentHtml) agent.innerHTML = agentHtml;
  setHiddenIfChanged(agent, !agentHtml);
  row.classList.toggle('has-agent', Boolean(agentHtml));
  const dirCountText = options.dirCountText || '';
  if (dirCount.textContent !== dirCountText) dirCount.textContent = dirCountText;
  setHiddenIfChanged(dirCount, !dirCountText);
  const diffParts = options.diffParts || [];
  const diffHtml = diffParts.map(p => `<span class="changes-diff-${esc(p.kind)}">${esc(p.text)}</span>`).join(' ');
  if (diff.innerHTML !== diffHtml) diff.innerHTML = diffHtml;
  setHiddenIfChanged(diff, !diffParts.length);
  const statusText = options.gitStatus || '';
  setClassNameIfChanged(status, ['file-tree-git-status', fileTreeGitStatusBadgeClass(statusText)].filter(Boolean).join(' '));
  if (status.textContent !== statusText) status.textContent = statusText;
  const statusTitle = options.gitStatusTitle || '';
  if (statusTitle) {
    status.setAttribute('title', statusTitle);
    status.setAttribute('aria-label', statusTitle);
  } else {
    status.removeAttribute('title');
    status.removeAttribute('aria-label');
  }
  setHiddenIfChanged(status, !statusText);
  const dateText = options.dateText || '';
  if (date.textContent !== dateText) date.textContent = dateText;
  setHiddenIfChanged(date, !dateText);
}

function updateFileTreeRow(row, parentPath, entry, depth, options = {}) {
  const fullPath = parentPath === '/' ? `/${entry.name}` : `${parentPath}/${entry.name}`;
  const differMode = options.differMode === true;
  const compact = options.compact === true;
  const currentDirectory = activeFinderDirectoryPath();
  const expanded = entry.kind === 'dir' && (differMode
    ? !changesFolderCollapsed.has(fullPath)
    : (options.autoExpand === true || fileExplorerExpanded.has(fullPath)));
  const indexedDirectory = !differMode && entry.kind === 'dir' && fileExplorerDirectoryIsIndexed(fullPath);
  const indexedDescendantDirectory = !differMode && entry.kind === 'dir' && !indexedDirectory && Boolean(fileExplorerIndexedAncestor(fullPath));
  syncFileTreeRowKindClass(row, entry.kind);
  row.classList.toggle('compact', compact);
  row.dataset.path = fullPath;
  row.dataset.kind = entry.kind;
  row.dataset.name = entry.name;
  row.dataset.isRepo = entry.is_repo === true ? 'true' : 'false';
  row.dataset.isSymlink = entry.is_symlink === true ? 'true' : 'false';
  if (entry.symlink_target) row.dataset.symlinkTarget = String(entry.symlink_target);
  else delete row.dataset.symlinkTarget;
  row.dataset.indexed = indexedDirectory ? 'true' : 'false';
  const paddingLeft = `${(compact ? 4 : 8) + depth * 14}px`;
  if (row.style.paddingLeft !== paddingLeft) row.style.paddingLeft = paddingLeft;
  row.setAttribute('role', 'treeitem');
  row.setAttribute('aria-selected', fileExplorerSelectedPaths.has(fullPath) ? 'true' : 'false');
  if (entry.kind === 'dir') row.setAttribute('aria-expanded', expanded ? 'true' : 'false');
  else row.removeAttribute('aria-expanded');
  row.draggable = entry.kind === 'file' || entry.kind === 'dir';
  row.classList.toggle('selected', fileExplorerSelectedPaths.has(fullPath));
  row.classList.toggle('expanded', expanded);
  row.classList.toggle('collapsed', entry.kind === 'dir' && !expanded);
  row.classList.toggle('is-repo', entry.kind === 'dir' && entry.is_repo === true);
  row.classList.toggle('repo-non-main', entry.kind === 'dir' && entry.is_repo === true && fileTreeRepoBranchIsNonMain(fullPath));
  row.classList.toggle('indexed-directory', indexedDirectory);
  row.classList.toggle('indexed-descendant-directory', indexedDescendantDirectory);
  const sessionHighlightClass = fileExplorerSessionHighlightClassForPath(fullPath, entry.kind, {
    differMode,
    sessionHighlightSets: options.sessionHighlightSets,
  });
  applySessionHighlightRowClass(row, sessionHighlightClass);
  const changedAncestor = !differMode && entry.kind === 'dir' && options.changedAncestorStats instanceof Map
    ? (options.changedAncestorStats.get(fullPath) || null)
    : null;
  row.classList.toggle('file-tree-row--changed-ancestor', Boolean(changedAncestor?.count));
  // flag symlinks so the icon gets an arrow-badge overlay (target-type icon is kept); a broken
  // link gets a red badge + struck-through name. The backend sets is_symlink + kind=symlink-broken.
  row.classList.toggle('is-symlink', entry.is_symlink === true);
  row.classList.toggle('symlink-broken', entry.kind === 'symlink-broken');
  const changedFile = entry.kind === 'file'
    ? (options.sessionFilesMap ? (options.sessionFilesMap.get(fullPath) || null) : fileTreeChangedFile(fullPath))
    : null;
  const gitStatus = entry.kind === 'file'
    ? (options.sessionFilesMap ? (changedFile ? String(changedFile.status || 'M').toUpperCase() : '') : fileTreeGitStatus(fullPath))
    : (differMode ? '' : fileExplorerIndexBadgeText(fullPath));
  const gitStatusTitle = entry.kind === 'dir' && !differMode ? fileExplorerIndexBadgeTitle(fullPath) : gitStatusBadgeTitle(gitStatus);
  const gitClass = fileTreeGitStatusClass(gitStatus);
  applyGitStatusRowClass(row, gitClass);
  if (!differMode && entry.kind === 'dir' && entry.is_repo === true) {
    row.removeAttribute('title');
    row.onmouseenter = event => { fileTreeRepoPopoverCursor = {x: event.clientX, y: event.clientY}; scheduleRepoRowHoverPopover(row, fullPath); };
    row.onmousemove = event => { fileTreeRepoPopoverCursor = {x: event.clientX, y: event.clientY}; };
    row.onmouseleave = () => hideFileTreeRepoPopover();
  } else if (!differMode) {
    cancelFileTreeRepoPopoverTimer();
    row.onmouseenter = null;
    row.onmousemove = null;
    row.onmouseleave = null;
    if (row.dataset.repoTitleLoaded) delete row.dataset.repoTitleLoaded;
    if (entry.is_symlink === true && entry.symlink_target) {
      const broken = entry.kind === 'symlink-broken';
      row.title = `${entry.name} → ${entry.symlink_target}${broken ? ` ${t('finder.symlink.broken')}` : ''}`;
    } else {
      row.removeAttribute('title');
    }
  }
  if (!differMode) {
    const newEntry = fileExplorerEntryIsNew(fullPath);
    row.classList.toggle('new-entry', newEntry);
    if (newEntry) scheduleNewEntryClassRemoval(row, fullPath);
    const currentFile = entry.kind === 'file' && fullPath === activeFile;
    const currentDirectoryRow = entry.kind === 'dir' && fullPath === currentDirectory;
    row.classList.toggle('current-file', currentFile);
    row.classList.toggle('current-directory', currentDirectoryRow);
    if (currentFile || currentDirectoryRow) row.setAttribute('aria-current', 'true');
    else row.removeAttribute('aria-current');
  }
  const icon = entry.kind === 'dir' ? (expanded ? '▾' : '▸') : (entry.kind === 'file' ? fileIconFor(entry.name) : '·');
  const displayName = differMode ? {text: entry.name, html: null} : fileTreeDisplayParts(fullPath, entry);
  const dirCountText = entry.kind === 'dir'
    ? (differMode
      ? String(countChangedFilesInDir(fullPath, options.entriesByDir, options.sessionFilesMap) || '')
      : (changedAncestor?.count ? String(changedAncestor.count) : ''))
    : '';
  // Set data attributes so Differ event delegation (click/drag/contextmenu) can find these rows
  if (changedFile?.abs_path) {
    row.dataset.openChangeFile = changedFile.abs_path;
    row.dataset.openChangeSession = changedFile.session || '';
    row.dataset.openChangeStatus = (changedFile.status || 'M').toUpperCase();
    row.dataset.changeRel = changedFile.path || '';
    if (changedFile.repo) row.dataset.openChangeRepo = changedFile.repo;
    else delete row.dataset.openChangeRepo;
    if (changedFile.size !== null && changedFile.size !== undefined) row.dataset.changeSize = String(changedFile.size);
    else delete row.dataset.changeSize;
  } else {
    delete row.dataset.openChangeFile;
    delete row.dataset.openChangeSession;
    delete row.dataset.openChangeStatus;
    delete row.dataset.changeRel;
    delete row.dataset.openChangeRepo;
    delete row.dataset.changeSize;
  }
  if (differMode && entry.kind === 'dir') {
    const repoRoot = options.repoForDiffer || '';
    const relDir = repoRoot && fullPath.startsWith(repoRoot + '/') ? fullPath.slice(repoRoot.length + 1) : '';
    row.dataset.changesFolderToggle = fullPath;
    row.dataset.openChangeDirectory = fullPath;
    row.dataset.changeRel = relDir;
  } else if (!differMode) {
    delete row.dataset.changesFolderToggle;
    delete row.dataset.openChangeDirectory;
  }
  updateFileTreeRowContents(row, icon, displayName.text, {
    gitStatus,
    gitStatusTitle,
    iconClass: [fileIconClassFor(entry.name, entry.kind), indexedDirectory ? 'file-icon-dir-indexed' : ''].filter(Boolean).join(' '),
    nameHtml: differMode ? null : displayName.html,
    dateText: fileTreeMtimeText(entry),
    diffParts: changedFile ? sessionFileDiffText(changedFile) : [],
    agentHtml: changedFile ? changeFileAgentsHtml(changedFile) : (changedAncestor ? changeFileAgentsHtml(changedAncestor) : ''),
    dirCountText,
  });
  if (entry.kind === 'file' && IMAGE_EXTENSIONS.has(fileExtensionOf(entry.name)) && Number(entry.size || 0) <= MAX_FILE_PREVIEW_BYTES) {
    bindFileImagePreview(row, fullPath, entry);
  }
  if (differMode) {
    // In differMode, event handling is via delegation in bindChangesPanel; clear Finder handlers
    row.onpointerdown = null;
    row.onpointerup = null;
    row.onclick = null;
    row.ondblclick = null;
    row.oncontextmenu = null;
    row.ondragstart = null;
    row.ondragend = null;
  } else {
    row.onpointerdown = event => {
      if (event.button != null && event.button !== 0) return;
      cancelPendingFileExplorerActiveSync();
      row.__fileTreePointerDown = {x: event.clientX || 0, y: event.clientY || 0};
    };
    row.onpointerup = event => {
      if (event.button != null && event.button !== 0) return;
      const start = row.__fileTreePointerDown;
      row.__fileTreePointerDown = null;
      if (row.__fileTreeDragging) return;
      const dx = Math.abs((event.clientX || 0) - (start?.x || 0));
      const dy = Math.abs((event.clientY || 0) - (start?.y || 0));
      if (start && Math.max(dx, dy) > 4) return;
      event.preventDefault();
      event.stopPropagation();
      if (event.detail > 1) return;
      row.__fileTreePointerActivated = true;
      setTimeout(() => { row.__fileTreePointerActivated = false; }, 0);
      onFileTreeRowClick(row, fullPath, entry, event);
    };
    row.onclick = event => {
      if (row.__fileTreePointerActivated) {
        row.__fileTreePointerActivated = false;
        event.preventDefault();
        event.stopPropagation();
        return;
      }
      event.stopPropagation();
      if (event.detail > 1) return;
      onFileTreeRowClick(row, fullPath, entry, event);
    };
    row.ondblclick = event => {
      event.preventDefault();
      event.stopPropagation();
      if (entry.kind === 'dir') openFileExplorerManualRoot(fullPath);
      else openFileInEditor(fullPath, entry);
    };
    row.oncontextmenu = event => {
      event.preventDefault();
      event.stopPropagation();
      closeFileImagePreview();
      showFileTreeContextMenu(row, fullPath, entry, event.clientX, event.clientY);
    };
    row.ondragstart = event => {
      row.__fileTreeDragging = true;
      startFileTreeDrag(event, row, fullPath, entry);
    };
    row.ondragend = () => {
      row.__fileTreeDragging = false;
      dragFilePayloadState = null;
      stopCustomDragPreview();
      clearDropPreview();
    };
  }
  return fullPath;
}

function renderTreeChildren(container, parentPath, entries, depth, options = {}) {
  if (!container) return;
  // Step the .file-tree-children::before guide line per nesting level: rows indent 14px/level
  // (updateFileTreeRow padding-left = base + depth*14), and the children wrappers are NOT physically
  // indented, so without this the fixed-left guide stacks every level at one x and only level 1 shows.
  container.style.setProperty('--tree-depth', String(depth));
  cacheFileExplorerRepoInfoEntries(parentPath, entries);
  const renderOptions = {
    ...options,
    sessionHighlightSets: options.sessionHighlightSets || fileExplorerSessionHighlightSets(),
    changedAncestorStats: options.changedAncestorStats instanceof Map ? options.changedAncestorStats : fileTreeChangedAncestorStats(),
  };
  const entriesByDir = renderOptions.entriesByDir instanceof Map ? renderOptions.entriesByDir : null;
  const visible = sortedFileTreeEntries(entries, renderOptions.treeSortMode, {includeHidden: renderOptions.includeHidden === true});
  const existingRows = new Map(fileTreeDirectRows(container).map(row => [row.dataset.path, row]));
  const nextNodes = [];
  for (const entry of visible) {
    const fullPath = parentPath === '/' ? `/${entry.name}` : `${parentPath}/${entry.name}`;
    const row = existingRows.get(fullPath) || document.createElement('div');
    updateFileTreeRow(row, parentPath, entry, depth, renderOptions);
    nextNodes.push(row);
    const isDifferDir = renderOptions.differMode === true && entry.kind === 'dir';
    if (entry.kind === 'dir' && (isDifferDir ? !changesFolderCollapsed.has(fullPath) : (renderOptions.autoExpand === true || fileExplorerExpanded.has(fullPath)))) {
      const childEntries = entriesByDir?.get(normalizeDirectoryPath(fullPath));
      const existingChildContainer = childContainerForRow(row, fullPath);
      const childContainer = existingChildContainer || (Array.isArray(childEntries) ? createFileTreeChildContainer(fullPath) : null);
      if (childContainer) {
        if (Array.isArray(childEntries)) {
          renderTreeChildren(childContainer, fullPath, childEntries, depth + 1, renderOptions);
        }
        nextNodes.push(childContainer);
      }
    }
  }
  reconcileChildNodes(container, nextNodes);
}

function rawFileUrl(path, params = {}) {
  const queryParts = [`path=${encodeURIComponent(path)}`];
  for (const [key, value] of Object.entries(params)) {
    if (value === null || value === undefined || value === '') continue;
    queryParts.push(`${encodeURIComponent(key)}=${encodeURIComponent(String(value))}`);
  }
  return `/api/fs/raw?${queryParts.join('&')}`;
}

function closeFileImagePreview(options = {}) {
  if (!options.fromController) fileImagePreviewController?.cancelTimers?.();
  fileImagePreviewPopover?.remove();
  fileImagePreviewPopover = null;
}

function positionFileImagePreview(anchor, popover, point = null) {
  const anchorRect = anchor.getBoundingClientRect();
  const rect = popover.getBoundingClientRect();
  const edgeGap = popoverEdgeGapPx();
  const desiredLeft = point ? point.x + 14 : anchorRect.right + 10;
  const desiredTop = point ? point.y + 14 : anchorRect.top - 8;
  const {left, top} = clampToViewport(desiredLeft, desiredTop, rect.width, rect.height, {edgeGap});
  popover.style.left = `${Math.round(left)}px`;
  popover.style.top = `${Math.round(top)}px`;
}

function openFileImagePreview(anchor, path, entry, point = null) {
  closeFileImagePreview();
  if (!anchor || !document.body) return;
  const popover = document.createElement('div');
  popover.className = 'file-image-preview-popover';
  popover.dataset.previewPath = path;
  const img = document.createElement('img');
  img.src = rawFileUrl(path);
  img.alt = entry?.name || basenameOf(path);
  popover.appendChild(img);
  document.body.appendChild(popover);
  fileImagePreviewPopover = popover;
  positionFileImagePreview(anchor, popover, point);
}

function bindFileImagePreview(anchor, path, entry) {
  if (!anchor || anchor.dataset.imagePreviewBound === 'true') return;
  anchor.dataset.imagePreviewBound = 'true';
  let pointer = null;
  const updatePointer = event => {
    pointer = {x: event.clientX, y: event.clientY};
    if (fileImagePreviewPopover?.dataset.previewPath === path) positionFileImagePreview(anchor, fileImagePreviewPopover, pointer);
  };
  const controller = createHoverPopover({
    anchor,
    popover: () => fileImagePreviewPopover?.dataset.previewPath === path ? fileImagePreviewPopover : null,
    stateClass: '',
    showDelay: () => Math.max(fileImagePreviewMinShowDelayMs, tabPopoverShowDelayMs),
    hideDelay: () => popoverHideDelayMs,
    canOpen: () => !appMenuIsOpen() && !contextMenuIsOpen() && !topbar?.matches?.(':hover'),
    stillActive: () => popoverStillActive(anchor, fileImagePreviewPopover?.dataset.previewPath === path ? fileImagePreviewPopover : null),
    onQueue: updatePointer,
    onOpen: event => {
      updatePointer(event);
      fileImagePreviewController = controller;
      openFileImagePreview(anchor, path, entry, pointer);
    },
    onClose: () => {
      if (fileImagePreviewPopover?.dataset.previewPath === path) closeFileImagePreview({fromController: true});
      if (fileImagePreviewController === controller) fileImagePreviewController = null;
    },
  });
  anchor.addEventListener('pointerenter', event => {
    fileImagePreviewController = controller;
    updatePointer(event);
  });
  anchor.addEventListener('pointermove', updatePointer);
}

function selectableFileTreeRows(container = document) {
  return Array.from(container.querySelectorAll('.file-tree-row[data-path]'))
    .filter(row => row.dataset.kind === 'file' || row.dataset.kind === 'dir');
}

function updateFileExplorerCurrentFileHighlight() {
  const currentDirectory = activeFinderDirectoryPath();
  document.querySelectorAll('.file-tree-row').forEach(row => {
    const selected = fileExplorerSelectedPaths.has(row.dataset.path);
    const currentFile = row.dataset.kind === 'file' && row.dataset.path === activeFile;
    const currentDirectoryRow = !currentFile && row.dataset.kind === 'dir' && row.dataset.path === currentDirectory;
    row.classList.toggle('selected', selected);
    row.classList.toggle('current-file', currentFile);
    row.classList.toggle('current-directory', currentDirectoryRow);
    row.setAttribute('aria-selected', selected ? 'true' : 'false');
    if (currentFile || currentDirectoryRow) row.setAttribute('aria-current', 'true');
    else row.removeAttribute('aria-current');
  });
}

function scheduleFileExplorerActiveFileReveal(path = activeFile) {
  if (!path) {
    updateFileExplorerCurrentFileHighlight();
    return;
  }
  const target = normalizeDirectoryPath(path);
  const root = normalizeDirectoryPath(currentFileExplorerRoot());
  updateFileExplorerCurrentFileHighlight();
  if (!fileExplorerIsOpen() || !pathIsInsideDirectory(target, root)) return;
  if (!fileExplorerTreeContainers().some(container => container.querySelector?.('.file-tree-row[data-path]'))) return;
  const generation = ++fileExplorerSyncGeneration;
  const schedule = typeof requestAnimationFrame === 'function' ? requestAnimationFrame : callback => setTimeout(callback, 0);
  schedule(() => {
    if (generation !== fileExplorerSyncGeneration) return;
    expandFileExplorerTreesToPath(target, root, generation, {auto: true}).catch(error => {
      console.warn('Finder active file reveal failed', error);
    });
  });
}

function updateFileTreeGitStatusRows() {
  const changedAncestorStats = fileTreeChangedAncestorStats();
  document.querySelectorAll('.file-tree-row[data-path]').forEach(row => {
    const gitStatus = row.dataset.kind === 'file' ? fileTreeGitStatus(row.dataset.path) : '';
    const gitClass = fileTreeGitStatusClass(gitStatus);
    applyGitStatusRowClass(row, gitClass);
    const status = row.querySelector(':scope > .file-tree-git-status');
    if (status) {
      setClassNameIfChanged(status, ['file-tree-git-status', fileTreeGitStatusBadgeClass(gitStatus)].filter(Boolean).join(' '));
      status.textContent = gitStatus;
      const title = gitStatusBadgeTitle(gitStatus);
      if (title) {
        status.setAttribute('title', title);
        status.setAttribute('aria-label', title);
      } else {
        status.removeAttribute('title');
        status.removeAttribute('aria-label');
      }
      status.hidden = !gitStatus;
    }
    const entry = {
      kind: row.dataset.kind,
      name: row.dataset.name || basenameOf(row.dataset.path),
      is_repo: row.dataset.isRepo === 'true',
      is_symlink: row.dataset.isSymlink === 'true',
      symlink_target: row.dataset.symlinkTarget || '',
    };
    row.classList.toggle('repo-non-main', entry.kind === 'dir' && entry.is_repo === true && fileTreeRepoBranchIsNonMain(row.dataset.path));
    const changedAncestor = entry.kind === 'dir' ? (changedAncestorStats.get(row.dataset.path) || null) : null;
    row.classList.toggle('file-tree-row--changed-ancestor', Boolean(changedAncestor?.count));
    const changedFile = entry.kind === 'file' ? fileTreeChangedFile(row.dataset.path) : null;
    const agentHtml = changedFile ? changeFileAgentsHtml(changedFile) : (changedAncestor ? changeFileAgentsHtml(changedAncestor) : '');
    const agent = row.querySelector(':scope > .file-tree-agent');
    if (agent) {
      if (agent.innerHTML !== agentHtml) agent.innerHTML = agentHtml;
      agent.hidden = !agentHtml;
    }
    row.classList.toggle('has-agent', Boolean(agentHtml));
    const dirCount = row.querySelector(':scope > .file-tree-dir-count');
    if (dirCount) {
      const dirCountText = changedAncestor?.count ? String(changedAncestor.count) : '';
      dirCount.textContent = dirCountText;
      dirCount.hidden = !dirCountText;
    }
    const name = row.querySelector(':scope > .file-tree-name');
    const nextName = fileTreeDisplayParts(row.dataset.path, entry);
    if (name && name.textContent !== nextName.text) {
      if (nextName.html) name.innerHTML = nextName.html;
      if (!name.children?.length) name.textContent = nextName.text;
    }
  });
  updateFileExplorerSessionHighlightRows();
}

function selectFileTreePath(fullPath, options = {}) {
  if (options.clear !== false) fileExplorerSelectedPaths.clear();
  if (options.toggle) {
    if (fileExplorerSelectedPaths.has(fullPath)) fileExplorerSelectedPaths.delete(fullPath);
    else fileExplorerSelectedPaths.add(fullPath);
  } else {
    fileExplorerSelectedPaths.add(fullPath);
  }
  if (options.anchor !== false) fileExplorerSelectionAnchor = fullPath;
  fileExplorerSelectionLead = fullPath;   // the keyboard cursor follows the single/clicked selection
  updateFileExplorerCurrentFileHighlight();
}

function selectFileTreeRange(row, fullPath, options = {}) {
  const rows = selectableFileTreeRows(row.closest('[role="tree"]') || document);
  fileExplorerSelectionLead = fullPath;   // a range extend leaves the anchor put but moves the lead to the target
  const scrollContainer = row.closest('.file-explorer-tree-panel');
  const restoreScrollTop = options.preserveScroll !== false && scrollContainer ? scrollContainer.scrollTop : null;
  const finish = () => {
    updateFileExplorerCurrentFileHighlight();
    if (restoreScrollTop !== null) {
      scrollContainer.scrollTop = restoreScrollTop;
      requestAnimationFrame(() => {
        scrollContainer.scrollTop = restoreScrollTop;
      });
    }
  };
  const targetIndex = rows.findIndex(item => item.dataset.path === fullPath);
  let anchorIndex = rows.findIndex(item => item.dataset.path === fileExplorerSelectionAnchor);
  if (anchorIndex < 0) {
    anchorIndex = rows.findIndex(item => fileExplorerSelectedPaths.has(item.dataset.path));
    if (anchorIndex >= 0) fileExplorerSelectionAnchor = rows[anchorIndex].dataset.path;
  }
  if (options.clear !== false) fileExplorerSelectedPaths.clear();
  if (targetIndex < 0) {
    selectFileTreePath(fullPath, {clear: false});
    if (restoreScrollTop !== null) scrollContainer.scrollTop = restoreScrollTop;
    return;
  }
  if (anchorIndex < 0) {
    fileExplorerSelectedPaths.add(fullPath);
    fileExplorerSelectionAnchor = fullPath;
    finish();
    return;
  }
  const start = Math.min(anchorIndex, targetIndex);
  const end = Math.max(anchorIndex, targetIndex);
  for (const selectedRow of rows.slice(start, end + 1)) {
    fileExplorerSelectedPaths.add(selectedRow.dataset.path);
  }
  finish();
}

function updateFileTreeSelectionFromClick(row, fullPath, event) {
  const toggleModifier = appModifier(event);
  if (event.shiftKey) {
    fileExplorerManualSelectionActive = true;
    selectFileTreeRange(row, fullPath, {clear: !toggleModifier});
    return true;
  }
  if (toggleModifier) {
    fileExplorerManualSelectionActive = true;
    selectFileTreePath(fullPath, {clear: false, toggle: true});
    return true;
  }
  fileExplorerManualSelectionActive = false;
  selectFileTreePath(fullPath);
  return false;
}

function fileTreeActionPaths(fullPath) {
  if (fileExplorerSelectedPaths.has(fullPath)) return Array.from(fileExplorerSelectedPaths);
  return [fullPath];
}

function compactNestedPaths(paths) {
  const sorted = Array.from(new Set(paths)).sort((left, right) => left.localeCompare(right));
  return sorted.filter((path, index) => !sorted.some((other, otherIndex) => otherIndex !== index && path.startsWith(`${other}/`)));
}

function fileExplorerDirectoryIsIndexed(path) {
  const normalized = normalizeStoredFileExplorerIndexedDir(path);
  return Boolean(normalized && fileExplorerIndexedDirs.has(normalized));
}

// Compact badge text for an indexed directory. When Date/Ago is visible, the directory icon is the only
// index marker; the status column must stay empty so it cannot compete with the date column.
function fileExplorerIndexBadgeText(path) {
  if (fileExplorerTreeDateMode !== 'none') return '';
  if (fileExplorerDirectoryIsIndexed(path)) {
    const normalized = normalizeStoredFileExplorerIndexedDir(path);
    return fileExplorerIndexStatus.get(normalized) === 'building' ? '…' : 'I';
  }
  if (fileExplorerIndexedAncestor(path)) return '';
  return '';
}

function fileExplorerIndexBadgeTitle(path) {
  if (!fileExplorerDirectoryIsIndexed(path)) return '';
  const normalized = normalizeStoredFileExplorerIndexedDir(path);
  return fileExplorerIndexStatus.get(normalized) === 'building' ? 'indexing…' : 'indexed';
}

// Warm the backend index for a root (kicks the build) and track building/ready; polls while
// building so the badge title transitions indexing… -> indexed exactly once.
async function refreshFileIndexStatus(root) {
  const normalized = normalizeStoredFileExplorerIndexedDir(root);
  if (!normalized || !fileExplorerIndexedDirs.has(normalized)) return;
  let payload;
  try {
    payload = await apiFetchJson(`/api/fs/index-status?root=${encodeURIComponent(normalized)}`);
  } catch (error) {
    return;  // transient error: keep the prior badge, don't flip it
  }
  if (!fileExplorerIndexedDirs.has(normalized)) return;  // un-indexed while the request was in flight
  const status = payload && payload.ready ? 'ready' : 'building';
  const previous = fileExplorerIndexStatus.get(normalized);
  fileExplorerIndexStatus.set(normalized, status);
  if (status === 'building') fileIndexStatusPollRoots.add(normalized);
  else fileIndexStatusPollRoots.delete(normalized);
  syncFileIndexStatusPollInterval();
  if (previous !== status) updateFileExplorerIndexedDirectoryRows();
}

function refreshBuildingFileIndexStatuses() {
  for (const root of Array.from(fileIndexStatusPollRoots)) {
    if (!fileExplorerIndexedDirs.has(root)) {
      fileIndexStatusPollRoots.delete(root);
      continue;
    }
    refreshFileIndexStatus(root);
  }
  syncFileIndexStatusPollInterval();
}

function syncFileIndexStatusPollInterval() {
  if (!fileIndexStatusPollRoots.size) {
    clearRuntimeInterval('file-index-building');
    return;
  }
  const proactiveMs = Math.max(1, fileExplorerIndexRefreshSeconds * 1000);
  resetRuntimeInterval('file-index-building', refreshBuildingFileIndexStatuses, Math.min(1500, proactiveMs));
}

// Lazily warm/poll an indexed root's status, without re-fetching once it is known ready or while a
// poll is already pending (so per-row render calls don't spam the endpoint).
function ensureFileIndexStatus(path) {
  const normalized = normalizeStoredFileExplorerIndexedDir(path);
  if (!normalized || !fileExplorerIndexedDirs.has(normalized)) return;
  if (fileExplorerIndexStatus.get(normalized) === 'ready' || fileIndexStatusPollRoots.has(normalized)) return;
  refreshFileIndexStatus(normalized);
}

function clearFileIndexStatus(root) {
  const normalized = normalizeStoredFileExplorerIndexedDir(root);
  if (!normalized) return;
  fileExplorerIndexStatus.delete(normalized);
  fileIndexStatusPollRoots.delete(normalized);
  syncFileIndexStatusPollInterval();
}

// Proactive periodic re-check: re-fetches index-status for every indexed root even if already
// 'ready', so stale indexes (TTL expired server-side) get rebuilt without waiting for a search.
function refreshAllIndexedDirsStatus() {
  for (const root of fileExplorerIndexedDirs) {
    refreshFileIndexStatus(root);
  }
}

function fileExplorerIndexedRootList() {
  return compactNestedPaths(Array.from(fileExplorerIndexedDirs || [])
    .map(normalizeStoredFileExplorerIndexedDir)
    .filter(Boolean));
}

function fileExplorerIndexedAncestor(path) {
  const normalized = normalizeStoredFileExplorerIndexedDir(path);
  if (!normalized) return '';
  return fileExplorerIndexedRootList()
    .filter(candidate => candidate !== normalized && pathIsInsideDirectory(normalized, candidate))
    .sort((left, right) => right.length - left.length)[0] || '';
}

function setFileExplorerIndexedDirs(paths) {
  const normalized = (paths || []).map(normalizeStoredFileExplorerIndexedDir).filter(Boolean);
  fileExplorerIndexedDirs = new Set(compactNestedPaths(normalized));
  writeStoredFileExplorerIndexedDirs();
}

function setFileExplorerDirectoryIndexed(path, indexed) {
  const normalized = normalizeStoredFileExplorerIndexedDir(path);
  if (!normalized) return;
  if (indexed) {
    const ancestor = fileExplorerIndexedAncestor(normalized);
    if (ancestor) {
      if (statusEl) statusEl.textContent = `${compactHomePath(normalized)} is already indexed by ${compactHomePath(ancestor)}`;
      return;
    }
    fileExplorerIndexedDirs.add(normalized);
    fileExplorerIndexedDirs = new Set(compactNestedPaths(Array.from(fileExplorerIndexedDirs)));
    // Eagerly build the backend index now (warm) so the first quick-open query hits a warm index,
    // and expose the building title immediately until the build reports ready.
    fileExplorerIndexStatus.set(normalized, 'building');
    refreshFileIndexStatus(normalized);
  } else {
    fileExplorerIndexedDirs.delete(normalized);
    clearFileIndexStatus(normalized);
    abortFileQuickOpenSearch();
    if (!applyingIndexedDirsSetting) {
      apiFetch(`/api/fs/unindex?root=${encodeURIComponent(normalized)}`, {method: 'POST', body: JSON.stringify({root: normalized})}).catch(() => {});
    }
  }
  writeStoredFileExplorerIndexedDirs();
  // Mirror the set into the file_explorer.indexed_dirs setting so the Preferences list stays in sync
  // (skip when this change WAS driven by the setting, to avoid a write-back loop). C11: pass the single
  // add/remove so the save MERGES into the shared list instead of overwriting it with this page's set.
  if (!applyingIndexedDirsSetting) persistIndexedDirsSetting(indexed ? {add: normalized} : {remove: normalized});
  updateFileExplorerIndexedDirectoryRows();
  if (statusEl) {
    statusEl.textContent = indexed ? `indexed ${compactHomePath(normalized)}` : `removed index ${compactHomePath(normalized)}`;
  }
}

function persistIndexedDirsSetting(op = {}) {
  // C11: MERGE the change into the current shared file_explorer.indexed_dirs rather than overwriting it
  // with this page's whole set. Two browser origins (:7777 vs :8001) do NOT share localStorage, so a
  // whole-list save from one would drop the other's dirs and make rows flip indexed/un-indexed on the
  // next settings poll. An explicit {add}/{remove} applies just that one op to the shared list; a bare
  // save (initial localStorage->setting migration) only UNIONS this page's dirs in, never removing.
  const current = initialSetting('file_explorer.indexed_dirs', []);
  const currentNorm = (Array.isArray(current) ? current : []).map(normalizeStoredFileExplorerIndexedDir).filter(Boolean);
  const set = new Set(currentNorm);
  if (op.add) set.add(op.add);
  if (op.remove) set.delete(op.remove);
  if (!op.add && !op.remove) {
    for (const dir of fileExplorerIndexedRootList()) set.add(dir);
  }
  const dirs = compactNestedPaths(Array.from(set));
  const currentList = compactNestedPaths(currentNorm);
  if (currentList.length === dirs.length && currentList.every((value, index) => value === dirs[index])) return;
  saveSettingsPatch({file_explorer: {indexed_dirs: dirs}}, {silent: true}).catch(() => {});
}

// C11 #3: the shared file_explorer.indexed_dirs SETTING is the durable source of truth for which dirs are
// indexed; per-origin localStorage is only a cache + a ONE-TIME migration seed. This reconciles the
// in-memory set FROM the setting (so the setting is authoritative — local-only dirs not in the setting are
// dropped), and on the very first load migrates any pre-existing localStorage dirs INTO the setting exactly
// once (guarded by a migration marker so a stale per-origin cache can never re-seed the setting later).
function reconcileIndexedDirsFromSetting(options = {}) {
  const raw = initialSetting('file_explorer.indexed_dirs', []);
  const list = Array.isArray(raw) ? raw : [];
  const migrated = storageGet(fileExplorerIndexedDirsMigratedKey) === '1';
  if (options.initial && !migrated) {
    // One-time migration: if the setting is empty but this origin's localStorage already has indexed dirs,
    // seed the durable setting from them (don't wipe the user's existing indexed directories). Either way,
    // record that migration is done so localStorage is never treated as a desired-root peer again.
    if (!list.length && fileExplorerIndexedDirs.size) {
      persistIndexedDirsSetting();
      storageSet(fileExplorerIndexedDirsMigratedKey, '1');
      return;
    }
    storageSet(fileExplorerIndexedDirsMigratedKey, '1');
  }
  const desired = new Set(compactNestedPaths(list.map(normalizeStoredFileExplorerIndexedDir).filter(Boolean)));
  const current = new Set(fileExplorerIndexedDirs);
  const adds = Array.from(desired).filter(dir => !current.has(dir));
  const removes = Array.from(current).filter(dir => !desired.has(dir));
  if (!adds.length && !removes.length) return;
  applyingIndexedDirsSetting = true;
  try {
    for (const dir of adds) setFileExplorerDirectoryIndexed(dir, true);
    for (const dir of removes) {
      setFileExplorerDirectoryIndexed(dir, false);
      apiFetch(`/api/fs/unindex?root=${encodeURIComponent(dir)}`, {method: 'POST', body: JSON.stringify({root: dir})}).catch(() => {});
    }
  } finally {
    applyingIndexedDirsSetting = false;
  }
}

function toggleFileExplorerDirectoryIndexed(path) {
  const normalized = normalizeStoredFileExplorerIndexedDir(path);
  if (!normalized) return;
  setFileExplorerDirectoryIndexed(normalized, !fileExplorerDirectoryIsIndexed(normalized));
}

function updateFileExplorerIndexedDirectoryRows() {
  document.querySelectorAll('.file-tree-row.kind-dir[data-path]').forEach(row => {
    const path = row.dataset.path || '';
    const indexed = fileExplorerDirectoryIsIndexed(path);
    const indexedDescendant = !indexed && Boolean(fileExplorerIndexedAncestor(path));
    row.dataset.indexed = indexed ? 'true' : 'false';
    row.classList.toggle('indexed-directory', indexed);
    row.classList.toggle('indexed-descendant-directory', indexedDescendant);
    if (indexed) ensureFileIndexStatus(path);  // warm + learn building/ready for the badge
    const icon = row.querySelector(':scope > .file-tree-icon');
    if (icon) {
      setClassNameIfChanged(icon, ['file-tree-icon', 'file-icon-dir', indexed ? 'file-icon-dir-indexed' : ''].filter(Boolean).join(' '));
    }
    const status = row.querySelector(':scope > .file-tree-git-status');
    if (status) {
      const badge = fileExplorerIndexBadgeText(path);
      if (status.textContent !== badge) status.textContent = badge;
      const title = fileExplorerIndexBadgeTitle(path);
      if (title) status.setAttribute('title', title);
      else status.removeAttribute('title');
      setHiddenIfChanged(status, !badge);
    }
  });
}

function fileExplorerIndexedSearchRoots(defaultRoot = fileQuickOpenRootForSearch(), extraRoots = []) {
  const defaultPath = normalizeStoredFileExplorerIndexedDir(defaultRoot);
  const indexedRoots = fileExplorerIndexedRootList();
  const defaultCoveredByIndexed = defaultPath && indexedRoots.some(root => root !== defaultPath && pathIsInsideDirectory(defaultPath, root));
  const defaultHasIndexedDescendant = defaultPath && indexedRoots.some(root => root !== defaultPath && pathIsInsideDirectory(root, defaultPath));
  const roots = defaultPath && !defaultCoveredByIndexed && !defaultHasIndexedDescendant ? [defaultPath] : [];
  for (const indexedRoot of indexedRoots) {
    if (!roots.includes(indexedRoot)) roots.push(indexedRoot);
  }
  for (const extraRoot of compactNestedPaths((extraRoots || []).map(normalizeStoredFileExplorerIndexedDir).filter(Boolean))) {
    if (!roots.some(root => pathIsInsideDirectory(extraRoot, root))) roots.push(extraRoot);
  }
  return roots;
}
